}

export interface FinanceTransaction {
  id: string;
  date: string;
  description: string;
  amount: number;
  type: 'income' | 'expense';
  category: string;
  status: 'pending' | 'approved' | 'rejected';
  requesterId: string;
  divisionId: DivisionType;
