import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { Tool, User, DivisionType, DivisionData, Announcement, AttendanceRecord, Task, UserRole, TaskPriority } from '../types';
import { DIVISIONS } from '../constants';
import { Icon } from './Icon';
import { ToolCard } from './ToolCard';
import { TaskTicker } from './TaskTicker';
import { CollaborationPanel } from './CollaborationPanel';
import { translations, LanguageCode } from '../translations';

interface DashboardProps {
  tools: Tool[];
  user: User;
  handleToolClick: (tool: Tool) => void;
  onContextMenu: (e: any, tool: Tool) => void;
  onSelect: (tool: Tool) => void;
  onAddTool: (tool: any) => void;
  setNotification: (msg: string) => void;
  isSelectionMode: boolean;
  selectedIds: Set<string>;
  setSmartAddContext: (ctx: string | null) => void;
  onOpenAttendance: () => void;
  onOpenProfile: () => void;
  lang: LanguageCode;
  todayAttendance?: AttendanceRecord;
  unreadAnnouncements: number;
  announcements: Announcement[];
  messages: any[];
  onSendMessage: (msg: string) => void;
  activeChannel: string;
  onChangeChannel: (id: string) => void;
  dashboardDivisions: DivisionData[];
  onAddTask: (divId: DivisionType, title: string, priority: TaskPriority) => void;
  onToggleTask: (divId: DivisionType, taskId: string) => void;
  onDeleteTask: (divId: DivisionType, taskId: string) => void;
  onUpdateTask: (divId: DivisionType, taskId: string, updates: Partial<Task>) => void;
  tasks: Task[];
  groups: any[];
  allUsers: User[];
}

const MainMenuButton: React.FC<{ label: string; icon: string; color: string; onClick: () => void }> = ({ label, icon, color, onClick }) => (
    <button onClick={onClick} className="flex flex-col items-center gap-3 active:scale-95 transition-transform group w-full">
        <div className={`w-16 h-16 rounded-3xl flex items-center justify-center text-white shadow-[0_10px_30px_-5px_rgba(0,0,0,0.5)] bg-[#1e293b]/40 border border-white/10 relative group-hover:border-white/30 overflow-hidden`}>
            <div className={`absolute inset-0 bg-gradient-to-br ${color} opacity-20 group-hover:opacity-30 transition-opacity`}></div>
            <Icon name={icon} size={28} className="relative z-10 drop-shadow-lg" />
        </div>
        <span className="text-[11px] font-bold text-gray-400 uppercase tracking-widest group-hover:text-white transition-colors">{label}</span>
    </button>
);

const DivisionAccordion: React.FC<any> = ({ division, tools, isOpen, onToggle, onToolClick, onContextMenu }) => (
    <div className="mb-3 rounded-3xl overflow-hidden glass-card border border-white/5 mx-1 shadow-lg bg-[#1e293b]/20">
        <button 
            onClick={onToggle}
            className={`w-full flex items-center justify-between p-5 transition-all ${isOpen ? 'bg-white/5' : 'hover:bg-white/5'}`}
        >
            <div className="flex items-center gap-4">
                <div className="w-10 h-10 rounded-2xl bg-gradient-to-br from-gray-800 to-gray-900 flex items-center justify-center text-gray-300 border border-white/10 shadow-inner">
                    <Icon name={division.icon} size={18} />
                </div>
                <div className="text-left">
                    <span className="font-bold text-gray-200 text-sm block tracking-wide">{division.name}</span>
                    <span className="text-[10px] text-gray-500 uppercase font-bold tracking-wider">{tools.length} TOOLS</span>
                </div>
            </div>
            <div className="flex items-center gap-3">
                <Icon name="ChevronDown" size={16} className={`text-gray-500 transition-transform duration-300 ${isOpen ? 'rotate-180 text-brand-400' : ''}`} />
            </div>
        </button>
        <div className={`overflow-hidden transition-all duration-300 bg-black/20 ${isOpen ? 'max-h-[800px] border-t border-white/5' : 'max-h-0'}`}>
            <div className="p-4 grid grid-cols-3 sm:grid-cols-4 gap-3">
                {tools.map((t: any) => (
                    <ToolCard key={t.id} tool={t} variant="tiny" onClick={() => onToolClick(t)} onContextMenu={onContextMenu} />
                ))}
                {tools.length === 0 && <div className="col-span-full text-center py-6 text-xs text-gray-600 italic">Folder kosong</div>}
            </div>
        </div>
    </div>
);

export const Dashboard: React.FC<DashboardProps> = (props) => {
    const navigate = useNavigate(); 
    const t = translations[props.lang] || translations.en; 
    const [searchTerm, setSearchTerm] = useState('');
    const [activeFolder, setActiveFolder] = useState<string | null>(props.user.division);

    const allowedTools = useMemo(() => {
        let items = props.tools;
        if (props.user.role !== UserRole.ADMIN) {
            items = props.tools.filter(t => t.divisionId === props.user.division || !t.divisionId);
        }
        if (searchTerm) {
            items = items.filter(t => t.name.toLowerCase().includes(searchTerm.toLowerCase()));
        }
        return items;
    }, [props.tools, searchTerm, props.user]);

    const displayedDivisions = useMemo(() => {
        if (props.user.role === UserRole.ADMIN) return props.dashboardDivisions;
        return props.dashboardDivisions.filter(d => d.id === props.user.division);
    }, [props.user, props.dashboardDivisions]);

    const tickerTasks = props.tasks.filter(t => t.priority === 'high' && !t.isCompleted);

    return (
        <div className="h-full flex flex-col overflow-y-auto bg-[#0b0f1a] bg-[radial-gradient(circle_at_top,_var(--tw-gradient-stops))] from-[#1e293b]/40 via-[#0b0f1a] to-[#0b0f1a] pb-32">

            <TaskTicker tasks={tickerTasks} onTaskClick={() => {}} />

            {/* Header Area */}
            <div className="flex items-center justify-between px-8 pt-8 pb-6 shrink-0">
                <div>
                    <h1 className="text-2xl font-black text-white tracking-widest">ONE-GATE</h1>
                    <p className="text-[10px] text-gray-500 uppercase tracking-[0.3em]">Working System</p>
                </div>
                <button 
                    onClick={props.onOpenProfile}
                    className="relative p-0.5 rounded-full border border-white/10 shadow-lg group"
                >
                    <div className="w-10 h-10 rounded-full bg-gradient-to-tr from-brand-600 to-indigo-600 flex items-center justify-center text-white font-bold text-sm">
                        {props.user.name.charAt(0)}
                    </div>
                    <div className="absolute bottom-0 right-0 w-3 h-3 bg-emerald-500 rounded-full border-2 border-[#0b0f1a]"></div>
                </button>
            </div>

            {/* Pivot Main Menu Grid */}
            <div className="grid grid-cols-4 gap-4 px-6 mb-8">
                <MainMenuButton label="Absensi" icon="Fingerprint" color="from-emerald-500 to-teal-600" onClick={props.onOpenAttendance} />
                <MainMenuButton label="Pesan" icon="MessageSquare" color="from-indigo-500 to-blue-600" onClick={() => navigate('/messages')} />
                <MainMenuButton label="Tugas" icon="CheckSquare" color="from-amber-500 to-orange-600" onClick={() => navigate(`/division/${props.user.division}`)} />
                <MainMenuButton label="Laporan" icon="BarChart2" color="from-pink-500 to-rose-600" onClick={() => {}} />
            </div>

            {/* Status Workspace Bar */}
            <div className="px-6 mb-6">
                <div className="bg-[#1e293b]/30 backdrop-blur-md border border-white/5 rounded-3xl px-6 py-4 flex items-center justify-between text-[10px] font-bold uppercase tracking-[0.15em] text-gray-500 shadow-xl">
                    <div className="flex items-center gap-3">
                        <div className="w-2 h-2 rounded-full bg-brand-500 animate-pulse"></div>
                        <span className="text-gray-300">{props.user.division}</span>
                    </div>
                    <div className="flex items-center gap-6">
                        <span className="hidden sm:inline">ALAT: <span className="text-white">{allowedTools.length}</span></span>
                        <div className="hidden sm:block h-3 w-px bg-white/10"></div>
                        <div className="flex items-center gap-2 text-emerald-400">
                            ONLINE
                        </div>
                    </div>
                </div>
            </div>

            {/* Folder / Division List */}
            <div className="flex-1 px-5 space-y-3">
                {displayedDivisions.map((div) => (
                    <DivisionAccordion 
                        key={div.id} 
                        division={div}
                        isOpen={activeFolder === div.id}
                        onToggle={() => setActiveFolder(activeFolder === div.id ? null : div.id)}
                        tools={allowedTools.filter(t => t.divisionId === div.id)} 
                        onToolClick={props.handleToolClick} 
                        onContextMenu={props.onContextMenu} 
                    />
                ))}

                {/* Search Bar for more tools */}
                <div className="mt-8 px-1 pb-10">
                    <div className="relative group">
                        <Icon name="Search" className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                        <input 
                            type="text" 
                            placeholder="Cari alat, file, atau link..." 
                            className="w-full bg-[#1e293b]/20 border border-white/5 rounded-2xl pl-14 pr-4 py-4 text-sm text-white placeholder-gray-600 outline-none focus:border-brand-500/50 focus:bg-[#1e293b]/40 transition-all shadow-inner"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                </div>
            </div>

            <CollaborationPanel isOpen={false} onClose={() => {}} user={props.user} divisions={props.dashboardDivisions} onAddTask={props.onAddTask} onToggleTask={props.onToggleTask} onDeleteTask={props.onDeleteTask} onUpdateTask={props.onUpdateTask} announcements={props.announcements} messages={props.messages} onSendMessage={props.onSendMessage} activeChannel={props.activeChannel} onChangeChannel={props.onChangeChannel} groups={props.groups} />
        </div>
    );
};

import React, { useEffect, useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { User, LanguageCode } from '../types';
import { Icon } from './Icon';
import { ResponsiveSidebar } from './Sidebar';

export const Toast: React.FC<{ message: string; onClose: () => void }> = ({ message, onClose }) => {
    useEffect(() => { 
        const timer = setTimeout(onClose, 3000); 
        return () => clearTimeout(timer); 
    }, [onClose]);

    return (
        <div className="fixed bottom-24 left-1/2 -translate-x-1/2 z-[100] bg-brand-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 animate-[slideUp_0.3s_ease-out] border border-white/20">
            <Icon name="CheckCircle" size={18} />
            <span className="font-bold text-xs uppercase tracking-wider">{message}</span>
        </div>
    );
};

