import React, { useState, useEffect } from 'react';
import { DIVISIONS } from '../constants';
import { DivisionType, User, UserRole } from '../types';
import { Icon } from './Icon';
import { StorageService } from '../services/storageService';
import { translations, LanguageCode } from '../translations';

interface LoginViewProps {
  onLogin: (user: User) => void;
}

export const LoginView: React.FC<LoginViewProps> = ({ onLogin }) => {
  const [step, setStep] = useState<1 | 2 | 3>(1);
  const [loginMode, setLoginMode] = useState<'INTERNAL' | 'PARTNER' | 'ADMIN' | null>(null);

  const [selectedDivision, setSelectedDivision] = useState<DivisionType | null>(null);
  const [selectedUser, setSelectedUser] = useState<User | null>(null);

  const [userSearch, setUserSearch] = useState('');
  const [usernameInput, setUsernameInput] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');
  const [users, setUsers] = useState<User[]>([]);

  const prefs = StorageService.getPreferences();
  const t = translations[prefs.language as LanguageCode] || translations.en;

  useEffect(() => {
    setUsers(StorageService.getUsers());
  }, []);

  const handleInternalAccess = () => {
      setLoginMode('INTERNAL');
      setStep(2); 
  };

  const handlePartnerAccess = () => {
      setLoginMode('PARTNER');
      setStep(3);
      setUsernameInput('');
      setPassword('');
      setError('');
  };

  const handleAdminAccess = () => {
      setLoginMode('ADMIN');
      setStep(3);
      setUsernameInput('');
      setPassword('');
      setError('');
  };

  const handleDivisionClick = (divId: DivisionType) => {
    setSelectedDivision(divId);
    setStep(3);
    setUserSearch(''); 
  };

  const handleUserClick = (user: User) => {
    setSelectedUser(user);
    const loggedIn = StorageService.login(user.username);
    if (loggedIn) onLogin(loggedIn);
  };

  const handleLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (loginMode === 'ADMIN') {
        const loggedIn = StorageService.login(usernameInput, password);
        if (loggedIn) {
            onLogin(loggedIn);
        } else {
            setError('Invalid Admin credentials.');
        }
    } else if (loginMode === 'PARTNER') {
        if (usernameInput.length > 3 && password === '123') { 
             const partnerUser: User = {
                 id: `prt_${Date.now()}`,
                 name: usernameInput, 
                 username: usernameInput.toLowerCase().replace(/\s/g, ''),
                 role: UserRole.PARTNER,
                 division: DivisionType.PARTNERS,
                 stickyNote: 'External Partner Access'
             };
             onLogin(partnerUser);
        } else {
             setError('Kode Akses atau ID Mitra salah. (Demo: ID=Nama, Pass=123)');
        }
    }
  };

  const filteredUsers = selectedDivision 
    ? users.filter(u => u && u.division === selectedDivision && u.name.toLowerCase().includes(userSearch.toLowerCase())) 
    : [];

  return (
