            <div className="flex-1 bg-black/20 rounded-2xl border border-white/5 overflow-hidden shadow-xl flex flex-col">
                <div className="overflow-x-auto flex-1 custom-scrollbar">
                    <table className="w-full text-left border-collapse">
                        <thead className="bg-white/5 text-gray-400 text-xs uppercase tracking-wider font-semibold sticky top-0 z-10 backdrop-blur-md"><tr><th className="p-4">Kode & Nama</th><th className="p-4">Kategori</th><th className="p-4">Lokasi</th><th className="p-4">Kondisi</th><th className="p-4">Tgl Beli</th><th className="p-4 text-center">Aksi</th></tr></thead>
                        <tbody className="divide-y divide-white/5 text-sm">{filteredAssets.map(asset => (<tr key={asset.id} className="hover:bg-white/5 transition-colors"><td className="p-4"><div className="font-bold text-white">{asset.name}</div><div className="text-xs text-gray-500 font-mono">{asset.code}</div></td><td className="p-4 text-gray-300">{asset.category}</td><td className="p-4 text-gray-300 flex items-center gap-1"><Icon name="MapPin" size={12} className="text-gray-500"/> {asset.location}</td><td className="p-4"><span className={`px-2 py-1 rounded text-[10px] font-bold uppercase border ${getConditionBadge(asset.condition)}`}>{asset.condition}</span></td><td className="p-4 text-gray-400 text-xs">{asset.purchaseDate}</td><td className="p-4 text-center">{canEdit && (<div className="flex justify-center gap-2"><button className="p-1.5 hover:bg-white/10 rounded text-blue-400"><Icon name="Edit" size={16}/></button><button className="p-1.5 hover:bg-white/10 rounded text-red-400"><Icon name="Trash2" size={16}/></button></div>)}</td></tr>))}</tbody>
                    </table>
