            </div>
        )}

        {/* NOTIFICATIONS TAB */}
        {activeTab === 'notifications' && isSystemAdmin && (
            <div className="max-w-2xl mx-auto space-y-8 animate-[fadeIn_0.3s]">
                <div className="bg-white/5 border border-white/5 rounded-2xl p-6 space-y-4">
                    <h3 className="text-lg font-bold text-white">Nomor Admin (WhatsApp)</h3>
                    <input className="w-full bg-black/30 border border-white/10 rounded-lg px-3 py-2 text-white text-sm outline-none" value={waNumber} onChange={e => setWaNumber(e.target.value)} placeholder="628..." />
                </div>
                <div className="bg-white/5 border border-white/5 rounded-2xl p-6 space-y-4">
                    <h3 className="text-lg font-bold text-white">Integrasi Fonnte</h3>
                    <div className="flex gap-2"><input className="flex-1 bg-black/30 border border-white/10 rounded-lg px-3 py-2 text-white text-sm outline-none" type="password" value={fonnteToken} onChange={e => setFonnteToken(e.target.value)} placeholder="Token..." /><button onClick={handleCheckFonnteStatus} className="px-4 py-2 bg-indigo-600 text-white rounded-lg text-xs font-bold">{isCheckingFonnteStatus ? '...' : 'Cek'}</button></div>
                    {fonnteDeviceStatus && (<div className={`p-3 rounded border text-xs ${fonnteDeviceStatus.status ? 'bg-green-500/20 border-green-500/50 text-green-300' : 'bg-red-500/20 border-red-500/50 text-red-300'}`}>{fonnteDeviceStatus.status ? `Connected: ${fonnteDeviceStatus.name}` : `Error: ${fonnteDeviceStatus.reason}`}</div>)}
                    <button onClick={handleTestFonnte} disabled={!fonnteToken} className="w-full py-2 bg-green-600/20 text-green-400 border border-green-600/30 rounded text-xs font-bold">Kirim Pesan Tes</button>
                </div>
                <div className="bg-white/5 border border-white/5 rounded-2xl p-6 space-y-4">
                    <h3 className="text-lg font-bold text-white">Webhook</h3>
                    <input className="w-full bg-black/30 border border-white/10 rounded-lg px-3 py-2 text-white text-sm outline-none" value={webhookUrl} onChange={e => setWebhookUrl(e.target.value)} placeholder="https://..." />
                    <button onClick={handleTestWebhook} className="w-full py-2 bg-yellow-600/20 text-yellow-400 border border-yellow-600/30 rounded text-xs font-bold">Test Webhook</button>
                </div>
                <button onClick={handleSaveNotifications} className="w-full py-3 bg-brand-600 text-white font-bold rounded-xl shadow-lg">Simpan Konfigurasi</button>
            </div>
        )}

        {/* SYSTEM TAB */}
        {activeTab === 'system' && isSystemAdmin && (
            <div className="max-w-4xl mx-auto animate-[fadeIn_0.3s]">
                <div className="flex gap-2 mb-8 bg-black/30 p-1 rounded-xl w-fit overflow-x-auto max-w-full">
                    <button onClick={() => setSystemSubTab('announcements')} className={`px-4 py-2 rounded-lg text-xs font-bold whitespace-nowrap ${systemSubTab === 'announcements' ? 'bg-brand-600 text-white' : 'text-gray-400'}`}>Pengumuman</button>
                    <button onClick={() => setSystemSubTab('attendance')} className={`px-4 py-2 rounded-lg text-xs font-bold whitespace-nowrap ${systemSubTab === 'attendance' ? 'bg-brand-600 text-white' : 'text-gray-400'}`}>Absensi</button>
                    <button onClick={() => setSystemSubTab('backup')} className={`px-4 py-2 rounded-lg text-xs font-bold whitespace-nowrap ${systemSubTab === 'backup' ? 'bg-brand-600 text-white' : 'text-gray-400'}`}>Backup</button>
                </div>

                {systemSubTab === 'announcements' && (<div className="bg-white/5 border border-white/5 rounded-2xl p-6"><h3 className="text-lg font-bold text-white mb-4">Pengumuman Baru</h3><form onSubmit={handleAddAnnouncement} className="space-y-4 mb-8"><input className="w-full bg-black/30 border border-white/10 rounded-lg px-4 py-2 text-white" placeholder="Judul" value={newAnnTitle} onChange={e => setNewAnnTitle(e.target.value)} /><textarea className="w-full bg-black/30 border border-white/10 rounded-lg px-4 py-2 text-white h-24" placeholder="Isi..." value={newAnnContent} onChange={e => setNewAnnContent(e.target.value)} /><button type="submit" className="px-4 py-2 bg-brand-600 text-white rounded-lg font-bold">Posting</button></form><div className="space-y-2">{announcements.map(ann => (<div key={ann.id} className="flex justify-between items-center p-3 bg-black/20 rounded-xl border border-white/5"><div><p className="font-bold text-white">{ann.title}</p><p className="text-xs text-gray-500">{ann.date}</p></div><button onClick={() => handleDeleteAnnouncement(ann.id)} className="text-red-500"><Icon name="Trash2" size={16}/></button></div>))}</div></div>)}

                {systemSubTab === 'attendance' && (
                    <div className="space-y-8">
                        <div className="bg-white/5 border border-white/5 rounded-2xl p-6 space-y-6">
                            <h3 className="text-lg font-bold text-white flex items-center gap-2"><Icon name="Clock" size={18}/> Konfigurasi Jam Kerja</h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6"><div className="space-y-2"><label className="text-xs font-bold text-gray-400 uppercase">Jam Masuk (WIB)</label><input type="time" className="w-full bg-black/30 border border-white/10 rounded px-3 py-2 text-white" value={editWorkStart} onChange={e => setEditWorkStart(e.target.value)} /></div><div className="space-y-2"><label className="text-xs font-bold text-gray-400 uppercase">Jam Pulang (WIB)</label><input type="time" className="w-full bg-black/30 border border-white/10 rounded px-3 py-2 text-white" value={editWorkEnd} onChange={e => setEditWorkEnd(e.target.value)} /></div></div>
                            <div className="flex justify-end"><button onClick={handleSaveAttendanceConfig} className="px-4 py-2 bg-brand-600 hover:bg-brand-500 text-white rounded font-bold transition-colors">Simpan Aturan</button></div>
                        </div>

                        {/* ATTENDANCE HISTORY TABLE */}
                        <div className="bg-white/5 border border-white/5 rounded-2xl p-6">
                            <div className="flex justify-between items-center mb-4">
                                <h3 className="text-lg font-bold text-white flex items-center gap-2"><Icon name="FileText" size={18}/> Laporan Kehadiran</h3>
                                <button onClick={() => alert("Mengunduh CSV...")} className="px-3 py-1.5 bg-green-600 hover:bg-green-500 text-white rounded-lg text-xs font-bold flex items-center gap-2"><Icon name="Download" size={14}/> Export CSV</button>
                            </div>
                            <div className="overflow-x-auto">
                                <table className="w-full text-left border-collapse">
                                    <thead className="bg-black/20 text-gray-400 text-xs uppercase tracking-wider">
                                        <tr><th className="p-3">Tanggal</th><th className="p-3">Nama</th><th className="p-3">Masuk</th><th className="p-3">Keluar</th><th className="p-3">Lokasi</th><th className="p-3">Mood</th></tr>
                                    </thead>
                                    <tbody className="divide-y divide-white/5 text-sm">
                                        {attendanceHistory.length === 0 && <tr><td colSpan={6} className="p-4 text-center text-gray-500">Belum ada data absensi.</td></tr>}
                                        {attendanceHistory.map(rec => (
                                            <tr key={rec.id} className="hover:bg-white/5 transition-colors">
                                                <td className="p-3 font-mono text-gray-300">{rec.date}</td>
                                                <td className="p-3 font-bold text-white">{getUserName(rec.userId)}</td>
                                                <td className="p-3 text-green-400 font-mono">{new Date(rec.checkInTime).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</td>
                                                <td className="p-3 text-red-400 font-mono">{rec.checkOutTime ? new Date(rec.checkOutTime).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}) : '-'}</td>
                                                <td className="p-3"><span className={`px-2 py-0.5 rounded text-[10px] uppercase font-bold ${rec.location === 'WFO' ? 'bg-blue-500/20 text-blue-300' : 'bg-purple-500/20 text-purple-300'}`}>{rec.location}</span></td>
                                                <td className="p-3 text-xl">{rec.mood}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    </div>
                )}

                {systemSubTab === 'backup' && (<div className="space-y-6"><div className="bg-indigo-900/20 border border-indigo-500/30 rounded-2xl p-6"><h3 className="font-bold text-white">Cloud Sync</h3><button onClick={handleCloudSync} disabled={isSyncing} className="mt-4 px-6 py-2 bg-indigo-600 text-white rounded font-bold">{isSyncing ? 'Syncing...' : 'Sync to Cloud'}</button></div><div className="bg-white/5 border border-white/5 rounded-2xl p-6"><h3 className="font-bold text-white">Local Backup</h3><div className="flex flex-col md:flex-row gap-4 mt-4"><button onClick={handleExportConfig} className="flex-1 bg-black/30 border border-white/10 p-4 rounded text-white font-bold">Export JSON</button><label className="flex-1 bg-black/30 border border-white/10 p-4 rounded text-white font-bold cursor-pointer text-center"><input type="file" className="hidden" onChange={handleImportConfig} />Import JSON</label></div></div></div>)}
            </div>
        )}

        </div>
      </div>
      <EmployeeModal isOpen={isEmployeeModalOpen} onClose={() => setIsEmployeeModalOpen(false)} onSave={handleSaveEmployee} initialData={editingEmployee} />
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { User, Tool, Announcement, UserRole, AttendanceConfig, Holiday, UserPreferences, SystemBackup, DivisionType, AttendanceRecord } from '../types';
import { Icon } from './Icon';
import { StorageService } from '../services/storageService';
import { translations, LanguageCode } from '../translations';
import { NotificationService } from '../services/notificationService';
import { UnifiedDataService } from '../services/UnifiedDataService';
import { isSupabaseConfigured } from '../services/supabaseClient';
import { EmployeeModal } from './EmployeeModal';
import { OrgChart } from './OrgChart';
import { EMPLOYEE_DATA } from '../constants';

interface SettingsViewProps {
  user: User;
  onUpdateUser: (user: User) => void;
  tools: Tool[];
  onUpdateTools: (tools: Tool[]) => void;
  announcements: Announcement[];
  onUpdateAnnouncements: (announcements: Announcement[]) => void;
  attendanceConfig: AttendanceConfig;
  onUpdateAttendanceConfig: (config: AttendanceConfig) => void;
  holidays: Holiday[];
  onUpdateHolidays: (holidays: Holiday[]) => void;
  onTeamUpdate: () => void; 
}

export const SettingsView: React.FC<SettingsViewProps> = ({ 
  user, onUpdateUser, tools, onUpdateTools, announcements, onUpdateAnnouncements,
  attendanceConfig, onUpdateAttendanceConfig, holidays, onUpdateHolidays, onTeamUpdate
}) => {
  // Allow Admin, IT Support, AND HR to manage team
  const isSystemAdmin = user.role === UserRole.ADMIN || user.division === DivisionType.IT_SUPPORT;
  const canManageTeam = isSystemAdmin || user.division === DivisionType.HR;

  const [activeTab, setActiveTab] = useState<'team' | 'profile' | 'system' | 'notifications'>(
      'profile' // Default to profile for better UX on mobile start
  );

  const [teamViewMode, setTeamViewMode] = useState<'list' | 'chart'>('list');
  const [searchTerm, setSearchTerm] = useState('');
  const [isSyncing, setIsSyncing] = useState(false);
  const [isTestingFonnte, setIsTestingFonnte] = useState(false);
  const [allEmployees, setAllEmployees] = useState<User[]>([]);
  const [isEmployeeModalOpen, setIsEmployeeModalOpen] = useState(false);
  const [editingEmployee, setEditingEmployee] = useState<User | undefined>(undefined);
  const [isCheckingFonnteStatus, setIsCheckingFonnteStatus] = useState(false);
  const [fonnteDeviceStatus, setFonnteDeviceStatus] = useState<any>(null);
  const [connectionStatus, setConnectionStatus] = useState<'checking' | 'connected' | 'disconnected'>('checking');
  const [preferences, setPreferences] = useState<UserPreferences>(StorageService.getPreferences());
  const t = translations[preferences.language as LanguageCode] || translations.en;

  const [editName, setEditName] = useState(user.name);
  const [editNote, setEditNote] = useState(user.stickyNote);
  const [editRole, setEditRole] = useState(user.role);
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [systemSubTab, setSystemSubTab] = useState<'announcements' | 'attendance' | 'backup'>('announcements');
  const [newAnnTitle, setNewAnnTitle] = useState('');
  const [newAnnContent, setNewAnnContent] = useState('');
  const [newAnnPriority, setNewAnnPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editWorkStart, setEditWorkStart] = useState(attendanceConfig.workStartTime);
  const [editWorkEnd, setEditWorkEnd] = useState(attendanceConfig.workEndTime);
  const [editGrace, setEditGrace] = useState(attendanceConfig.gracePeriodMinutes);
  const [editQuota, setEditQuota] = useState(attendanceConfig.annualLeaveQuota);
  const [waNumber, setWaNumber] = useState(preferences.whatsappNumber || '');
  const [webhookUrl, setWebhookUrl] = useState(preferences.webhookUrl || 'https://hooks.zapier.com/hooks/catch/123456/sample');
  const [fonnteToken, setFonnteToken] = useState(preferences.fonnteToken || '');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Attendance History State
  const [attendanceHistory, setAttendanceHistory] = useState<AttendanceRecord[]>([]);

  useEffect(() => {
      setAllEmployees(StorageService.getUsers());
      setConnectionStatus(isSupabaseConfigured() ? 'connected' : 'disconnected');
      if (canManageTeam) {
          setAttendanceHistory(StorageService.getAttendanceHistory());
      }
  }, [canManageTeam]);

  const handleAddEmployee = () => { setEditingEmployee(undefined); setIsEmployeeModalOpen(true); };
  const handleEditEmployee = (emp: User) => { setEditingEmployee(emp); setIsEmployeeModalOpen(true); };

  const handleDeleteEmployee = (id: string) => { 
      if (id === user.id) return alert("Anda tidak dapat menghapus akun sendiri."); 
      if (window.confirm("Hapus user ini secara permanen?")) { 
          StorageService.deleteUser(id); 
          setAllEmployees(StorageService.getUsers()); 
          if(onTeamUpdate) onTeamUpdate();
      } 
  };

  const handleSaveEmployee = (empData: User) => { 
      if (editingEmployee) StorageService.updateUser(empData); 
      else StorageService.addUser(empData); 
      setAllEmployees(StorageService.getUsers()); 
      setIsEmployeeModalOpen(false); 
      if(onTeamUpdate) onTeamUpdate();
  };

  const handleSaveProfile = () => { onUpdateUser({ ...user, name: editName, stickyNote: editNote, role: editRole }); alert(t.common.save); };
  const handleChangePassword = (e: React.FormEvent) => { e.preventDefault(); if (!newPassword || newPassword !== confirmPassword) return alert("Mismatch"); onUpdateUser({ ...user, password: newPassword }); setNewPassword(''); setConfirmPassword(''); alert("Updated"); };
  const handleAddAnnouncement = (e: React.FormEvent) => { e.preventDefault(); onUpdateAnnouncements([{ id: `ann_${Date.now()}`, title: newAnnTitle, content: newAnnContent, priority: newAnnPriority, date: new Date().toISOString().split('T')[0] }, ...announcements]); setNewAnnTitle(''); setNewAnnContent(''); };
  const handleDeleteAnnouncement = (id: string) => { onUpdateAnnouncements(announcements.filter(a => a.id !== id)); };
  const handleSaveAttendanceConfig = () => { onUpdateAttendanceConfig({ ...attendanceConfig, workStartTime: editWorkStart, workEndTime: editWorkEnd, gracePeriodMinutes: editGrace, annualLeaveQuota: editQuota }); alert("Saved"); };
  const handleExportConfig = () => { const blob = new Blob([JSON.stringify(StorageService.createBackup(), null, 2)], { type: 'application/json' }); const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = 'config.json'; a.click(); };
  const handleImportConfig = (e: React.ChangeEvent<HTMLInputElement>) => { const file = e.target.files?.[0]; if (!file) return; const reader = new FileReader(); reader.onload = (ev) => { try { StorageService.restoreBackup(JSON.parse(ev.target?.result as string)); } catch (e) { alert("Invalid"); } }; reader.readAsText(file); };
  const handleCloudSync = async () => { if (!window.confirm("Sync to cloud?")) return; setIsSyncing(true); await UnifiedDataService.syncLocalToCloud(StorageService.getTasks(), StorageService.getMessages(), StorageService.getChatGroups()); setIsSyncing(false); alert("Done"); };
  const handleSaveNotifications = () => { const upd = { ...preferences, whatsappNumber: waNumber, webhookUrl, fonnteToken }; setPreferences(upd); StorageService.savePreferences(upd); alert("Saved"); };
  const handleTestWebhook = () => { NotificationService.triggerWebhook({ id: 'test', title: 'Test', priority: 'medium', isCompleted: false, creatorId: 'me' } as any, 'created', webhookUrl); alert("Triggered"); };
  const handleCheckFonnteStatus = async () => { setIsCheckingFonnteStatus(true); setFonnteDeviceStatus(await NotificationService.validateFonnteToken(fonnteToken)); setIsCheckingFonnteStatus(false); };
  const handleTestFonnte = async () => { setIsTestingFonnte(true); await NotificationService.sendViaFonnte("Test Message", fonnteToken, waNumber); setIsTestingFonnte(false); alert("Sent request"); };

  const getBadgeColor = (division: string) => { 
      switch(division) { 
          case 'Direksi': return 'bg-purple-500/20 text-purple-300 border-purple-500/30'; 
          case 'Marketing': return 'bg-blue-500/20 text-blue-300 border-blue-500/30'; 
          case 'Administrasi': return 'bg-orange-500/20 text-orange-300 border-orange-500/30'; 
          case 'Keuangan': return 'bg-emerald-500/20 text-emerald-300 border-emerald-500/30'; 
          case 'IT Support': return 'bg-indigo-500/20 text-indigo-300 border-indigo-500/30';
          case 'SDM & Personalia': return 'bg-pink-500/20 text-pink-300 border-pink-500/30';
          default: return 'bg-gray-500/20 text-gray-300 border-gray-500/30'; 
      } 
  };

  const filteredEmployees = allEmployees.filter(emp => emp.name.toLowerCase().includes(searchTerm.toLowerCase()) || emp.division.toLowerCase().includes(searchTerm.toLowerCase()));

  // Helper to get user name
  const getUserName = (id: string) => {
      const u = allEmployees.find(emp => emp.id === id);
      return u ? u.name : id;
  };

  return (
    <div className="flex h-full bg-[#0b0f1a] overflow-hidden">
      <div className="hidden md:flex w-64 bg-black/20 border-r border-white/5 p-6 flex-col gap-2 shrink-0 backdrop-blur-md">
        <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2"><Icon name="Settings" className="text-brand-400" /> Pengaturan</h2>
        <button onClick={() => setActiveTab('profile')} className={`text-left px-4 py-3 rounded-xl flex items-center gap-3 transition-all ${activeTab === 'profile' ? 'bg-brand-600 text-white' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}><Icon name="User" size={18} /> Profil</button>
        {canManageTeam && (<button onClick={() => setActiveTab('team')} className={`text-left px-4 py-3 rounded-xl flex items-center gap-3 transition-all ${activeTab === 'team' ? 'bg-brand-600 text-white' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}><Icon name="Users" size={18} /> Data Tim</button>)}
        {isSystemAdmin && (<button onClick={() => setActiveTab('notifications')} className={`text-left px-4 py-3 rounded-xl flex items-center gap-3 transition-all ${activeTab === 'notifications' ? 'bg-brand-600 text-white' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}><Icon name="Bell" size={18} /> Notifikasi</button>)}
        {isSystemAdmin && (<button onClick={() => setActiveTab('system')} className={`text-left px-4 py-3 rounded-xl flex items-center gap-3 transition-all ${activeTab === 'system' ? 'bg-brand-600 text-white' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}><Icon name="Server" size={18} /> Sistem</button>)}
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar">

        {/* Mobile Tab Selector */}
        <div className="md:hidden flex overflow-x-auto gap-2 p-4 pb-2 scrollbar-hide border-b border-white/5 bg-[#0b0f1a] sticky top-0 z-20">
             <button onClick={() => setActiveTab('profile')} className={`whitespace-nowrap px-4 py-2 rounded-full text-xs font-bold border transition-colors ${activeTab === 'profile' ? 'bg-brand-600 border-brand-500 text-white' : 'bg-white/5 border-white/10 text-gray-400'}`}>Profil</button>
             {canManageTeam && <button onClick={() => setActiveTab('team')} className={`whitespace-nowrap px-4 py-2 rounded-full text-xs font-bold border transition-colors ${activeTab === 'team' ? 'bg-brand-600 border-brand-500 text-white' : 'bg-white/5 border-white/10 text-gray-400'}`}>Data Tim</button>}
             {isSystemAdmin && <button onClick={() => setActiveTab('notifications')} className={`whitespace-nowrap px-4 py-2 rounded-full text-xs font-bold border transition-colors ${activeTab === 'notifications' ? 'bg-brand-600 border-brand-500 text-white' : 'bg-white/5 border-white/10 text-gray-400'}`}>Notifikasi</button>}
             {isSystemAdmin && <button onClick={() => setActiveTab('system')} className={`whitespace-nowrap px-4 py-2 rounded-full text-xs font-bold border transition-colors ${activeTab === 'system' ? 'bg-brand-600 border-brand-500 text-white' : 'bg-white/5 border-white/10 text-gray-400'}`}>Sistem</button>}
        </div>

        <div className="p-4 md:p-8">
        {/* === PROFILE TAB (Redesigned) === */}
        {activeTab === 'profile' && (
            <div className="max-w-2xl mx-auto space-y-6 animate-[fadeIn_0.3s]">

                {/* Profile Header */}
                <div className="flex flex-col items-center py-6">
                    <div className="relative group cursor-pointer mb-4">
                        <div className="w-28 h-28 rounded-full border-4 border-[#1e293b] shadow-2xl overflow-hidden relative bg-[#0b0f1a]">
                             {/* Avatar or Initial */}
                             <div className="w-full h-full flex items-center justify-center bg-gradient-to-tr from-brand-600 to-indigo-500 text-4xl font-bold text-white">
                                {user.name.charAt(0)}
                             </div>
                        </div>
                        <div className="absolute bottom-0 right-0 bg-brand-600 p-2.5 rounded-full border-4 border-[#0b0f1a] text-white shadow-lg">
                            <Icon name="Camera" size={16} />
                        </div>
                    </div>
                    <h2 className="text-xl font-bold text-white tracking-tight">{user.name}</h2>
                    <p className="text-[#9dabb9] text-sm mt-1 font-medium">{user.role} - {user.division}</p>
                    <div className="mt-2 px-3 py-1 bg-[#1e293b] rounded-full border border-white/5">
                        <p className="text-[#9dabb9] text-xs font-mono tracking-wide">ID: {user.id}</p>
                    </div>
                </div>

                <div className="h-px bg-white/5 w-full"></div>

                {/* Edit Profile Section */}
                <div className="space-y-5">
                    <div className="flex items-center justify-between">
                        <h2 className="text-lg font-bold text-white tracking-tight">Edit Profil</h2>
                    </div>

                    <div className="space-y-4">
                        <label className="block w-full">
                            <p className="text-[#9dabb9] text-sm font-medium mb-2">Nama Lengkap</p>
                            <input 
                                className="w-full h-12 bg-[#1e293b] rounded-xl px-4 text-white border border-white/5 focus:border-brand-500 focus:ring-1 focus:ring-brand-500 outline-none transition-all text-base"
                                value={editName} 
                                onChange={e => setEditName(e.target.value)} 
                            />
                        </label>

                        <label className="block w-full opacity-70">
                            <div className="flex justify-between mb-2">
                                <p className="text-[#9dabb9] text-sm font-medium">Sticky Note (Dashboard)</p>
                            </div>
                            <input 
                                className="w-full h-12 bg-[#1e293b] rounded-xl px-4 text-white border border-white/5 outline-none focus:border-brand-500 transition-all text-base"
                                value={editNote} 
                                onChange={e => setEditNote(e.target.value)}
                            />
                        </label>

                        {/* Read Only Fields Simulation */}
                        <label className="block w-full opacity-60">
                            <div className="flex justify-between mb-2">
                                <p className="text-[#9dabb9] text-sm font-medium">Email / Kontak</p>
                                <span className="text-[10px] text-gray-500 uppercase font-bold tracking-wider pt-0.5">Read Only</span>
                            </div>
                            <div className="w-full h-12 bg-[#151b26] rounded-xl px-4 flex items-center justify-between border border-white/5">
                                <span className="text-gray-400 text-sm">{user.email || 'No Email'}</span>
                                <Icon name="Lock" size={16} className="text-gray-600"/>
                            </div>
                        </label>
                    </div>

                    <button 
                        onClick={handleSaveProfile} 
                        className="w-full h-12 bg-brand-600 hover:bg-brand-500 text-white font-bold rounded-xl shadow-lg shadow-brand-900/20 active:scale-[0.98] transition-all flex items-center justify-center gap-2"
                    >
                        <Icon name="Save" size={18} /> Simpan Perubahan
                    </button>
                </div>

                <div className="h-2 bg-[#1e293b]/50 w-full rounded-full my-6"></div>

                {/* Security Section */}
                <div>
                    <h2 className="text-lg font-bold text-white tracking-tight mb-4">Keamanan</h2>
                    <div className="space-y-3">
                        <div className="bg-[#1e293b] p-4 rounded-xl flex items-center justify-between border border-white/5 hover:border-white/10 transition-colors group cursor-pointer" onClick={() => {
                             const newPass = prompt("Masukkan Password Baru:");
                             if (newPass) {
                                 onUpdateUser({ ...user, password: newPass });
                                 alert("Password Updated");
                             }
                        }}>
                            <div className="flex items-center gap-4">
                                <div className="bg-brand-500/10 p-2.5 rounded-full text-brand-500">
                                    <Icon name="Lock" size={20} />
                                </div>
                                <span className="text-white font-medium">Ubah Password</span>
                            </div>
                            <Icon name="ChevronRight" size={20} className="text-gray-600 group-hover:text-white transition-colors" />
                        </div>

                        <div className="bg-[#1e293b] p-4 rounded-xl flex items-center justify-between border border-white/5">
                            <div className="flex items-center gap-4">
                                <div className="bg-brand-500/10 p-2.5 rounded-full text-brand-500">
                                    <Icon name="Fingerprint" size={20} />
                                </div>
                                <div className="flex flex-col">
                                    <span className="text-white font-medium">Biometric Login</span>
                                    <span className="text-[#9dabb9] text-xs">FaceID / TouchID</span>
                                </div>
                            </div>
                            {/* Fake Toggle */}
                            <div className="w-11 h-6 bg-brand-600 rounded-full relative cursor-pointer">
                                <div className="absolute right-1 top-1 w-4 h-4 bg-white rounded-full shadow-md"></div>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="h-10"></div>
            </div>
        )}

        {/* === TEAM MANAGEMENT (RESTRICTED) === */}
        {activeTab === 'team' && canManageTeam && (
            <div className="max-w-6xl mx-auto space-y-6 animate-[fadeIn_0.3s]">
                <div className="flex flex-col md:flex-row md:justify-between md:items-center gap-4 mb-2">
                    <div>
                        <h2 className="text-xl md:text-2xl font-bold text-white mb-1">Data & Struktur Tim</h2>
                        <p className="text-gray-400 text-xs md:text-sm">Kelola akses dan hierarki perusahaan.</p>
                    </div>
                    <div className="flex flex-wrap gap-3">
                        <div className="hidden md:flex bg-black/30 p-1 rounded-xl border border-white/10">
                            <button onClick={() => setTeamViewMode('list')} className={`px-3 py-1.5 rounded-lg text-xs font-bold flex items-center gap-2 ${teamViewMode === 'list' ? 'bg-white/10 text-white' : 'text-gray-500'}`}><Icon name="List" size={14} /> List</button>
                            <button onClick={() => setTeamViewMode('chart')} className={`px-3 py-1.5 rounded-lg text-xs font-bold flex items-center gap-2 ${teamViewMode === 'chart' ? 'bg-white/10 text-white' : 'text-gray-500'}`}><Icon name="GitFork" size={14} /> Bagan</button>
                        </div>
                        {teamViewMode === 'list' && (
                            <div className="relative flex-1 md:flex-none">
                                <input className="w-full md:w-64 bg-black/30 border border-white/10 rounded-xl pl-9 pr-4 py-2 text-sm text-white focus:border-brand-500 outline-none" placeholder="Cari..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                                <Icon name="Search" size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500"/>
                            </div>
                        )}
                        <button onClick={handleAddEmployee} className="bg-brand-600 hover:bg-brand-500 text-white px-4 py-2 rounded-xl text-sm font-bold flex items-center gap-2 shadow-lg transition-all"><Icon name="UserPlus" size={16} /> <span className="hidden md:inline">Tambah</span></button>
                    </div>
                </div>

                {teamViewMode === 'list' ? (
                    <>
                    {/* DESKTOP TABLE */}
                    <div className="hidden md:block bg-white/5 border border-white/5 rounded-2xl overflow-hidden shadow-2xl">
                        <table className="w-full text-left border-collapse">
                            <thead className="bg-black/20 text-gray-400 text-xs uppercase tracking-wider font-semibold">
                                <tr><th className="p-4 w-16 text-center">No</th><th className="p-4">Nama</th><th className="p-4">Divisi</th><th className="p-4">Kontak</th><th className="p-4 text-center">Aksi</th></tr>
                            </thead>
                            <tbody className="divide-y divide-white/5 text-sm">
                                {filteredEmployees.map((emp, idx) => (
                                    <tr key={emp.id} className="hover:bg-white/5 transition-colors group">
                                        <td className="p-4 text-center text-gray-500">{idx + 1}</td>
                                        <td className="p-4 font-medium text-white flex items-center gap-3"><div className="w-8 h-8 rounded-full bg-gray-700 flex items-center justify-center text-xs">{emp.name.charAt(0)}</div>{emp.name}</td>
                                        <td className="p-4"><span className={`text-[10px] px-2 py-0.5 rounded border uppercase font-bold ${getBadgeColor(emp.division)}`}>{emp.division}</span> <span className="text-gray-400 text-xs ml-2">{emp.role}</span></td>
                                        <td className="p-4 text-gray-400 font-mono text-xs"><div>{emp.email}</div><div>{emp.phoneNumber}</div></td>
                                        <td className="p-4 text-center"><div className="flex justify-center gap-2"><button onClick={() => handleEditEmployee(emp)} className="p-1.5 bg-blue-500/10 text-blue-400 rounded"><Icon name="Pencil" size={14} /></button><button onClick={() => handleDeleteEmployee(emp.id)} className="p-1.5 bg-red-500/10 text-red-400 rounded"><Icon name="Trash2" size={14} /></button></div></td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>

                    {/* MOBILE CARD LIST */}
                    <div className="md:hidden space-y-3">
                        {filteredEmployees.map((emp) => (
                            <div key={emp.id} className="bg-white/5 border border-white/5 rounded-xl p-4 flex flex-col gap-3">
                                <div className="flex items-start justify-between">
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 rounded-full bg-gradient-to-br from-gray-700 to-gray-600 flex items-center justify-center text-white font-bold text-sm shadow-md">
                                            {emp.name.charAt(0)}
                                        </div>
                                        <div>
                                            <h4 className="text-sm font-bold text-white">{emp.name}</h4>
                                            <p className="text-xs text-gray-400">{emp.role}</p>
                                        </div>
                                    </div>
                                    <div className="flex gap-2">
                                        <button onClick={() => handleEditEmployee(emp)} className="p-2 bg-blue-500/10 text-blue-400 rounded-lg"><Icon name="Pencil" size={16} /></button>
                                        <button onClick={() => handleDeleteEmployee(emp.id)} className="p-2 bg-red-500/10 text-red-400 rounded-lg"><Icon name="Trash2" size={16} /></button>
                                    </div>
                                </div>
                                <div className="flex flex-wrap gap-2">
                                    <span className={`text-[10px] px-2 py-0.5 rounded border uppercase font-bold ${getBadgeColor(emp.division)}`}>{emp.division}</span>
                                    {emp.email && <span className="text-[10px] px-2 py-0.5 rounded bg-black/20 text-gray-400 flex items-center gap-1"><Icon name="Mail" size={10}/> {emp.email}</span>}
                                    {emp.phoneNumber && <span className="text-[10px] px-2 py-0.5 rounded bg-green-500/10 text-green-400 flex items-center gap-1"><Icon name="Phone" size={10}/> {emp.phoneNumber}</span>}
                                </div>
                            </div>
                        ))}
                    </div>
                    </>
                ) : (
                    <div className="bg-white/5 border border-white/5 rounded-2xl overflow-x-auto shadow-2xl p-4">
                        <OrgChart users={allEmployees} />
                    </div>
                )}
            </div>
        )}

        {/* NOTIFICATIONS TAB */}
        {activeTab === 'notifications' && isSystemAdmin && (
            <div className="max-w-2xl mx-auto space-y-8 animate-[fadeIn_0.3s]">
                <div className="bg-white/5 border border-white/5 rounded-2xl p-6 space-y-4">
                    <h3 className="text-lg font-bold text-white">Nomor Admin (WhatsApp)</h3>
                    <input className="w-full bg-black/30 border border-white/10 rounded-lg px-3 py-2 text-white text-sm outline-none" value={waNumber} onChange={e => setWaNumber(e.target.value)} placeholder="628..." />
                </div>
                <div className="bg-white/5 border border-white/5 rounded-2xl p-6 space-y-4">
                    <h3 className="text-lg font-bold text-white">Integrasi Fonnte</h3>
                    <div className="flex gap-2"><input className="flex-1 bg-black/30 border border-white/10 rounded-lg px-3 py-2 text-white text-sm outline-none" type="password" value={fonnteToken} onChange={e => setFonnteToken(e.target.value)} placeholder="Token..." /><button onClick={handleCheckFonnteStatus} className="px-4 py-2 bg-indigo-600 text-white rounded-lg text-xs font-bold">{isCheckingFonnteStatus ? '...' : 'Cek'}</button></div>
                    {fonnteDeviceStatus && (<div className={`p-3 rounded border text-xs ${fonnteDeviceStatus.status ? 'bg-green-500/20 border-green-500/50 text-green-300' : 'bg-red-500/20 border-red-500/50 text-red-300'}`}>{fonnteDeviceStatus.status ? `Connected: ${fonnteDeviceStatus.name}` : `Error: ${fonnteDeviceStatus.reason}`}</div>)}
                    <button onClick={handleTestFonnte} disabled={!fonnteToken} className="w-full py-2 bg-green-600/20 text-green-400 border border-green-600/30 rounded text-xs font-bold">Kirim Pesan Tes</button>
                </div>
                <div className="bg-white/5 border border-white/5 rounded-2xl p-6 space-y-4">
                    <h3 className="text-lg font-bold text-white">Webhook</h3>
                    <input className="w-full bg-black/30 border border-white/10 rounded-lg px-3 py-2 text-white text-sm outline-none" value={webhookUrl} onChange={e => setWebhookUrl(e.target.value)} placeholder="https://..." />
                    <button onClick={handleTestWebhook} className="w-full py-2 bg-yellow-600/20 text-yellow-400 border border-yellow-600/30 rounded text-xs font-bold">Test Webhook</button>
                </div>
                <button onClick={handleSaveNotifications} className="w-full py-3 bg-brand-600 text-white font-bold rounded-xl shadow-lg">Simpan Konfigurasi</button>
            </div>
        )}

        {/* SYSTEM TAB */}
        {activeTab === 'system' && isSystemAdmin && (
            <div className="max-w-4xl mx-auto animate-[fadeIn_0.3s]">
                <div className="flex gap-2 mb-8 bg-black/30 p-1 rounded-xl w-fit overflow-x-auto max-w-full">
                    <button onClick={() => setSystemSubTab('announcements')} className={`px-4 py-2 rounded-lg text-xs font-bold whitespace-nowrap ${systemSubTab === 'announcements' ? 'bg-brand-600 text-white' : 'text-gray-400'}`}>Pengumuman</button>
                    <button onClick={() => setSystemSubTab('attendance')} className={`px-4 py-2 rounded-lg text-xs font-bold whitespace-nowrap ${systemSubTab === 'attendance' ? 'bg-brand-600 text-white' : 'text-gray-400'}`}>Absensi</button>
                    <button onClick={() => setSystemSubTab('backup')} className={`px-4 py-2 rounded-lg text-xs font-bold whitespace-nowrap ${systemSubTab === 'backup' ? 'bg-brand-600 text-white' : 'text-gray-400'}`}>Backup</button>
                </div>

                {systemSubTab === 'announcements' && (<div className="bg-white/5 border border-white/5 rounded-2xl p-6"><h3 className="text-lg font-bold text-white mb-4">Pengumuman Baru</h3><form onSubmit={handleAddAnnouncement} className="space-y-4 mb-8"><input className="w-full bg-black/30 border border-white/10 rounded-lg px-4 py-2 text-white" placeholder="Judul" value={newAnnTitle} onChange={e => setNewAnnTitle(e.target.value)} /><textarea className="w-full bg-black/30 border border-white/10 rounded-lg px-4 py-2 text-white h-24" placeholder="Isi..." value={newAnnContent} onChange={e => setNewAnnContent(e.target.value)} /><button type="submit" className="px-4 py-2 bg-brand-600 text-white rounded-lg font-bold">Posting</button></form><div className="space-y-2">{announcements.map(ann => (<div key={ann.id} className="flex justify-between items-center p-3 bg-black/20 rounded-xl border border-white/5"><div><p className="font-bold text-white">{ann.title}</p><p className="text-xs text-gray-500">{ann.date}</p></div><button onClick={() => handleDeleteAnnouncement(ann.id)} className="text-red-500"><Icon name="Trash2" size={16}/></button></div>))}</div></div>)}

                {systemSubTab === 'attendance' && (
                    <div className="space-y-8">
                        <div className="bg-white/5 border border-white/5 rounded-2xl p-6 space-y-6">
                            <h3 className="text-lg font-bold text-white flex items-center gap-2"><Icon name="Clock" size={18}/> Konfigurasi Jam Kerja</h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6"><div className="space-y-2"><label className="text-xs font-bold text-gray-400 uppercase">Jam Masuk (WIB)</label><input type="time" className="w-full bg-black/30 border border-white/10 rounded px-3 py-2 text-white" value={editWorkStart} onChange={e => setEditWorkStart(e.target.value)} /></div><div className="space-y-2"><label className="text-xs font-bold text-gray-400 uppercase">Jam Pulang (WIB)</label><input type="time" className="w-full bg-black/30 border border-white/10 rounded px-3 py-2 text-white" value={editWorkEnd} onChange={e => setEditWorkEnd(e.target.value)} /></div></div>
                            <div className="flex justify-end"><button onClick={handleSaveAttendanceConfig} className="px-4 py-2 bg-brand-600 hover:bg-brand-500 text-white rounded font-bold transition-colors">Simpan Aturan</button></div>
                        </div>

                        {/* ATTENDANCE HISTORY TABLE */}
                        <div className="bg-white/5 border border-white/5 rounded-2xl p-6">
                            <div className="flex justify-between items-center mb-4">
                                <h3 className="text-lg font-bold text-white flex items-center gap-2"><Icon name="FileText" size={18}/> Laporan Kehadiran</h3>
                                <button onClick={() => alert("Mengunduh CSV...")} className="px-3 py-1.5 bg-green-600 hover:bg-green-500 text-white rounded-lg text-xs font-bold flex items-center gap-2"><Icon name="Download" size={14}/> Export CSV</button>
                            </div>
                            <div className="overflow-x-auto">
                                <table className="w-full text-left border-collapse">
                                    <thead className="bg-black/20 text-gray-400 text-xs uppercase tracking-wider">
                                        <tr><th className="p-3">Tanggal</th><th className="p-3">Nama</th><th className="p-3">Masuk</th><th className="p-3">Keluar</th><th className="p-3">Lokasi</th><th className="p-3">Mood</th></tr>
                                    </thead>
                                    <tbody className="divide-y divide-white/5 text-sm">
                                        {attendanceHistory.length === 0 && <tr><td colSpan={6} className="p-4 text-center text-gray-500">Belum ada data absensi.</td></tr>}
                                        {attendanceHistory.map(rec => (
                                            <tr key={rec.id} className="hover:bg-white/5 transition-colors">
                                                <td className="p-3 font-mono text-gray-300">{rec.date}</td>
                                                <td className="p-3 font-bold text-white">{getUserName(rec.userId)}</td>
                                                <td className="p-3 text-green-400 font-mono">{new Date(rec.checkInTime).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</td>
                                                <td className="p-3 text-red-400 font-mono">{rec.checkOutTime ? new Date(rec.checkOutTime).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}) : '-'}</td>
                                                <td className="p-3"><span className={`px-2 py-0.5 rounded text-[10px] uppercase font-bold ${rec.location === 'WFO' ? 'bg-blue-500/20 text-blue-300' : 'bg-purple-500/20 text-purple-300'}`}>{rec.location}</span></td>
                                                <td className="p-3 text-xl">{rec.mood}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    </div>
                )}

                {systemSubTab === 'backup' && (<div className="space-y-6"><div className="bg-indigo-900/20 border border-indigo-500/30 rounded-2xl p-6"><h3 className="font-bold text-white">Cloud Sync</h3><button onClick={handleCloudSync} disabled={isSyncing} className="mt-4 px-6 py-2 bg-indigo-600 text-white rounded font-bold">{isSyncing ? 'Syncing...' : 'Sync to Cloud'}</button></div><div className="bg-white/5 border border-white/5 rounded-2xl p-6"><h3 className="font-bold text-white">Local Backup</h3><div className="flex flex-col md:flex-row gap-4 mt-4"><button onClick={handleExportConfig} className="flex-1 bg-black/30 border border-white/10 p-4 rounded text-white font-bold">Export JSON</button><label className="flex-1 bg-black/30 border border-white/10 p-4 rounded text-white font-bold cursor-pointer text-center"><input type="file" className="hidden" onChange={handleImportConfig} />Import JSON</label></div></div></div>)}
            </div>
        )}

        </div>
      </div>
      <EmployeeModal isOpen={isEmployeeModalOpen} onClose={() => setIsEmployeeModalOpen(false)} onSave={handleSaveEmployee} initialData={editingEmployee} />
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { User, Tool, Announcement, UserRole, AttendanceConfig, Holiday, UserPreferences, SystemBackup, DivisionType, AttendanceRecord } from '../types';
import { Icon } from './Icon';
import { StorageService } from '../services/storageService';
import { translations, LanguageCode } from '../translations';
import { NotificationService } from '../services/notificationService';
import { UnifiedDataService } from '../services/UnifiedDataService';
import { isSupabaseConfigured } from '../services/supabaseClient';
import { EmployeeModal } from './EmployeeModal';
import { OrgChart } from './OrgChart';
import { EMPLOYEE_DATA } from '../constants';

interface SettingsViewProps {
  user: User;
  onUpdateUser: (user: User) => void;
  tools: Tool[];
  onUpdateTools: (tools: Tool[]) => void;
  announcements: Announcement[];
  onUpdateAnnouncements: (announcements: Announcement[]) => void;
  attendanceConfig: AttendanceConfig;
  onUpdateAttendanceConfig: (config: AttendanceConfig) => void;
  holidays: Holiday[];
  onUpdateHolidays: (holidays: Holiday[]) => void;
  onTeamUpdate: () => void; 
}

export const SettingsView: React.FC<SettingsViewProps> = ({ 
  user, onUpdateUser, tools, onUpdateTools, announcements, onUpdateAnnouncements,
  attendanceConfig, onUpdateAttendanceConfig, holidays, onUpdateHolidays, onTeamUpdate
}) => {
  // Allow Admin, IT Support, AND HR to manage team
  const isSystemAdmin = user.role === UserRole.ADMIN || user.division === DivisionType.IT_SUPPORT;
  const canManageTeam = isSystemAdmin || user.division === DivisionType.HR;

  const [activeTab, setActiveTab] = useState<'team' | 'profile' | 'system' | 'notifications'>(
      'profile' // Default to profile for better UX on mobile start
  );

  const [teamViewMode, setTeamViewMode] = useState<'list' | 'chart'>('list');
  const [searchTerm, setSearchTerm] = useState('');
  const [isSyncing, setIsSyncing] = useState(false);
  const [allEmployees, setAllEmployees] = useState<User[]>([]);
  const [isEmployeeModalOpen, setIsEmployeeModalOpen] = useState(false);
  const [editingEmployee, setEditingEmployee] = useState<User | undefined>(undefined);
  const [fonnteDeviceStatus, setFonnteDeviceStatus] = useState<any>(null);
  const [isCheckingFonnteStatus, setIsCheckingFonnteStatus] = useState(false);
  const [preferences, setPreferences] = useState<UserPreferences>(StorageService.getPreferences());
  const t = translations[preferences.language as LanguageCode] || translations.en;

  const [editName, setEditName] = useState(user.name);
  const [editNote, setEditNote] = useState(user.stickyNote);
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [systemSubTab, setSystemSubTab] = useState<'announcements' | 'attendance' | 'backup'>('announcements');
  const [newAnnTitle, setNewAnnTitle] = useState('');
  const [newAnnContent, setNewAnnContent] = useState('');
  const [newAnnPriority, setNewAnnPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editWorkStart, setEditWorkStart] = useState(attendanceConfig.workStartTime);
  const [editWorkEnd, setEditWorkEnd] = useState(attendanceConfig.workEndTime);
  const [waNumber, setWaNumber] = useState(preferences.whatsappNumber || '');
  const [webhookUrl, setWebhookUrl] = useState(preferences.webhookUrl || '');
  const [fonnteToken, setFonnteToken] = useState(preferences.fonnteToken || '');

  const [attendanceHistory, setAttendanceHistory] = useState<AttendanceRecord[]>([]);

  useEffect(() => {
      setAllEmployees(StorageService.getUsers());
      if (canManageTeam) {
          setAttendanceHistory(StorageService.getAttendanceHistory());
      }
  }, [canManageTeam]);

  const handleAddEmployee = () => { setEditingEmployee(undefined); setIsEmployeeModalOpen(true); };
  const handleEditEmployee = (emp: User) => { setEditingEmployee(emp); setIsEmployeeModalOpen(true); };

  const handleDeleteEmployee = (id: string) => { 
      if (id === user.id) return alert("Anda tidak dapat menghapus akun sendiri."); 
      if (window.confirm("Hapus user ini secara permanen?")) { 
          StorageService.deleteUser(id); 
          setAllEmployees(StorageService.getUsers()); 
          if(onTeamUpdate) onTeamUpdate();
      } 
  };

  const handleSaveEmployee = (empData: User) => { 
      if (editingEmployee) StorageService.updateUser(empData); 
      else StorageService.addUser(empData); 
      setAllEmployees(StorageService.getUsers()); 
      setIsEmployeeModalOpen(false); 
      if(onTeamUpdate) onTeamUpdate();
  };

  const handleSaveProfile = () => { onUpdateUser({ ...user, name: editName, stickyNote: editNote }); alert(t.common.save); };
  const handleAddAnnouncement = (e: React.FormEvent) => { e.preventDefault(); onUpdateAnnouncements([{ id: `ann_${Date.now()}`, title: newAnnTitle, content: newAnnContent, priority: newAnnPriority, date: new Date().toISOString().split('T')[0] }, ...announcements]); setNewAnnTitle(''); setNewAnnContent(''); };
  const handleDeleteAnnouncement = (id: string) => { onUpdateAnnouncements(announcements.filter(a => a.id !== id)); };
  const handleSaveAttendanceConfig = () => { onUpdateAttendanceConfig({ ...attendanceConfig, workStartTime: editWorkStart, workEndTime: editWorkEnd }); alert("Saved"); };
  const handleExportConfig = () => { const blob = new Blob([JSON.stringify(StorageService.createBackup(), null, 2)], { type: 'application/json' }); const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = 'config.json'; a.click(); };
  const handleCloudSync = async () => { if (!window.confirm("Sync to cloud?")) return; setIsSyncing(true); await UnifiedDataService.syncLocalToCloud(StorageService.getTasks(), StorageService.getMessages(), StorageService.getChatGroups()); setIsSyncing(false); alert("Done"); };
  const handleSaveNotifications = () => { const upd = { ...preferences, whatsappNumber: waNumber, webhookUrl, fonnteToken }; setPreferences(upd); StorageService.savePreferences(upd); alert("Saved"); };
  const handleCheckFonnteStatus = async () => { setIsCheckingFonnteStatus(true); setFonnteDeviceStatus(await NotificationService.validateFonnteToken(fonnteToken)); setIsCheckingFonnteStatus(false); };

  const getBadgeColor = (division: string) => { 
      switch(division) { 
          case 'Direksi': return 'bg-purple-500/20 text-purple-300 border-purple-500/30'; 
          case 'Marketing': return 'bg-blue-500/20 text-blue-300 border-blue-500/30'; 
          case 'Administrasi': return 'bg-orange-500/20 text-orange-300 border-orange-500/30'; 
          case 'Keuangan': return 'bg-emerald-500/20 text-emerald-300 border-emerald-500/30'; 
          case 'IT Support': return 'bg-indigo-500/20 text-indigo-300 border-indigo-500/30';
          case 'SDM & Personalia': return 'bg-pink-500/20 text-pink-300 border-pink-500/30';
          default: return 'bg-gray-500/20 text-gray-300 border-gray-500/30'; 
      } 
  };

  const filteredEmployees = allEmployees.filter(emp => emp.name.toLowerCase().includes(searchTerm.toLowerCase()) || emp.division.toLowerCase().includes(searchTerm.toLowerCase()));

  const getUserName = (id: string) => {
      const u = allEmployees.find(emp => emp.id === id);
      return u ? u.name : id;
  };

  return (
