                                <tr><th className="p-4">Nama</th><th className="p-4">Divisi</th><th className="p-4 text-center">Aksi</th></tr>
                            </thead>
                            <tbody className="divide-y divide-white/5 text-sm">
                                {filteredEmployees.map((emp) => (
