import React, { useState, useEffect } from 'react';
import { User, UserRole, DivisionType } from '../types';
import { Icon } from './Icon';
import { DIVISIONS } from '../constants';

interface EmployeeModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (user: User) => void;
  initialData?: User;
}

export const EmployeeModal: React.FC<EmployeeModalProps> = ({ isOpen, onClose, onSave, initialData }) => {
  const [formData, setFormData] = useState<Partial<User>>({
    name: '',
    division: DivisionType.MARKETING,
    role: UserRole.STAFF,
    email: '',
    phoneNumber: '',
    username: ''
  });

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setFormData({ ...initialData });
      } else {
        setFormData({
          name: '',
          division: DivisionType.MARKETING,
          role: UserRole.STAFF,
          email: '',
          phoneNumber: '',
          username: ''
        });
      }
    }
  }, [isOpen, initialData]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.division) return;

    const finalUser: User = {
      id: initialData?.id || `emp_${Date.now()}`,
      username: initialData?.username || formData.name?.toLowerCase().replace(/\s/g, '') || 'user',
      name: formData.name!,
      role: formData.role || UserRole.STAFF,
      division: formData.division!,
      stickyNote: initialData?.stickyNote || 'Welcome!',
      email: formData.email,
      phoneNumber: formData.phoneNumber
    };

    onSave(finalUser);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-[fadeIn_0.2s]">
      <div className="bg-[#1e293b] w-full max-w-lg rounded-2xl border border-white/10 shadow-2xl flex flex-col overflow-hidden">
        <div className="p-6 border-b border-white/10 flex justify-between items-center bg-white/5">
          <h3 className="text-xl font-bold text-white flex items-center gap-2">
            <Icon name={initialData ? "UserCog" : "UserPlus"} className="text-brand-400"/> 
            {initialData ? 'Edit Karyawan' : 'Tambah Karyawan'}
          </h3>
          <button onClick={onClose} className="text-gray-400 hover:text-white transition-colors"><Icon name="X" size={24}/></button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div>
            <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Nama Lengkap</label>
            <input required className="w-full bg-black/30 border border-white/10 rounded-xl px-4 py-3 text-white outline-none focus:border-brand-500 transition-all placeholder-gray-600" placeholder="Contoh: Budi Santoso" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Divisi</label>
              <select className="w-full bg-black/30 border border-white/10 rounded-xl px-3 py-3 text-white outline-none focus:border-brand-500 cursor-pointer" value={formData.division} onChange={e => setFormData({...formData, division: e.target.value as DivisionType})}>
                {DIVISIONS.map(d => (<option key={d.id} value={d.id}>{d.name}</option>))}
              </select>
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Jabatan (Role)</label>
              <select className="w-full bg-black/30 border border-white/10 rounded-xl px-3 py-3 text-white outline-none focus:border-brand-500 cursor-pointer" value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as UserRole})}>
                {Object.values(UserRole).map(r => (<option key={r} value={r}>{r}</option>))}
              </select>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4">
             <div>
                <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Email (Opsional)</label>
                <input type="email" className="w-full bg-black/30 border border-white/10 rounded-xl px-4 py-3 text-white outline-none focus:border-brand-500 transition-all placeholder-gray-600" placeholder="user@company.com" value={formData.email || ''} onChange={e => setFormData({...formData, email: e.target.value})} />
             </div>
             <div>
                <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">WhatsApp (Opsional)</label>
                <input type="tel" className="w-full bg-black/30 border border-white/10 rounded-xl px-4 py-3 text-white outline-none focus:border-brand-500 transition-all placeholder-gray-600" placeholder="62812345678" value={formData.phoneNumber || ''} onChange={e => setFormData({...formData, phoneNumber: e.target.value})} />
             </div>
          </div>
          <div className="pt-4 flex justify-end gap-3">
            <button type="button" onClick={onClose} className="px-6 py-2.5 rounded-xl text-sm font-bold text-gray-400 hover:text-white hover:bg-white/5 transition-colors">Batal</button>
            <button type="submit" className="px-6 py-2.5 bg-brand-600 hover:bg-brand-500 text-white text-sm font-bold rounded-xl shadow-lg transition-all flex items-center gap-2">
              <Icon name="Save" size={16} /> Simpan Data
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { User, Tool, Announcement, UserRole, AttendanceConfig, Holiday, UserPreferences, SystemBackup, DivisionType, AttendanceRecord } from '../types';
import { Icon } from './Icon';
import { StorageService } from '../services/storageService';
import { translations, LanguageCode } from '../translations';
import { NotificationService } from '../services/notificationService';
import { UnifiedDataService } from '../services/UnifiedDataService';
import { isSupabaseConfigured } from '../services/supabaseClient';
import { EmployeeModal } from './EmployeeModal';
import { OrgChart } from './OrgChart';
import { EMPLOYEE_DATA } from '../constants';

interface SettingsViewProps {
  user: User;
  onUpdateUser: (user: User) => void;
  tools: Tool[];
  onUpdateTools: (tools: Tool[]) => void;
  announcements: Announcement[];
  onUpdateAnnouncements: (announcements: Announcement[]) => void;
  attendanceConfig: AttendanceConfig;
  onUpdateAttendanceConfig: (config: AttendanceConfig) => void;
  holidays: Holiday[];
  onUpdateHolidays: (holidays: Holiday[]) => void;
  onTeamUpdate: () => void; 
}

export const SettingsView: React.FC<SettingsViewProps> = ({ 
  user, onUpdateUser, tools, onUpdateTools, announcements, onUpdateAnnouncements,
  attendanceConfig, onUpdateAttendanceConfig, holidays, onUpdateHolidays, onTeamUpdate
}) => {
  const isSystemAdmin = user.role === UserRole.ADMIN || user.division === DivisionType.IT_SUPPORT;
  const canManageTeam = isSystemAdmin || user.division === DivisionType.HR;

  const [activeTab, setActiveTab] = useState<'team' | 'profile' | 'system' | 'notifications'>(
      'profile'
  );

  const [teamViewMode, setTeamViewMode] = useState<'list' | 'chart'>('list');
  const [searchTerm, setSearchTerm] = useState('');
  const [isSyncing, setIsSyncing] = useState(false);
  const [allEmployees, setAllEmployees] = useState<User[]>([]);
  const [isEmployeeModalOpen, setIsEmployeeModalOpen] = useState(false);
  const [editingEmployee, setEditingEmployee] = useState<User | undefined>(undefined);
  const [isCheckingFonnteStatus, setIsCheckingFonnteStatus] = useState(false);
  const [fonnteDeviceStatus, setFonnteDeviceStatus] = useState<any>(null);
  const [preferences, setPreferences] = useState<UserPreferences>(StorageService.getPreferences());
  const t = translations[preferences.language as LanguageCode] || translations.en;

  const [editName, setEditName] = useState(user.name);
  const [editNote, setEditNote] = useState(user.stickyNote);
  const [editRole, setEditRole] = useState(user.role);
  const [systemSubTab, setSystemSubTab] = useState<'announcements' | 'attendance' | 'backup'>('announcements');
  const [newAnnTitle, setNewAnnTitle] = useState('');
  const [newAnnContent, setNewAnnContent] = useState('');
  const [newAnnPriority, setNewAnnPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editWorkStart, setEditWorkStart] = useState(attendanceConfig.workStartTime);
  const [editWorkEnd, setEditWorkEnd] = useState(attendanceConfig.workEndTime);
  const [waNumber, setWaNumber] = useState(preferences.whatsappNumber || '');
  const [fonnteToken, setFonnteToken] = useState(preferences.fonnteToken || '');

  const [attendanceHistory, setAttendanceHistory] = useState<AttendanceRecord[]>([]);

  useEffect(() => {
      setAllEmployees(StorageService.getUsers());
      if (canManageTeam) {
          setAttendanceHistory(StorageService.getAttendanceHistory());
      }
  }, [canManageTeam]);

  const handleAddEmployee = () => { setEditingEmployee(undefined); setIsEmployeeModalOpen(true); };
  const handleEditEmployee = (emp: User) => { setEditingEmployee(emp); setIsEmployeeModalOpen(true); };

  const handleDeleteEmployee = (id: string) => { 
      if (id === user.id) return alert("Anda tidak dapat menghapus akun sendiri."); 
      if (window.confirm("Hapus user ini secara permanen?")) { 
          StorageService.deleteUser(id); 
          setAllEmployees(StorageService.getUsers()); 
          if(onTeamUpdate) onTeamUpdate();
      } 
  };

  const handleSaveEmployee = (empData: User) => { 
      if (editingEmployee) StorageService.updateUser(empData); 
      else StorageService.addUser(empData); 
      setAllEmployees(StorageService.getUsers()); 
      setIsEmployeeModalOpen(false); 
      if(onTeamUpdate) onTeamUpdate();
  };

  const handleSaveProfile = () => { onUpdateUser({ ...user, name: editName, stickyNote: editNote, role: editRole }); alert(t.common.save); };

  const handleAddAnnouncement = (e: React.FormEvent) => { 
    e.preventDefault(); 
    onUpdateAnnouncements([{ id: `ann_${Date.now()}`, title: newAnnTitle, content: newAnnContent, priority: newAnnPriority, date: new Date().toISOString().split('T')[0] }, ...announcements]); 
    setNewAnnTitle(''); 
    setNewAnnContent(''); 
  };

  const handleDeleteAnnouncement = (id: string) => { onUpdateAnnouncements(announcements.filter(a => a.id !== id)); };

  const handleSaveAttendanceConfig = () => { 
    onUpdateAttendanceConfig({ ...attendanceConfig, workStartTime: editWorkStart, workEndTime: editWorkEnd }); 
    alert("Saved"); 
  };

  const handleExportConfig = () => { 
    const blob = new Blob([JSON.stringify(StorageService.createBackup(), null, 2)], { type: 'application/json' }); 
    const a = document.createElement('a'); 
    a.href = URL.createObjectURL(blob); 
    a.download = 'config.json'; 
    a.click(); 
  };

  const handleCloudSync = async () => { 
    if (!window.confirm("Sync to cloud?")) return; 
    setIsSyncing(true); 
    const syncRes = await UnifiedDataService.syncLocalToCloud(StorageService.getTasks(), StorageService.getMessages(), StorageService.getChatGroups()); 
    setIsSyncing(false); 
    if(syncRes.success) alert("Data berhasil disinkronkan ke Cloud.");
    else alert("Gagal sinkron: " + syncRes.message);
  };

  const handleSaveNotifications = () => { 
    const upd = { ...preferences, whatsappNumber: waNumber, fonnteToken }; 
    setPreferences(upd); 
    StorageService.savePreferences(upd); 
