    setIsSyncing(true); 
    const res = await UnifiedDataService.syncLocalToCloud(StorageService.getTasks(), StorageService.getMessages(), StorageService.getChatGroups()); 
    setIsSyncing(false); 
    alert(res.success ? "Sinkronisasi Berhasil" : "Gagal: " + res.message); 
  };

  const handleSaveNotifications = () => { 
    const upd = { ...preferences, whatsappNumber: waNumber, fonnteToken }; 
    setPreferences(upd); 
    StorageService.savePreferences(upd); 
    alert("Konfigurasi WA Tersimpan"); 
  };

  const filteredEmployees = allEmployees.filter(emp => emp.name.toLowerCase().includes(searchTerm.toLowerCase()) || emp.division.toLowerCase().includes(searchTerm.toLowerCase()));

  return (
    <div className="flex h-full bg-[#0b0f1a] overflow-hidden">
