import React, { useState, useEffect } from 'react';
import { User, Task, TaskPriority, DivisionType, UserRole } from '../types';
import { Icon } from './Icon';
import { StorageService } from '../services/storageService';
import { translations, LanguageCode } from '../translations';
import { DIVISIONS } from '../constants';
import { TaskItem } from './TaskItem';

interface TaskBoardProps {
  user: User;
  tasks: Task[];
  onAdd: (task: Task) => void;
  onToggle: (taskId: string) => void;
  onDelete: (taskId: string) => void;
  onTaskClick?: (task: Task) => void;
  onWhatsApp?: (task: Task) => void;
  onDiscuss?: (task: Task) => void;
  divisionContext: DivisionType | null; 
  isEmbedded?: boolean; 
}

export const TaskBoard: React.FC<TaskBoardProps> = ({ 
    user, tasks, onAdd, onToggle, onDelete, onTaskClick, onWhatsApp, onDiscuss, divisionContext, isEmbedded = false
}) => {
    const [activeTab, setActiveTab] = useState<'my_tasks' | 'delegated' | 'incoming'>('my_tasks');

    // Add Task State
    const [newTaskTitle, setNewTaskTitle] = useState('');
    const [newTaskTargetDivision, setNewTaskTargetDivision] = useState<DivisionType>(user.division);
    const [newTaskAssignee, setNewTaskAssignee] = useState(user.id);
    const [newTaskPriority, setNewTaskPriority] = useState<TaskPriority>('medium');

    // Team Data
    const [teamUsers, setTeamUsers] = useState<User[]>([]);

    const prefs = StorageService.getPreferences();
    const t = translations[prefs.language as LanguageCode] || translations.en;

    useEffect(() => {
        setTeamUsers(StorageService.getUsers());
        if (!divisionContext) {
            setNewTaskAssignee(user.id);
            setNewTaskTargetDivision(user.division);
        }
    }, [user.id, user.division, divisionContext]);

    // Update Assignee List when Target Division Changes
    useEffect(() => {
        const potentialAssignees = teamUsers.filter(u => u.division === newTaskTargetDivision);
        if (potentialAssignees.length > 0) {
            const manager = potentialAssignees.find(u => u.role === UserRole.MANAGER);
            setNewTaskAssignee(manager ? manager.id : potentialAssignees[0].id);
        } else if (newTaskTargetDivision === user.division) {
            setNewTaskAssignee(user.id);
        } else {
            setNewTaskAssignee('');
        }
    }, [newTaskTargetDivision, teamUsers, user.id, user.division]);

    const isDivisionView = !!divisionContext;
    const divisionUsers = isDivisionView ? teamUsers.filter(u => u.division === divisionContext) : [];

    const myTasks = tasks.filter(t => t.assigneeId === user.id);
    const delegatedTasks = tasks.filter(t => t.creatorId === user.id && t.assigneeId !== user.id);
    const incomingRequests = tasks.filter(t => t.targetDivisionId === user.division && t.originDivisionId !== user.division);

    const displayTasksStandard = activeTab === 'my_tasks' ? myTasks : (activeTab === 'delegated' ? delegatedTasks : incomingRequests);
    const canSeeIncoming = user.role === UserRole.MANAGER || user.role === UserRole.ADMIN;

    const handleAddTask = (e: React.FormEvent, specificAssignee?: string) => {
        e.preventDefault();
        if(!newTaskTitle.trim()) return;

        const assigneeId = specificAssignee || newTaskAssignee;

        const newTask: Task = {
            id: `tsk_${Date.now()}`,
            title: newTaskTitle,
            creatorId: user.id,
            assigneeId: assigneeId,
            priority: newTaskPriority,
            isCompleted: false,
            originDivisionId: user.division,
            targetDivisionId: isDivisionView ? divisionContext : newTaskTargetDivision,
            timestamp: Date.now()
        };

        onAdd(newTask);
        setNewTaskTitle('');
    };

    const getPriorityColor = (p: TaskPriority) => {
        switch(p) {
            case 'high': return 'bg-red-500 text-white';
            case 'medium': return 'bg-amber-500 text-white';
            case 'low': return 'bg-blue-500 text-white';
        }
    };

    const getDivisionName = (id?: string) => {
        return DIVISIONS.find(d => d.id === id)?.name || id;
    };

    const renderTaskList = (taskList: Task[], showAssigneeName: boolean = false, showOrigin: boolean = false) => (
        <div className="space-y-2">
            {taskList.length === 0 && <p className="text-xs text-gray-500 italic text-center py-4">Belum ada tugas.</p>}
            {taskList.sort((a,b) => (b.timestamp || 0) - (a.timestamp || 0)).map(task => (
                <TaskItem 
                    key={task.id}
                    task={{
                        ...task,
                        divName: showOrigin && task.originDivisionId ? `${t.tasks.from} ${getDivisionName(task.originDivisionId)}` : undefined
                    }}
                    onToggle={() => onToggle(task.id)}
                    onSelect={() => onTaskClick && onTaskClick(task)}
                    onDelete={() => onDelete(task.id)}
                    onDiscuss={() => onDiscuss && onDiscuss(task)}
                    onWhatsApp={() => onWhatsApp && onWhatsApp(task)}
                    onReminder={() => {}} 
                />
            ))}
        </div>
    );

    return (
        <div className={`flex flex-col h-full ${isEmbedded ? '' : 'overflow-hidden'}`}>
            {!isDivisionView && (
                <div className="flex gap-2 p-6 border-b border-white/5 bg-white/5 shrink-0">
                    <button onClick={() => setActiveTab('my_tasks')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition-colors flex items-center justify-center gap-2 ${activeTab === 'my_tasks' ? 'bg-brand-600 text-white shadow-lg' : 'bg-white/5 text-gray-400'}`}>
                        <Icon name="User" size={14} /> Tugas Saya <span className="bg-white/20 px-1.5 rounded-full text-[10px]">{myTasks.filter(t => !t.isCompleted).length}</span>
                    </button>
                    <button onClick={() => setActiveTab('delegated')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition-colors flex items-center justify-center gap-2 ${activeTab === 'delegated' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white/5 text-gray-400'}`}>
                        <Icon name="Users" size={14} /> Delegasi <span className="bg-white/20 px-1.5 rounded-full text-[10px]">{delegatedTasks.filter(t => !t.isCompleted).length}</span>
                    </button>
                    {canSeeIncoming && (
                        <button onClick={() => setActiveTab('incoming')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition-colors flex items-center justify-center gap-2 ${activeTab === 'incoming' ? 'bg-purple-600 text-white shadow-lg' : 'bg-white/5 text-gray-400'}`}>
                            <Icon name="Inbox" size={14} /> Masuk <span className="bg-white/20 px-1.5 rounded-full text-[10px]">{incomingRequests.filter(t => !t.isCompleted).length}</span>
                        </button>
                    )}
                </div>
            )}

            <div className={`flex-1 overflow-y-auto custom-scrollbar p-6`}>
                {isDivisionView ? (
                    <div className="space-y-6">
                        {divisionUsers.map(member => (
                            <div key={member.id} className="bg-white/5 rounded-xl border border-white/5 overflow-hidden">
                                <div className="p-3 bg-white/5 border-b border-white/5 flex justify-between items-center">
                                    <div className="flex items-center gap-2">
                                        <div className="w-7 h-7 rounded-full bg-indigo-500 flex items-center justify-center text-white font-bold text-[10px]">{member.name.charAt(0)}</div>
                                        <span className="text-xs font-bold text-white">{member.name}</span>
                                    </div>
                                    <button onClick={() => setNewTaskAssignee(member.id)} className={`p-1 rounded text-gray-400 ${newTaskAssignee === member.id ? 'text-brand-400' : ''}`}><Icon name="Plus" size={14} /></button>
                                </div>
                                <div className="p-3">
                                    {newTaskAssignee === member.id && (
                                        <form onSubmit={(e) => handleAddTask(e, member.id)} className="mb-3 flex gap-2">
                                            <input autoFocus className="flex-1 bg-black/20 border border-white/10 rounded-lg px-3 py-1.5 text-xs text-white outline-none focus:border-brand-500" placeholder="Tugas baru..." value={newTaskTitle} onChange={e => setNewTaskTitle(e.target.value)} />
                                            <button type="submit" className="p-1.5 bg-brand-600 text-white rounded-lg"><Icon name="ArrowRight" size={12}/></button>
                                        </form>
                                    )}
                                    {renderTaskList(tasks.filter(t => t.assigneeId === member.id))}
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    renderTaskList(displayTasksStandard, activeTab === 'delegated', activeTab === 'incoming')
                )}
            </div>

            {!isDivisionView && (
                <div className="p-4 bg-white/5 border-t border-white/5 shrink-0">
                    <form onSubmit={handleAddTask} className="flex flex-col gap-2">
                        <div className="flex gap-2">
                            <input type="text" value={newTaskTitle} onChange={e => setNewTaskTitle(e.target.value)} placeholder="Tulis tugas..." className="flex-1 bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-sm text-white focus:ring-1 focus:ring-brand-500 outline-none" />
                            <button type="submit" disabled={!newTaskTitle} className="p-2 bg-brand-600 text-white rounded-xl disabled:opacity-50"><Icon name="Plus" /></button>
                        </div>
                        <div className="flex gap-2">
                             <select value={newTaskTargetDivision} onChange={e => setNewTaskTargetDivision(e.target.value as DivisionType)} className="flex-1 bg-black/20 border border-white/10 text-[10px] text-gray-300 rounded-lg px-2 py-1 outline-none">
                                {DIVISIONS.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                            </select>
                            <select value={newTaskPriority} onChange={e => setNewTaskPriority(e.target.value as TaskPriority)} className="w-24 bg-black/20 border border-white/10 text-[10px] text-gray-300 rounded-lg px-2 py-1 outline-none">
                                <option value="low">Low</option>
                                <option value="medium">Normal</option>
                                <option value="high">High</option>
                            </select>
                        </div>
                    </form>
                </div>
            )}
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Task, Subtask } from '../types';
import { Icon } from './Icon';
import { UnifiedDataService } from '../services/UnifiedDataService';
import { GeminiService } from '../services/geminiService';

interface TaskDetailViewProps {
    task: Task & { divName?: string, divIcon?: string, description?: string, divId?: string };
    isOpen: boolean;
    onClose: () => void;
    onToggle: () => void;
    onDelete: () => void;
    onUpdate: (updates: Partial<Task>) => void;
}

export const TaskDetailView: React.FC<TaskDetailViewProps> = ({ task, isOpen, onClose, onToggle, onDelete, onUpdate }) => {
    const [desc, setDesc] = useState(task.description || '');
    const [title, setTitle] = useState(task.title || '');
    const [subtasks, setSubtasks] = useState<Subtask[]>(task.subtasks || []);
    const [newSubtaskTitle, setNewSubtaskTitle] = useState('');
    const [isUploading, setIsUploading] = useState(false);
    const [isGeneratingSubtasks, setIsGeneratingSubtasks] = useState(false);

    useEffect(() => { 
        setDesc(task.description || ''); 
        setTitle(task.title || ''); 
        setSubtasks(task.subtasks || []);
    }, [task.id]);

    const saveChanges = (updates: Partial<Task>) => onUpdate(updates);
    const handleBlur = () => saveChanges({ title, description: desc, subtasks });

    const addSubtask = (e?: React.FormEvent) => {
        if(e) e.preventDefault();
        if (!newSubtaskTitle.trim()) return;
        const newSub: Subtask = { id: `sub_${Date.now()}`, title: newSubtaskTitle, isCompleted: false };
        const updated = [...subtasks, newSub];
        setSubtasks(updated);
        saveChanges({ subtasks: updated });
        setNewSubtaskTitle('');
    };

    const toggleSubtask = (subId: string) => {
        const updated = subtasks.map(s => s.id === subId ? { ...s, isCompleted: !s.isCompleted } : s);
        setSubtasks(updated);
        saveChanges({ subtasks: updated });
    };

    const handleAIBreakdown = async () => {
        setIsGeneratingSubtasks(true);
        try {
            const steps = await GeminiService.generateSubtasks(title, desc);
            const newSubs = steps.map((s, idx) => ({ id: `ai_sub_${Date.now()}_${idx}`, title: s.title, isCompleted: false }));
            const updated = [...subtasks, ...newSubs];
            setSubtasks(updated);
            saveChanges({ subtasks: updated });
        } catch (e) {
            alert("AI gagal memproses.");
        } finally {
            setIsGeneratingSubtasks(false);
        }
    };

    const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        setIsUploading(true);
        try {
            const url = await UnifiedDataService.uploadAttachment(file);
            if (url) saveChanges({ attachmentUrl: url });
        } catch (e) {
            alert("Upload gagal.");
        } finally {
            setIsUploading(false);
        }
    };

    const progress = subtasks.length > 0 ? Math.round((subtasks.filter(s => s.isCompleted).length / subtasks.length) * 100) : 0;

    return (
        <>
            <div className={`fixed inset-0 bg-black/70 backdrop-blur-sm z-[99] transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`} onClick={onClose}></div>
            <div className={`fixed z-[100] bg-[#0f172a] shadow-2xl flex flex-col transition-transform duration-300 ease-out bottom-0 left-0 right-0 w-full h-[85vh] md:h-full md:top-0 md:left-auto md:w-[500px] rounded-t-3xl md:rounded-none border-t border-white/10 md:border-t-0 md:border-l ${isOpen ? 'translate-y-0 md:translate-x-0' : 'translate-y-full md:translate-x-full md:translate-y-0'}`}>
                <div className="h-14 border-b border-white/5 flex items-center justify-between px-6 shrink-0">
                    <span className="text-[10px] font-bold text-brand-400 uppercase tracking-widest">{task.divName || "Detail Tugas"}</span>
                    <button onClick={onClose} className="p-2 text-gray-400"><Icon name="X" size={20}/></button>
                </div>
                <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-6">
                    <div className="space-y-4">
                        <div className="flex items-start gap-3">
                            <button onClick={onToggle} className={`mt-1 w-6 h-6 rounded-lg border flex items-center justify-center transition-all ${task.isCompleted ? 'bg-emerald-500 border-emerald-500' : 'border-gray-500'}`}>{task.isCompleted && <Icon name="Check" size={14} className="text-white" />}</button>
                            <input className="w-full bg-transparent text-lg font-bold text-white outline-none" value={title} onChange={(e) => setTitle(e.target.value)} onBlur={handleBlur} />
                        </div>
                    </div>
                    <div className="space-y-4">
                        <div className="flex items-center justify-between">
                            <h4 className="text-[10px] font-bold text-gray-500 uppercase">Checklist {progress}%</h4>
                            <button onClick={handleAIBreakdown} disabled={isGeneratingSubtasks} className="text-[9px] flex items-center gap-1.5 bg-purple-500/10 text-purple-300 px-3 py-1 rounded-lg border border-purple-500/20">{isGeneratingSubtasks ? "..." : "AI Breakdown"}</button>
                        </div>
                        <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden"><div className="h-full bg-brand-500 transition-all duration-500" style={{ width: `${progress}%` }}></div></div>
                        <div className="space-y-2">
                            {subtasks.map(sub => (
                                <div key={sub.id} className="flex items-center gap-3 bg-white/5 p-3 rounded-xl border border-white/5" onClick={() => toggleSubtask(sub.id)}>
                                    <div className={`w-4 h-4 rounded border flex items-center justify-center ${sub.isCompleted ? 'bg-brand-500 border-brand-500' : 'border-gray-600'}`}>{sub.isCompleted && <Icon name="Check" size={10} className="text-white" />}</div>
                                    <span className={`text-sm ${sub.isCompleted ? 'text-gray-500 line-through' : 'text-gray-200'}`}>{sub.title}</span>
                                </div>
                            ))}
                        </div>
                        <form onSubmit={addSubtask} className="flex items-center gap-3 px-3 py-2 bg-black/20 rounded-xl border border-dashed border-white/10">
                            <Icon name="Plus" size={14} className="text-gray-500" />
                            <input className="flex-1 bg-transparent text-sm text-white outline-none" placeholder="Tambah sub-tugas..." value={newSubtaskTitle} onChange={(e) => setNewSubtaskTitle(e.target.value)} />
                        </form>
                    </div>
                    <div className="space-y-2">
                        <h4 className="text-[10px] font-bold text-gray-500 uppercase">Lampiran & Dokumen</h4>
                        {task.attachmentUrl ? (
                            <div className="p-3 bg-white/5 rounded-xl border border-white/10 flex items-center justify-between">
                                <a href={task.attachmentUrl} target="_blank" rel="noreferrer" className="text-sm font-bold text-white flex items-center gap-2 truncate"><Icon name="FileText" size={16} /> Buka File</a>
                                <button onClick={() => saveChanges({ attachmentUrl: undefined })} className="p-1 text-red-400"><Icon name="Trash2" size={16}/></button>
                            </div>
                        ) : (
                            <div className="relative border-2 border-dashed border-white/10 rounded-xl p-6 flex flex-col items-center justify-center text-gray-500 hover:bg-white/5 transition-all">
                                <input type="file" onChange={handleFileUpload} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" disabled={isUploading}/>
                                {isUploading ? <Icon name="Loader2" className="animate-spin" /> : <><Icon name="UploadCloud" className="mb-1" /><p className="text-[10px] font-bold">Klik untuk upload bukti</p></>}
                            </div>
                        )}
                    </div>
                    <div className="space-y-2">
                        <h4 className="text-[10px] font-bold text-gray-500 uppercase">Deskripsi / Catatan</h4>
                        <textarea className="w-full min-h-[100px] bg-black/20 border border-white/10 rounded-xl p-3 text-sm text-gray-300 outline-none" placeholder="Tambahkan detail..." value={desc} onChange={(e) => setDesc(e.target.value)} onBlur={handleBlur} />
                    </div>
                </div>
                <div className="p-6 border-t border-white/5 bg-black/30 flex justify-between">
                    <button onClick={onDelete} className="p-3 text-red-400 hover:bg-red-400/10 rounded-xl"><Icon name="Trash2" size={20} /></button>
                    <button onClick={onClose} className="px-6 py-2 bg-brand-600 text-white font-bold rounded-xl shadow-lg">Selesai</button>
                </div>
            </div>
        </>
    );
};

import React, { useState, useEffect, useRef } from 'react';
import { User, Tool, Announcement, UserRole, AttendanceConfig, Holiday, UserPreferences, SystemBackup, DivisionType, AttendanceRecord } from '../types';
