import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { Icon } from './Icon';
import { Tool, User, DivisionData, Task } from '../types';

interface QuickCommandProps {
  isOpen: boolean;
  onClose: () => void;
  tools: Tool[];
  users: User[];
  divisions: DivisionData[];
  tasks: Task[];
  onTaskSelect: (task: Task) => void;
}

export const QuickCommand: React.FC<QuickCommandProps> = ({ isOpen, onClose, tools, users, divisions, tasks, onTaskSelect }) => {
  const [query, setQuery] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const inputRef = useRef<HTMLInputElement>(null);
  const navigate = useNavigate();

  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 50);
      setQuery('');
      setSelectedIndex(0);
    }
  }, [isOpen]);

  const filteredItems = React.useMemo(() => {
    if (!query) return [];
    const lowerQuery = query.toLowerCase();

    const commands = [
        { label: 'Dashboard Utama', action: () => navigate('/'), icon: 'Layout' },
        { label: 'Buka Pesan Tim', action: () => navigate('/messages'), icon: 'MessageSquare' },
        { label: 'Pengaturan Sistem', action: () => navigate('/settings'), icon: 'Settings' },
        { label: 'Log Absensi', action: () => navigate('/settings'), icon: 'Fingerprint' },
    ].filter(c => c.label.toLowerCase().includes(lowerQuery)).map(c => ({ type: 'ACTION', data: c }));

    const resultTasks = tasks.filter(t => t.title.toLowerCase().includes(lowerQuery) && !t.isCompleted).map(t => ({ type: 'TUGAS', data: t }));
    const resultUsers = users.filter(u => u.name.toLowerCase().includes(lowerQuery)).map(u => ({ type: 'ORANG', data: u }));
    const resultDivs = divisions.filter(d => d.name.toLowerCase().includes(lowerQuery)).map(d => ({ type: 'DIVISI', data: d }));
    const resultTools = tools.filter(t => t.name.toLowerCase().includes(lowerQuery)).map(t => ({ type: 'ALAT', data: t }));

    return [...commands, ...resultTasks, ...resultDivs, ...resultTools, ...resultUsers].slice(0, 10);
  }, [query, tools, users, divisions, tasks, navigate]);

  const handleSelect = (item: any) => {
    if (!item) return;
    if (item.type === 'ACTION') item.data.action();
    else if (item.type === 'DIVISI') navigate(`/division/${item.data.id}`);
    else if (item.type === 'ALAT') { if(item.data.url && item.data.url !== '#') window.open(item.data.url, '_blank'); }
    else if (item.type === 'TUGAS') onTaskSelect(item.data);
    else if (item.type === 'ORANG') navigate('/messages'); 
    onClose();
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'ArrowDown') setSelectedIndex(prev => (prev + 1) % filteredItems.length);
    else if (e.key === 'ArrowUp') setSelectedIndex(prev => (prev - 1 + filteredItems.length) % filteredItems.length);
    else if (e.key === 'Enter') handleSelect(filteredItems[selectedIndex]);
    else if (e.key === 'Escape') onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[150] flex items-start justify-center pt-[12vh] bg-[#020617]/80 backdrop-blur-xl transition-all" onClick={onClose}>
      <div 
        className="w-full max-w-2xl bg-[#1e293b]/90 border border-white/10 rounded-[2rem] shadow-[0_30px_100px_rgba(0,0,0,0.8)] overflow-hidden animate-[scaleIn_0.15s_ease-out] ring-1 ring-white/20"
        onClick={e => e.stopPropagation()}
      >
        <div className="flex items-center gap-4 px-6 py-5 border-b border-white/5 bg-white/5">
          <Icon name="Search" className="text-brand-400" size={24} />
          <input
            ref={inputRef}
            className="flex-1 bg-transparent text-white placeholder-gray-500 outline-none text-lg font-medium"
            placeholder="Cari apa saja... (tugas, alat, atau perintah)"
            value={query}
            onChange={e => setQuery(e.target.value)}
            onKeyDown={handleKeyDown}
          />
          <div className="flex items-center gap-1.5">
             <kbd className="px-2 py-1 bg-white/5 border border-white/10 rounded-md text-[10px] font-bold text-gray-500">ESC</kbd>
          </div>
        </div>

        <div className="max-h-[50vh] overflow-y-auto custom-scrollbar p-3">
            {filteredItems.length === 0 && query ? (
                <div className="py-12 text-center">
                    <Icon name="SearchX" size={48} className="mx-auto text-gray-700 mb-4 opacity-20" />
                    <p className="text-gray-500 font-medium">Tidak ada hasil untuk "{query}"</p>
                </div>
            ) : filteredItems.length === 0 && !query ? (
                <div className="p-4">
                    <p className="text-[10px] font-bold text-gray-500 uppercase tracking-[0.2em] mb-4 ml-2">Saran Pencarian</p>
                    <div className="grid grid-cols-2 gap-2">
                        {['Buka Marketing', 'Absen Sekarang', 'Tugas Baru', 'Cari Alex'].map(s => (
                            <button key={s} onClick={() => setQuery(s)} className="flex items-center gap-3 p-3 rounded-2xl bg-white/5 hover:bg-white/10 border border-white/5 text-left transition-all">
                                <Icon name="Zap" size={14} className="text-brand-400" />
                                <span className="text-xs text-gray-300 font-medium">{s}</span>
                            </button>
                        ))}
                    </div>
                </div>
            ) : null}

            {filteredItems.map((item, idx) => (
                <button
                    key={idx}
                    onClick={() => handleSelect(item)}
                    className={`w-full text-left px-4 py-3.5 rounded-2xl flex items-center gap-4 transition-all ${idx === selectedIndex ? 'bg-brand-600 text-white shadow-xl shadow-brand-600/20 translate-x-1' : 'text-gray-400 hover:bg-white/5'}`}
                >
                    <div className={`p-2 rounded-xl shrink-0 ${idx === selectedIndex ? 'bg-white/20' : 'bg-white/5 border border-white/10'}`}>
                        <Icon 
                            name={
                                item.type === 'ACTION' ? (item.data as any).icon : 
                                item.type === 'DIVISI' ? 'Briefcase' :
                                item.type === 'TUGAS' ? 'CheckSquare' :
                                item.type === 'ORANG' ? 'User' : 
                                (item.data as Tool).icon || 'Link'
                            } 
                            size={18} 
                        />
                    </div>
                    <div className="flex-1 min-w-0">
                        <p className={`text-sm font-bold truncate ${idx === selectedIndex ? 'text-white' : 'text-gray-200'}`}>
                            {item.type === 'ACTION' ? (item.data as any).label : 
                             item.type === 'TUGAS' ? (item.data as Task).title : 
                             (item.data as any).name}
                        </p>
                        <div className="flex items-center gap-2 mt-0.5">
                            <span className={`text-[9px] font-black uppercase tracking-widest px-1.5 py-0.5 rounded ${idx === selectedIndex ? 'bg-white/20 text-white' : 'bg-black/20 text-gray-500'}`}>
                                {item.type}
                            </span>
                            {item.type === 'TUGAS' && (item.data as Task).priority === 'high' && (
                                <span className="text-[9px] text-red-400 font-bold">URGENT</span>
                            )}
                        </div>
                    </div>
                    {idx === selectedIndex && (
                        <div className="flex items-center gap-1 opacity-60">
                             <span className="text-[10px] font-bold">ENTER</span>
                             <Icon name="CornerDownLeft" size={12} />
                        </div>
                    )}
                </button>
            ))}
        </div>

        <div className="px-6 py-4 bg-black/20 border-t border-white/5 flex justify-between items-center text-[10px] text-gray-500 font-bold">
            <div className="flex gap-4">
                <span className="flex items-center gap-1.5"><Icon name="ArrowUp" size={10}/> <Icon name="ArrowDown" size={10}/> Navigasi</span>
                <span className="flex items-center gap-1.5"><Icon name="CornerDownLeft" size={10}/> Pilih</span>
            </div>
            <span className="text-brand-500/50 uppercase tracking-widest">Pintu Kuliah Command Center</span>
        </div>
      </div>
    </div>
  );
};

import { StorageService } from './storageService';
import { supabase, isSupabaseConfigured } from './supabaseClient';
import { Task, ChatMessage, ChatGroup } from '../types';

// Helper to safely stringify errors
const getErrorMessage = (error: any): string => {
    if (!error) return 'Unknown Error';
    if (typeof error === 'object' && error !== null) {
        if (error.message) {
            let msg = error.message;
            if (error.details) msg += ` (${error.details})`;
            if (error.hint) msg += ` Hint: ${error.hint}`;
            return msg;
        }
        if (error.error_description) return error.error_description;
    }
    if (typeof error === 'string') return error;
    if (error instanceof Error) return error.message;
    try {
        return JSON.stringify(error);
    } catch (e) {
        return 'Non-serializable error object';
    }
};

export const UnifiedDataService = {

    getTasks: async (): Promise<Task[]> => {
        if (isSupabaseConfigured()) {
            try {
                const { data, error } = await supabase!
                    .from('tasks')
                    .select('*')
                    .order('created_at', { ascending: false });

                if (error) {
                    console.warn("Supabase Error (getTasks):", error);
                    return StorageService.getTasks();
                }

                return (data || []).map((d: any) => ({
                    id: d.id,
                    title: d.title,
                    description: d.description,
                    isCompleted: d.is_completed,
                    priority: d.priority,
                    creatorId: d.creator_id,
                    assigneeId: d.assignee_id,
                    originDivisionId: d.origin_division_id,
                    targetDivisionId: d.target_division_id,
                    dueDate: d.due_date,
                    reminderAt: d.reminder_at,
                    isReminded: d.is_reminded,
                    attachmentUrl: d.attachment_url,
                    subtasks: d.subtasks || [],
                    timestamp: d.created_at ? new Date(d.created_at).getTime() : Date.now()
                }));
            } catch (err) {
                console.warn("Supabase Exception (getTasks):", err);
                return StorageService.getTasks();
            }
        }
        return StorageService.getTasks();
    },

    addTask: async (task: Task) => {
        const current = StorageService.getTasks();
        StorageService.saveTasks([task, ...current]);

        if (isSupabaseConfigured()) {
            try {
                const { error } = await supabase!.from('tasks').insert([{
                    id: task.id,
                    title: task.title,
                    description: task.description,
                    is_completed: task.isCompleted,
                    priority: task.priority,
                    creator_id: task.creatorId,
                    assignee_id: task.assigneeId,
                    origin_division_id: task.origin_division_id,
                    target_division_id: task.target_division_id,
                    due_date: task.dueDate,
                    reminder_at: task.reminderAt,
                    is_reminded: task.isReminded,
                    attachment_url: task.attachmentUrl,
                    subtasks: task.subtasks,
                    created_at: new Date(task.timestamp || Date.now()).toISOString()
                }]);
                if (error) console.warn("DB Insert Error:", getErrorMessage(error));
            } catch (err) {
                console.warn("DB Insert Exception:", getErrorMessage(err));
            }
        }
    },

    updateTask: async (taskId: string, updates: Partial<Task>) => {
        const current = StorageService.getTasks();
        const updated = current.map(t => t.id === taskId ? { ...t, ...updates } : t);
        StorageService.saveTasks(updated);

        if (isSupabaseConfigured()) {
            try {
                const dbUpdates: any = {};
                if (updates.title !== undefined) dbUpdates.title = updates.title;
                if (updates.description !== undefined) dbUpdates.description = updates.description;
                if (updates.isCompleted !== undefined) dbUpdates.is_completed = updates.isCompleted;
                if (updates.priority !== undefined) dbUpdates.priority = updates.priority;
                if (updates.assigneeId !== undefined) dbUpdates.assignee_id = updates.assigneeId;
                if (updates.isReminded !== undefined) dbUpdates.is_reminded = updates.isReminded;
                if (updates.reminderAt !== undefined) dbUpdates.reminder_at = updates.reminderAt;
                if (updates.attachmentUrl !== undefined) dbUpdates.attachment_url = updates.attachmentUrl;
                if (updates.subtasks !== undefined) dbUpdates.subtasks = updates.subtasks;

                const { error } = await supabase!.from('tasks').update(dbUpdates).eq('id', taskId);
                if (error) console.warn("DB Update Error:", getErrorMessage(error));
            } catch (err) {
                console.warn("DB Update Exception:", getErrorMessage(err));
            }
        }
    },

    deleteTask: async (taskId: string) => {
        const current = StorageService.getTasks();
        StorageService.saveTasks(current.filter(t => t.id !== taskId));

        if (isSupabaseConfigured()) {
            try {
                const { error } = await supabase!.from('tasks').delete().eq('id', taskId);
                if (error) console.warn("DB Delete Error:", getErrorMessage(error));
            } catch (err) {
                console.warn("DB Delete Exception:", getErrorMessage(err));
            }
        }
    },

    uploadAttachment: async (file: File): Promise<string | null> => {
        if (!isSupabaseConfigured()) {
            alert("Error: Database Cloud belum terhubung. Tidak bisa upload.");
            return null;
        }
        try {
            const fileExt = file.name.split('.').pop();
            const fileName = `${Date.now()}_${Math.random().toString(36).substring(2)}.${fileExt}`;
            const filePath = `${fileName}`;
            const { error: uploadError } = await supabase!.storage.from('task-attachments').upload(filePath, file);
            if (uploadError) {
                console.error("Upload Error:", uploadError);
                return null;
            }
            const { data } = supabase!.storage.from('task-attachments').getPublicUrl(filePath);
            return data.publicUrl;
        } catch (e) {
            console.error("Upload Exception:", e);
            return null;
        }
    },

    getMessages: async (): Promise<ChatMessage[]> => {
        if (isSupabaseConfigured()) {
            try {
                const { data, error } = await supabase!.from('chat_messages').select('*').order('timestamp', { ascending: true }).limit(500); 
                if (error) {
                    console.warn("Supabase Error (getMessages):", getErrorMessage(error));
                    return StorageService.getMessages();
                }
                if (data) {
                    return data.map((d: any) => ({
                        id: d.id,
                        content: d.content,
                        senderId: d.sender_id,
                        senderName: d.sender_name,
                        channelId: d.channel_id,
                        timestamp: d.timestamp
                    }));
                }
            } catch (err) {
                console.warn("Supabase Exception (getMessages):", err);
                return StorageService.getMessages();
            }
        }
        return StorageService.getMessages();
    },

    sendMessage: async (msg: ChatMessage) => {
        const current = StorageService.getMessages();
        StorageService.saveMessages([...current, msg]);
        if (isSupabaseConfigured()) {
            try {
                const { error } = await supabase!.from('chat_messages').insert([{
                    id: msg.id,
                    content: msg.content,
                    sender_id: msg.senderId,
                    sender_name: msg.senderName,
                    channel_id: msg.channelId,
                    timestamp: msg.timestamp
                }]);
                if (error) console.warn("DB Message Error:", getErrorMessage(error));
            } catch (err) {
                console.warn("DB Message Exception:", getErrorMessage(err));
            }
        }
    },

    getChatGroups: async (): Promise<ChatGroup[]> => {
        if (isSupabaseConfigured()) {
            try {
                const { data, error } = await supabase!.from('chat_groups').select('*');
                if (error) {
                    console.warn("Supabase Error (getChatGroups):", getErrorMessage(error));
                    return StorageService.getChatGroups();
                }
                if (data) {
                    return data.map((d: any) => ({
                        id: d.id,
                        name: d.name,
                        memberIds: d.member_ids,
                        createdBy: d.created_by,
                        createdAt: d.created_at
                    }));
                }
            } catch (err) {
                console.warn("Supabase Exception (getChatGroups):", err);
                return StorageService.getChatGroups();
            }
        }
        return StorageService.getChatGroups();
    },

    createChatGroup: async (group: ChatGroup) => {
        StorageService.createChatGroup(group);
        if (isSupabaseConfigured()) {
            try {
                const { error } = await supabase!.from('chat_groups').insert([{
                    id: group.id,
                    name: group.name,
                    member_ids: group.memberIds,
                    created_by: group.createdBy,
                    created_at: group.createdAt
                }]);
                if (error) console.warn("DB Group Error:", getErrorMessage(error));
            } catch (err) {
                console.warn("DB Group Exception:", getErrorMessage(err));
            }
        }
    },

    subscribeToUpdates: (onTaskChange: () => void, onMessageInsert: (newMsg: ChatMessage) => void, onGroupChange: () => void) => {
        if (!isSupabaseConfigured()) return null;
        try {
            const channel = supabase!.channel('db-realtime')
                .on('postgres_changes', { event: '*', schema: 'public', table: 'tasks' }, () => onTaskChange())
                .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'chat_messages' }, (payload) => {
                    const d = payload.new;
                    onMessageInsert({
                        id: d.id,
                        content: d.content,
                        senderId: d.sender_id,
                        senderName: d.sender_name,
                        channelId: d.channel_id,
                        timestamp: d.timestamp
                    });
                })
                .on('postgres_changes', { event: '*', schema: 'public', table: 'chat_groups' }, () => onGroupChange())
                .subscribe();
            return channel;
        } catch (err) {
            console.warn("Realtime Subscription Exception:", err);
            return null;
        }
    },

    syncLocalToCloud: async (tasks: Task[], messages: ChatMessage[], groups: ChatGroup[]) => {
        if (!isSupabaseConfigured()) return { success: false, message: 'Supabase client not initialized' };
        try {
            if (tasks.length > 0) {
                await supabase!.from('tasks').upsert(tasks.map(t => ({
                    id: t.id,
                    title: t.title,
                    description: t.description,
                    is_completed: t.isCompleted,
                    priority: t.priority,
                    creator_id: t.creatorId,
                    assignee_id: t.assigneeId,
                    origin_division_id: t.originDivisionId,
                    target_division_id: t.targetDivisionId,
                    due_date: t.dueDate,
                    reminder_at: t.reminderAt,
                    is_reminded: t.isReminded,
                    attachment_url: t.attachmentUrl,
                    subtasks: t.subtasks,
