import { GoogleGenAI, Type } from "@google/genai";
import { Tool, User, ToolCategory, TaskPriority, DivisionType, Task } from "../types";

// Fallback suggestions if AI fails or no key
const FALLBACK_SUGGESTIONS = [
    "Cek email harian",
    "Update laporan mingguan",
    "Koordinasi tim pagi"
];

export const GeminiService = {

    // 1. SMART SUGGESTIONS
    async getSmartSuggestions(user: User, recentTools: Tool[]): Promise<string[]> {
        if (!process.env.API_KEY) return FALLBACK_SUGGESTIONS;
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
            const toolNames = recentTools.map(t => t.name).join(", ");
            const prompt = `
                Peran User: ${user.role}
                Divisi User: ${user.division}
                Tools Terakhir: ${toolNames}

                Berikan 3 saran tugas singkat (maks 5 kata) yang relevan untuk produktivitas kerja dalam bahasa Indonesia.
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.ARRAY,
                        items: { type: Type.STRING }
                    }
                }
            });

            return JSON.parse(response.text || '[]') || FALLBACK_SUGGESTIONS;
        } catch (error) {
            console.error("Gemini Suggestions Error:", error);
            return FALLBACK_SUGGESTIONS;
        }
    },

    // 2. SMART ADD TOOL
    async generateToolConfig(description: string, divisionName: string): Promise<Partial<Tool>> {
        if (!process.env.API_KEY) return { name: "New Tool", icon: "Link", color: "bg-blue-500", category: ToolCategory.PROJECT };
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
             const prompt = `Analisis permintaan pembuatan alat kerja untuk divisi "${divisionName}": "${description}".`;

             const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
                config: {
                    systemInstruction: `Tentukan: 
                    1. "name" (Nama pendek, Title Case, maks 25 karakter).
                    2. "category" (Daily Tools, Shared Tools, atau Project & Drafts).
                    3. "icon" (Nama ikon Lucide React yang cocok).
                    4. "color" (Tailwind bg class).`,
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            name: { type: Type.STRING },
                            category: { type: Type.STRING },
                            icon: { type: Type.STRING },
                            color: { type: Type.STRING }
                        },
                        required: ["name", "category", "icon", "color"]
                    }
                }
            });

            const data = JSON.parse(response.text || '{}');
            return {
                name: data.name,
                category: data.category as ToolCategory,
                icon: data.icon,
                color: data.color
            };
        } catch (e) {
            return { name: "New Tool", icon: "Link", color: "bg-blue-500", category: ToolCategory.PROJECT };
        }
    },

    // 3. BULK IMPORT PARSER
    async parseBulkTasks(text: string): Promise<any[]> {
        if (!process.env.API_KEY) return [];
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: `Ekstrak daftar tugas dari teks ini: "${text}"`,
                config: {
                    systemInstruction: "Ekstrak menjadi JSON Array dengan properti: title, divisionId, priority (high/medium/low), dueDate (YYYY-MM-DD atau null). Gunakan 'BROADCAST' jika untuk semua tim.",
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                title: { type: Type.STRING },
                                divisionId: { type: Type.STRING },
                                priority: { type: Type.STRING },
                                dueDate: { type: Type.STRING, nullable: true }
                            },
                            required: ["title", "divisionId", "priority"]
                        }
                    }
                }
            });

            return JSON.parse(response.text || '[]');
        } catch (error) {
            return [];
        }
    },

    // 4. ASK YOUR DATA
    async askData(question: string, contextData: { tasks: Task[], users: User[], announcements: any[] }): Promise<string> {
        if (!process.env.API_KEY) return "AI Key not configured.";
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
            const tasksContext = contextData.tasks.slice(0, 20).map(t => 
                `- [${t.isCompleted ? 'SELESAI' : 'PENDING'}] ${t.title} (Div: ${t.targetDivisionId})`
            ).join('\n');

            const usersContext = contextData.users.map(u => `- ${u.name} (${u.division})`).join('\n');

            const prompt = `Jawab pertanyaan: "${question}" berdasarkan data ini:\n\nKARYAWAN:\n${usersContext}\n\nTUGAS:\n${tasksContext}`;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
                config: {
                    systemInstruction: "Anda adalah asisten kantor STIS-DU. Jawab dengan sangat singkat, padat, dan profesional."
                }
            });

            return response.text || "Maaf, saya tidak menemukan datanya.";
        } catch (e) {
            return "Terjadi kesalahan sistem AI.";
        }
    },

    // 5. DOCUMENT INTELLIGENCE (NEW TAHAP 4)
    async analyzeDocument(base64Image: string, mimeType: string): Promise<any> {
        if (!process.env.API_KEY) throw new Error("API Key missing");
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: [
                    {
                        inlineData: {
                            mimeType: mimeType,
                            data: base64Image
                        }
                    },
                    {
                        text: "Analisis gambar dokumen ini. Ekstrak informasi penting."
                    }
                ],
                config: {
                    systemInstruction: "Ekstrak informasi dokumen ke JSON. Field wajib: type (invoice/id/document), summary (bahasa indonesia), title (judul pendek), amount (angka saja jika invoice), date (YYYY-MM-DD).",
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            type: { type: Type.STRING },
                            summary: { type: Type.STRING },
                            title: { type: Type.STRING },
                            amount: { type: Type.NUMBER },
                            date: { type: Type.STRING }
                        },
                        required: ["type", "summary", "title"]
                    }
                }
            });

            return JSON.parse(response.text || '{}');
        } catch (e) {
            console.error("OCR Error:", e);
            throw e;
        }
    },

    async generateSubtasks(taskTitle: string, taskDesc?: string): Promise<{title: string}[]> {
        if (!process.env.API_KEY) return [];
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        try {
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: `Pecah tugas "${taskTitle}" ${taskDesc ? `dengan konteks: ${taskDesc}` : ''} menjadi langkah-langkah konkret.`,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: { title: { type: Type.STRING } },
                            required: ["title"]
                        }
                    }
                }
            });
            return JSON.parse(response.text || '[]');
        } catch (e) { return []; }
    }
};

