export const Toast: React.FC<{ message: string; onClose: () => void }> = ({ message, onClose }) => {
    useEffect(() => { 
        const timer = setTimeout(onClose, 3000); 
        return () => clearTimeout(timer); 
    }, [onClose]);

    return (
        <div className="fixed bottom-24 left-1/2 -translate-x-1/2 z-[100] bg-brand-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 animate-[slideUp_0.3s_ease-out] border border-white/20">
            <Icon name="CheckCircle" size={18} />
            <span className="font-bold text-xs uppercase tracking-wider">{message}</span>
        </div>
    );
};

