interface ProfileModalProps {
  isOpen: boolean;
  onClose: () => void;
  user: User;
  onUpdateUser: (u: User) => void;
  announcements: Announcement[];
  onLogout: () => void;
}

export const ProfileModal: React.FC<ProfileModalProps> = ({ isOpen, onClose, user, onUpdateUser, announcements, onLogout }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'settings' | 'security' | 'activity' | 'notifications'>('overview');
  const [activityLogs, setActivityLogs] = useState<ActivityLog[]>([]);
  const [preferences, setPreferences] = useState<UserPreferences>(StorageService.getPreferences());
  const [editNote, setEditNote] = useState(user.stickyNote);
  const [isEditingNote, setIsEditingNote] = useState(false);

  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  const t = translations[preferences.language as LanguageCode] || translations.en;

  useEffect(() => {
    if (isOpen) {
      setActivityLogs(StorageService.getActivityLogs());
      setPreferences(StorageService.getPreferences());
    }
  }, [isOpen]);

  useEffect(() => {
    const root = window.document.documentElement;
    if (preferences.theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    StorageService.savePreferences(preferences);
  }, [preferences.theme]);

  const handleSaveNote = () => {
      onUpdateUser({ ...user, stickyNote: editNote });
      setIsEditingNote(false);
  };

  const handleTogglePref = (key: keyof UserPreferences) => {
      setPreferences(prev => {
          const updated = { ...prev, [key]: !prev[key] };
          if (key === 'theme') updated.theme = prev.theme === 'dark' ? 'light' : 'dark';
          StorageService.savePreferences(updated);
          return updated;
      });
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
      <div className="bg-[#0f172a] border border-white/10 w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden flex flex-col md:flex-row max-h-[90vh] animate-[scaleIn_0.3s]">

        {/* Sidebar Navigation */}
        <div className="w-full md:w-56 bg-white/5 p-6 flex flex-col gap-1 shrink-0 border-b md:border-b-0 md:border-r border-white/5">
            <div className="flex md:flex-col items-center gap-4 md:gap-0 mb-6">
                 <div className="w-16 h-16 md:w-20 md:h-20 rounded-3xl bg-gradient-to-tr from-brand-600 to-indigo-600 flex items-center justify-center text-white text-3xl font-black shadow-lg mb-0 md:mb-4">
                    {user.name.charAt(0)}
                 </div>
                 <div className="text-left md:text-center">
                    <h2 className="text-lg font-bold text-white truncate">{user.name}</h2>
                    <p className="text-xs text-gray-500 uppercase tracking-widest">{user.division}</p>
                 </div>
            </div>

            <nav className="flex md:flex-col gap-2 overflow-x-auto md:overflow-visible pb-2 md:pb-0 scrollbar-hide">
                <button onClick={() => setActiveTab('overview')} className={`px-4 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest whitespace-nowrap transition-all ${activeTab === 'overview' ? 'bg-brand-600 text-white' : 'text-gray-500 hover:text-white'}`}>Profil</button>
                <button onClick={() => setActiveTab('activity')} className={`px-4 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest whitespace-nowrap transition-all ${activeTab === 'activity' ? 'bg-brand-600 text-white' : 'text-gray-500 hover:text-white'}`}>Log</button>
                <button onClick={() => setActiveTab('settings')} className={`px-4 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest whitespace-nowrap transition-all ${activeTab === 'settings' ? 'bg-brand-600 text-white' : 'text-gray-500 hover:text-white'}`}>Opsi</button>
            </nav>

            <button onClick={onLogout} className="mt-auto hidden md:flex items-center gap-3 px-4 py-3 rounded-2xl text-xs font-black uppercase tracking-widest text-red-400 hover:bg-red-500/10 transition-colors">
