                            <button onClick={() => handleTogglePref('soundEnabled')} className={`w-12 h-6 rounded-full p-1 transition-all ${preferences.soundEnabled ? 'bg-brand-500' : 'bg-gray-600'}`}><div className={`w-4 h-4 bg-white rounded-full transition-transform ${preferences.soundEnabled ? 'translate-x-6' : ''}`} /></button>
