import React from 'react';
import { Task } from '../types';
import { Icon } from './Icon';

interface TaskItemProps { 
    task: Task & { divName?: string; divIcon?: string }; 
    onToggle: () => void; 
    onSelect: () => void; 
    onDelete: () => void; 
    onDiscuss: () => void;
    onWhatsApp: () => void;
    onReminder: () => void;
    showDivisionBadge?: boolean;
    divisionName?: string;
    divisionIcon?: string;
}

export const TaskItem: React.FC<TaskItemProps> = ({ 
    task, onToggle, onSelect, onDelete, onDiscuss, onWhatsApp, onReminder, 
    showDivisionBadge, divisionName, divisionIcon 
}) => {
    const isOverdue = !task.isCompleted && task.dueDate && new Date(task.dueDate) < new Date(new Date().setHours(0,0,0,0));
    const totalSub = task.subtasks?.length || 0;
    const completedSub = task.subtasks?.filter(s => s.isCompleted).length || 0;

    return (
        <div 
            onClick={onSelect}
            className={`group relative flex flex-col p-4 rounded-[1.8rem] transition-all border border-white/5 shadow-sm active:bg-[#1e293b] duration-300 cursor-pointer overflow-hidden active:scale-[0.97]
                ${task.isCompleted ? 'bg-white/5 opacity-50 grayscale' : 'bg-[#1e293b]/80 hover:bg-[#232d3f] hover:border-white/10 hover:shadow-xl'} 
                ${isOverdue ? 'border-l-4 border-l-red-500' : ''}
            `}
        >
            <div className="flex items-start gap-4 relative z-10">
                <button 
                    onClick={(e) => { e.stopPropagation(); onToggle(); }} 
                    className={`mt-1 w-6 h-6 rounded-xl border flex items-center justify-center transition-all shrink-0 shadow-inner
                        ${task.isCompleted ? 'bg-emerald-500 border-emerald-500' : 'bg-black/40 border-gray-600 hover:border-brand-500'}
                    `}
                >
                    {task.isCompleted && <Icon name="Check" size={14} className="text-white stroke-[3]" />}
                </button>

                <div className="flex-1 min-w-0 pr-4">
                    <p className={`text-sm font-bold leading-tight mb-2.5 ${task.isCompleted ? 'text-gray-500 line-through' : 'text-gray-100'}`}>
                        {task.title}
                    </p>

                    <div className="flex flex-wrap gap-2 items-center">
                        {totalSub > 0 && (
                            <span className={`inline-flex items-center gap-1 text-[9px] font-black px-2 py-0.5 rounded-lg border uppercase tracking-widest ${completedSub === totalSub ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' : 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20'}`}>
                                <Icon name="ListChecks" size={10} /> {completedSub}/{totalSub}
                            </span>
                        )}
                        {task.priority === 'high' && !task.isCompleted && (
                            <span className="text-[9px] font-black px-2 py-0.5 rounded-lg bg-red-500/10 text-red-400 border border-red-500/20 uppercase tracking-[0.15em]">Urgent</span>
                        )}
                        {(showDivisionBadge || divisionName) && (
                            <span className="text-[9px] font-bold text-gray-500 bg-white/5 px-2 py-0.5 rounded-lg border border-white/5 uppercase tracking-wider">{divisionName || task.divName}</span>
                        )}
                    </div>
                </div>

                <div className="mt-1 flex flex-col items-end gap-1">
                    <Icon name="ChevronRight" size={16} className="text-gray-700 group-hover:text-brand-500 transition-colors" />
                    {task.dueDate && <span className={`text-[8px] font-bold uppercase tracking-tighter ${isOverdue ? 'text-red-400' : 'text-gray-600'}`}>{task.dueDate}</span>}
                </div>
            </div>

            {/* Soft highlight for pending high priority */}
            {!task.isCompleted && task.priority === 'high' && (
                <div className="absolute top-0 right-0 w-24 h-24 bg-red-500/5 blur-2xl -mr-12 -mt-12 pointer-events-none"></div>
            )}
        </div>
    );
};

