const MainMenuButton: React.FC<{ label: string; icon: string; color: string; onClick: () => void }> = ({ label, icon, color, onClick }) => (
    <button onClick={onClick} className="flex flex-col items-center gap-3 active:scale-95 transition-transform group w-full">
