            <div className={`absolute inset-0 bg-gradient-to-br ${color} opacity-20 group-hover:opacity-40 transition-opacity`}></div>
            <Icon name={icon} size={28} className="relative z-10 drop-shadow-lg group-hover:scale-110 transition-transform" />
        </div>
        <span className="text-[10px] font-black text-gray-500 uppercase tracking-[0.2em] group-hover:text-white transition-colors text-center">{label}</span>
    </button>
);

const DivisionAccordion: React.FC<any> = ({ division, tools, isOpen, onToggle, onToolClick, onContextMenu, tasks }) => {
    const pendingTasks = tasks.filter((t: any) => !t.isCompleted).length;
    return (
        <div className="mb-3 rounded-[2rem] overflow-hidden glass-card border border-white/5 mx-1 shadow-lg bg-[#1e293b]/30 group transition-all">
            <button 
                onClick={onToggle}
                className={`w-full flex items-center justify-between p-5 transition-all ${isOpen ? 'bg-white/5' : 'hover:bg-white/5'}`}
            >
                <div className="flex items-center gap-4">
                    <div className="w-10 h-10 rounded-2xl bg-gradient-to-br from-gray-800 to-gray-900 flex items-center justify-center text-gray-300 border border-white/10 shadow-inner group-hover:text-brand-400">
                        <Icon name={division.icon} size={18} />
                    </div>
                    <div className="text-left">
                        <span className="font-bold text-gray-100 text-sm block tracking-wide">{division.name}</span>
                        <div className="flex gap-2 mt-0.5">
                            <span className="text-[9px] text-gray-500 uppercase font-black tracking-widest">{tools.length} TOOLS</span>
                            {pendingTasks > 0 && <span className="text-[9px] text-rose-400 uppercase font-black tracking-widest">• {pendingTasks} PENDING</span>}
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-3">
                    <Icon name="ChevronDown" size={16} className={`text-gray-500 transition-transform duration-500 ${isOpen ? 'rotate-180 text-brand-400' : ''}`} />
                </div>
            </button>
            <div className={`overflow-hidden transition-all duration-500 bg-black/20 ${isOpen ? 'max-h-[800px] border-t border-white/5' : 'max-h-0'}`}>
                <div className="p-5 grid grid-cols-3 sm:grid-cols-4 gap-4">
                    {tools.map((t: any) => (
                        <ToolCard key={t.id} tool={t} variant="tiny" onClick={() => onToolClick(t)} onContextMenu={onContextMenu} />
                    ))}
                    {tools.length === 0 && <div className="col-span-full text-center py-8 text-xs text-gray-600 italic">Folder masih kosong</div>}
                </div>
            </div>
        </div>
    );
};

export const Dashboard: React.FC<DashboardProps> = (props) => {
    const navigate = useNavigate(); 
    const [searchTerm, setSearchTerm] = useState('');
    const [activeFolder, setActiveFolder] = useState<string | null>(props.user.division);

    const allowedTools = useMemo(() => {
        let items = props.tools;
        if (props.user.role !== UserRole.ADMIN) {
            items = props.tools.filter(t => t.divisionId === props.user.division || !t.divisionId);
        }
        if (searchTerm) {
            items = items.filter(t => t.name.toLowerCase().includes(searchTerm.toLowerCase()));
        }
        return items;
    }, [props.tools, searchTerm, props.user]);

    const displayedDivisions = useMemo(() => {
        if (props.user.role === UserRole.ADMIN) return props.dashboardDivisions;
        return props.dashboardDivisions.filter(d => d.id === props.user.division);
    }, [props.user, props.dashboardDivisions]);

    const tickerTasks = props.tasks.filter(t => t.priority === 'high' && !t.isCompleted);

    return (
        <div className="h-full flex flex-col overflow-y-auto bg-[#0b0f1a] bg-[radial-gradient(circle_at_top,_var(--tw-gradient-stops))] from-[#1e293b]/50 via-[#0b0f1a] to-[#0b0f1a] pb-40">

            <TaskTicker tasks={tickerTasks} onTaskClick={() => navigate(`/division/${props.user.division}`)} />

            {/* Header Area */}
