                    <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-emerald-500 rounded-full border-2 border-[#0b0f1a]"></div>
                </button>
            </div>

            {/* Pivot Main Menu Grid */}
            <div className="grid grid-cols-4 gap-4 px-6 mb-12">
