                <MainMenuButton label="Tugas" icon="CheckSquare" color="from-amber-500 to-orange-600" onClick={() => navigate(`/division/${props.user.division}`)} />
                <MainMenuButton label="Laporan" icon="BarChart2" color="from-rose-500 to-pink-600" onClick={() => navigate('/finance')} />
            </div>

            {/* Status Workspace Bar */}
            <div className="px-6 mb-8">
                <div className="bg-[#1e293b]/40 backdrop-blur-xl border border-white/10 rounded-[2.2rem] px-6 py-4 flex items-center justify-between shadow-2xl">
                    <div className="flex items-center gap-3">
                        <div className="w-2.5 h-2.5 rounded-full bg-brand-500 animate-pulse shadow-[0_0_10px_rgba(14,165,233,0.8)]"></div>
                        <span className="text-[10px] font-black uppercase tracking-[0.2em] text-gray-300">{props.user.division}</span>
                    </div>
                    <div className="flex items-center gap-4">
                        <div className="flex items-center gap-2 text-emerald-400 text-[10px] font-black uppercase tracking-widest">
                            <Icon name="Wifi" size={12}/> ONLINE
                        </div>
                    </div>
                </div>
            </div>

