import React, { useState } from 'react';
import { Icon } from './Icon';
import { GeminiService } from '../services/geminiService';
import { Task, User, Announcement } from '../types';

interface AIAssistantProps {
    tasks: Task[];
    users: User[];
    announcements: Announcement[];
}

export const AIAssistant: React.FC<AIAssistantProps> = ({ tasks, users, announcements }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [query, setQuery] = useState('');
    const [response, setResponse] = useState('');
    const [isLoading, setIsLoading] = useState(false);

    const handleAsk = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!query.trim()) return;
        setIsLoading(true);
        const answer = await GeminiService.askData(query, { tasks, users, announcements });
        setResponse(answer);
        setIsLoading(false);
    };

    return (
        <div className="fixed bottom-28 md:bottom-6 right-6 z-[100] flex flex-col items-end pointer-events-none">
            {isOpen && (
                <div className="pointer-events-auto bg-[#0f172a] border border-white/10 shadow-2xl rounded-[2.5rem] w-[85vw] md:w-80 mb-4 overflow-hidden animate-[scaleIn_0.2s_ease-out] flex flex-col max-h-[60vh] ring-1 ring-white/5">
                    <div className="p-5 bg-gradient-to-r from-purple-600 to-indigo-600 text-white flex justify-between items-center">
                        <div className="flex items-center gap-2 font-black text-sm uppercase tracking-widest"><Icon name="Sparkles" size={16} /> AI Assistant</div>
                        <button onClick={() => setIsOpen(false)} className="p-1 hover:bg-white/20 rounded-lg"><Icon name="X" size={18} /></button>
                    </div>
                    <div className="flex-1 p-5 bg-black/20 overflow-y-auto custom-scrollbar text-sm text-gray-200 leading-relaxed">
                        {!response && !isLoading && <div className="text-center py-8"><Icon name="Bot" size={40} className="mx-auto mb-3 opacity-20" /><p className="text-gray-500 italic">Halo! Ada yang bisa saya bantu terkait data kantor hari ini?</p></div>}
                        {isLoading && <div className="flex flex-col items-center justify-center p-8 gap-3"><Icon name="Loader2" className="animate-spin text-purple-400" size={32} /><p className="text-xs text-gray-500 font-bold uppercase animate-pulse">Sedang Berpikir...</p></div>}
                        {response && <div className="whitespace-pre-wrap animate-[fadeIn_0.3s]">{response}</div>}
                    </div>
                    <form onSubmit={handleAsk} className="p-4 border-t border-white/10 bg-black/40 flex gap-2">
                        <input className="flex-1 bg-white/5 border border-white/10 rounded-2xl px-4 py-3 text-xs text-white outline-none focus:border-purple-500 transition-all" placeholder="Tanya sesuatu..." value={query} onChange={e => setQuery(e.target.value)} />
                        <button type="submit" disabled={!query || isLoading} className="bg-purple-600 hover:bg-purple-500 text-white p-3 rounded-2xl disabled:opacity-50 transition-colors shadow-lg shadow-purple-900/20"><Icon name="Send" size={18} /></button>
                    </form>
                </div>
            )}
            <button 
                onClick={() => setIsOpen(!isOpen)} 
                className={`pointer-events-auto w-14 h-14 rounded-2xl shadow-2xl flex items-center justify-center text-white hover:scale-110 transition-all ring-4 ring-[#0b0f1a] relative ${isOpen ? 'bg-indigo-600 rotate-90' : 'bg-gradient-to-tr from-purple-600 to-indigo-600 animate-bounce md:animate-none'}`}
            >
                <Icon name={isOpen ? "X" : "Sparkles"} size={24} />
                {!isOpen && <div className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-white"></div>}
            </button>
        </div>
    );
};

import { GoogleGenAI, Type } from "@google/genai";
import { Tool, User, ToolCategory, TaskPriority, DivisionType, Task } from "../types";

// Fallback suggestions if AI fails or no key
const FALLBACK_SUGGESTIONS = [
    "Cek email harian",
    "Update laporan mingguan",
    "Koordinasi tim pagi"
];

export const GeminiService = {

    // 1. SMART SUGGESTIONS
    async getSmartSuggestions(user: User, recentTools: Tool[]): Promise<string[]> {
        if (!process.env.API_KEY) return FALLBACK_SUGGESTIONS;
        // Fix: Use named parameter for apiKey and use gemini-3-flash-preview for text tasks
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
            const toolNames = recentTools.map(t => t.name).join(", ");
            const prompt = `
                Peran User: ${user.role}
                Divisi User: ${user.division}
                Tools Terakhir: ${toolNames}

                Berikan 3 saran tugas singkat (maks 5 kata) yang relevan untuk produktivitas kerja dalam bahasa Indonesia.
                Return ONLY a JSON array of strings.
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.ARRAY,
                        items: { type: Type.STRING }
                    }
                }
            });

            // Fix: Use .text property directly
            const text = response.text;
            if (text) return JSON.parse(text);
            return FALLBACK_SUGGESTIONS;

        } catch (error) {
            console.error("Gemini Suggestions Error:", error);
            return FALLBACK_SUGGESTIONS;
        }
    },

    // 2. CHECK LINK HEALTH
    async checkLinkHealth(url: string): Promise<{ status: 'ok' | 'broken' | 'unknown', reason?: string }> {
         return { status: 'ok' };
    },

    // 3. SMART ADD TOOL
    async generateToolConfig(description: string, divisionName: string): Promise<Partial<Tool>> {
        if (!process.env.API_KEY) {
            return {
                name: description.substring(0, 15) + '...',
                icon: 'Link',
                color: 'bg-blue-500',
                category: ToolCategory.PROJECT
            };
        }
        // Fix: Use named parameter for apiKey and use gemini-3-flash-preview for text tasks
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
             const prompt = `
                Analisis permintaan pembuatan alat kerja untuk divisi "${divisionName}": "${description}".

                Tentukan:
                1. "name" (Nama pendek, Title Case, maks 25 karakter).
                2. "category" (Pilih salah satu: "${ToolCategory.DAILY}", "${ToolCategory.SHARED}", "${ToolCategory.PROJECT}").
                3. "icon" (Nama ikon Lucide React yang cocok, misal: FileText, BarChart, Users, Globe).
                4. "color" (Tailwind CSS bg color class, misal: bg-blue-500, bg-red-600, bg-green-500, bg-purple-500, bg-orange-500).

                Return ONLY a JSON object.
             `;

             const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            name: { type: Type.STRING },
                            category: { type: Type.STRING },
                            icon: { type: Type.STRING },
                            color: { type: Type.STRING }
                        },
                        required: ["name", "category", "icon", "color"]
                    }
                }
            });

            // Fix: Use .text property directly
            const text = response.text;
            if (text) {
                const data = JSON.parse(text);
                return {
                    name: data.name,
                    category: data.category as ToolCategory,
                    icon: data.icon,
                    color: data.color
                };
            }
            throw new Error("Empty response");

        } catch (e) {
            console.error(e);
            return { name: "New Tool", icon: "Link", color: "bg-blue-500", category: ToolCategory.PROJECT };
        }
    },

    // 4. TASK ASSISTANT
    async generateTaskDescription(prompt: string): Promise<string> {
        if (!process.env.API_KEY) return prompt;
        // Fix: Use named parameter for apiKey and use gemini-3-flash-preview for text tasks
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
            const aiPrompt = `Ubah input ini menjadi judul tugas profesional (Bahasa Indonesia): "${prompt}"`;
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: aiPrompt,
            });
            // Fix: Use .text property directly
            return response.text?.trim() || prompt;
        } catch (error) {
            return prompt;
        }
    },

    // 5. BULK IMPORT PARSER (CORE LOGIC)
    async parseBulkTasks(text: string): Promise<any[]> {
        if (!process.env.API_KEY) {
            console.warn("API Key missing");
            return [];
        }
        // Fix: Use named parameter for apiKey and use gemini-3-flash-preview for text tasks
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
            const systemPrompt = `
            PERAN: Asisten Project Manager Cerdas.
            TUGAS: Ekstrak daftar tugas dari teks input (chat/notulen) menjadi JSON Array.

            ATURAN PENENTUAN DIVISI (divisionId):
            Analisis konteks kalimat untuk memetakan ke salah satu ID ini:
            - 'Direksi' (Manajemen, keputusan, laporan pimpinan)
            - 'Marketing' (Sosmed, iklan, konten, desain, leads)
            - 'Administrasi' (Surat, arsip, data siswa, input)
            - 'Keuangan' (Gaji, invoice, bayar, pajak, anggaran)
            - 'IT Support' (Wifi, server, error, web, aplikasi, laptop)
            - 'Kebersihan & Keamanan' (Satpam, cleaning, parkir, AC, perbaikan fisik)
            - 'Mitra Kampus' (Kerjasama, MoU, event luar)

            *** ATURAN KHUSUS BROADCAST ***
            Jika perintah ditujukan untuk "Semua", "All Team", "Seluruh Divisi", "Pengumuman", "Setiap Tim", atau tidak spesifik divisi:
            MAKA set "divisionId" menjadi: 'BROADCAST'.

            ATURAN PRIORITAS (priority):
            - 'high': Kata kunci 'segera', 'urgent', 'penting', 'rusak', 'deadline', 'hari ini'.
            - 'low': Kata kunci 'santai', 'ide', 'nanti', 'low'.
            - 'medium': Jika tidak ada indikasi waktu mendesak.

            ATURAN JUDUL (title):
            Buat judul singkat, padat, jelas, menggunakan kata kerja aktif (misal: "Perbaiki Wifi", "Rekap Laporan").

            OUTPUT JSON ONLY:
            [{ "title": string, "divisionId": string, "priority": "high"|"medium"|"low", "dueDate": "YYYY-MM-DD" | null }]
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: `Instruction: ${systemPrompt}\n\nInput Text:\n"${text}"`,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                title: { type: Type.STRING },
                                divisionId: { type: Type.STRING },
                                priority: { type: Type.STRING },
                                dueDate: { type: Type.STRING, nullable: true }
                            },
                            required: ["title", "divisionId", "priority"]
                        }
                    }
                }
            });

            // Fix: Use .text property directly
            const responseText = response.text;
            return JSON.parse(responseText || '[]');

        } catch (error) {
            console.error("Gemini Bulk Parse Error:", error);
            return [];
        }
    },

    // 6. GENERATE SUBTASKS (TASK BREAKDOWN)
    async generateSubtasks(taskTitle: string, taskDesc?: string): Promise<{title: string}[]> {
        if (!process.env.API_KEY) return [];
        // Fix: Use named parameter for apiKey and use gemini-3-flash-preview for text tasks
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
            const prompt = `
                Tugas: "${taskTitle}"
                Konteks Tambahan: "${taskDesc || ''}"

                Pecah tugas ini menjadi 3-6 langkah (sub-tugas) yang konkret, dapat ditindaklanjuti, dan berurutan.
                Bahasa: Indonesia Formal & Profesional.

                Output JSON: [{ "title": string }]
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                title: { type: Type.STRING }
                            },
                            required: ["title"]
                        }
                    }
                }
            });

            // Fix: Use .text property directly
            const text = response.text;
            return JSON.parse(text || '[]');
        } catch (e) {
            console.error("Gemini Subtasks Error:", e);
            return [];
        }
    },

    // 7. ASK YOUR DATA (RAG-LITE)
    // Fix: Added missing askData method used in AIAssistant.tsx
    async askData(question: string, contextData: { tasks: Task[], users: User[], announcements: any[] }): Promise<string> {
        if (!process.env.API_KEY) return "AI Key not configured.";
        // Fix: Use named parameter for apiKey and use gemini-3-flash-preview for text tasks
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        try {
            // Simplify context to save tokens
            const tasksContext = contextData.tasks.map(t => 
                `- [${t.isCompleted ? 'SELESAI' : 'PENDING'}] ${t.title} (Div: ${t.targetDivisionId}, Assignee: ${t.assigneeId}, Priority: ${t.priority})`
            ).join('\n');

            const usersContext = contextData.users.map(u => 
                `- ${u.name} (${u.role} - ${u.division})`
            ).join('\n');

            const announcementsContext = contextData.announcements.map(a =>
                `- ${a.title}: ${a.content}`
            ).join('\n');

            const prompt = `
                Anda adalah Asisten Kantor Pintar "STIS-DU".
                Jawab pertanyaan user berdasarkan data berikut:

                DATA KARYAWAN:
                ${usersContext}

                DAFTAR TUGAS SAAT INI:
                ${tasksContext}

                PENGUMUMAN TERBARU:
                ${announcementsContext}

                Pertanyaan User: "${question}"

                Jawab dengan ramah, singkat, dan informatif. Jika data ada, gunakan untuk menjawab. Jika tidak ada, sampaikan bahwa informasi tersebut tidak tersedia di sistem.
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
            });

            // Fix: Use .text property directly
            return response.text || "Maaf, saya tidak bisa menjawab saat ini.";
        } catch (error) {
            console.error("Gemini AskData Error:", error);
            return "Terjadi kesalahan koneksi AI.";
        }
    }
};

