import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, useParams } from 'react-router-dom';
import { Tool, User, Announcement, ChatMessage, AttendanceConfig, Holiday, UserPreferences, AttendanceRecord, Task, DivisionType, DivisionData, TaskPriority, ChatGroup } from './types';
import { StorageService } from './services/storageService';
import { UnifiedDataService } from './services/UnifiedDataService'; 
import { isSupabaseConfigured } from './services/supabaseClient';
import { AddToolModal } from './components/AddToolModal';
import { SmartAddModal } from './components/SmartAddModal';
import { ContextMenu } from './components/ContextMenu';
import { ToolActionModal } from './components/ToolActionModal';
import { ProfileModal } from './components/ProfileModal';
import { SettingsView } from './components/SettingsView';
import { AttendanceModal } from './components/AttendanceModal';
import { LoginView } from './components/LoginView';
import { Dashboard } from './components/Dashboard';
import { DivisionView } from './components/DivisionView';
import { Messages } from './components/Messages';
import { DocumentsView } from './components/DocumentsView';
import { InventoryView } from './components/InventoryView';
import { FinanceView } from './components/FinanceView';
import { AppLayout, Toast } from './components/Layout';
import { QuickCommand } from './components/QuickCommand';
import { AIAssistant } from './components/AIAssistant';
import { LanguageCode } from './translations';
import { DIVISIONS } from './constants';
import { NotificationService } from './services/notificationService';
import { TaskDetailView } from './components/TaskDetailView';

const ChannelUpdater: React.FC<{ onUpdate: (id: string) => void }> = ({ onUpdate }) => {
    const { id } = useParams<{ id: string }>();
    useEffect(() => {
        if (id) onUpdate(id);
        else onUpdate('GENERAL');
    }, [id, onUpdate]);
    return null;
};

const App: React.FC = () => {
    const [user, setUser] = useState<User | null>(StorageService.getUser());
    const [tools, setTools] = useState<Tool[]>(StorageService.getTools());
    const [users, setUsers] = useState<User[]>(StorageService.getUsers());
    const [allTasks, setAllTasks] = useState<Task[]>([]);
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [chatGroups, setChatGroups] = useState<ChatGroup[]>([]);
    const [notification, setNotification] = useState<string | null>(null);
    const [announcements, setAnnouncements] = useState<Announcement[]>(StorageService.getAnnouncements());
    const [attendanceConfig, setAttendanceConfig] = useState<AttendanceConfig>(StorageService.getAttendanceConfig());
    const [holidays, setHolidays] = useState<Holiday[]>(StorageService.getHolidays());
    const [preferences] = useState<UserPreferences>(StorageService.getPreferences());
    const lang = (preferences.language as LanguageCode) || 'en';

    const [contextMenu, setContextMenu] = useState<{ isOpen: boolean; x: number; y: number; toolId: string | null }>({ isOpen: false, x: 0, y: 0, toolId: null });
    const [isEditModalOpen, setEditModalOpen] = useState(false);
    const [actionModal, setActionModal] = useState<{ isOpen: boolean; mode: 'move' | 'mirror'; toolId: string | null }>({ isOpen: false, mode: 'move', toolId: null });
    const [isSelectionMode, setIsSelectionMode] = useState(false);
    const [selectedToolIds, setSelectedToolIds] = useState<Set<string>>(new Set());
    const [smartAddContext, setSmartAddContext] = useState<string | null>(null);
    const [activeChatChannel, setActiveChatChannel] = useState<string>('GENERAL');
    const [isAttendanceOpen, setAttendanceOpen] = useState(false);
    const [isProfileOpen, setProfileOpen] = useState(false);
    const [isQuickCommandOpen, setQuickCommandOpen] = useState(false);
    const [globalSelectedTask, setGlobalSelectedTask] = useState<(Task & { divName?: string, divIcon?: string, description?: string, divId?: string }) | null>(null);

    useEffect(() => {
        const loadData = async () => {
            const [t, m, g] = await Promise.all([
                UnifiedDataService.getTasks(),
                UnifiedDataService.getMessages(),
                UnifiedDataService.getChatGroups()
            ]);
            setAllTasks(t);
            setMessages(m);
            setChatGroups(g);
        };
        loadData();
    }, []);

    useEffect(() => {
        if (!user) return;
        if (isSupabaseConfigured()) {
            const subscription = UnifiedDataService.subscribeToUpdates(
                () => { UnifiedDataService.getTasks().then(setAllTasks); },
                (newMsg) => {
                    setMessages(prev => [...prev, newMsg]);
                    if (newMsg.senderId !== user.id) {
                        NotificationService.playSound();
                        if (newMsg.channelId.includes(user.id) && !newMsg.channelId.startsWith('grp_')) {
                            setNotification(`Pesan baru dari ${newMsg.senderName}`);
                        }
                    }
                },
                () => { UnifiedDataService.getChatGroups().then(setChatGroups); }
            );
            return () => { subscription?.unsubscribe(); };
        } else {
            const syncInterval = setInterval(() => {
                const storedMessages = StorageService.getMessages();
                if (storedMessages.length !== messages.length) {
                    const lastMsg = storedMessages[storedMessages.length - 1];
                    setMessages(storedMessages);
                    if (lastMsg && lastMsg.senderId !== user.id) { NotificationService.playSound(); }
                }
                const storedGroups = StorageService.getChatGroups();
                if (storedGroups.length !== chatGroups.length) setChatGroups(storedGroups);
                const storedTasks = StorageService.getTasks();
                if (storedTasks.length !== allTasks.length) setAllTasks(storedTasks);
                const storedUsers = StorageService.getUsers();
                if (storedUsers.length !== users.length) setUsers(storedUsers);
            }, 2000); 
            return () => clearInterval(syncInterval);
        }
    }, [user, messages.length, chatGroups.length, allTasks.length, users.length]);

    const dashboardDivisions = DIVISIONS.map(div => ({
        ...div,
        tasks: allTasks.filter(t => t.targetDivisionId === div.id || t.originDivisionId === div.id).sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0))
    }));

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
                e.preventDefault();
                setQuickCommandOpen(prev => !prev);
            }
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, []);

    useEffect(() => {
        if (!user) return;
        const interval = setInterval(() => {
            NotificationService.checkReminders(allTasks, (taskId) => {
                const updatedTasks = allTasks.map(t => t.id === taskId ? { ...t, isReminded: true } : t);
                setAllTasks(updatedTasks);
                UnifiedDataService.updateTask(taskId, { isReminded: true });
            });
        }, 60000);
        return () => clearInterval(interval);
    }, [user, allTasks]);

    useEffect(() => { 
        const root = window.document.documentElement; 
        if (preferences.theme === 'dark') root.classList.add('dark'); 
        else root.classList.remove('dark'); 
    }, [preferences.theme]);

    const handleLogin = (loggedInUser: User) => { StorageService.saveUser(loggedInUser); setUser(loggedInUser); };
    const handleLogout = () => { StorageService.logout(); setUser(null); };
    const handleUpdateUser = (updated: User) => { setUser(updated); StorageService.saveUser(updated); setNotification("Profile updated"); };
    const handleTeamUpdate = () => { setUsers(StorageService.getUsers()); };
    const handleUpdateAnnouncements = (updated: Announcement[]) => { setAnnouncements(updated); StorageService.saveAnnouncements(updated); setNotification("Announcements updated"); };
    const handleUpdateTools = (updated: Tool[]) => { setTools(updated); StorageService.saveTools(updated); setNotification("Tools updated"); };
    const handleUpdateAttendanceConfig = (updated: AttendanceConfig) => { setAttendanceConfig(updated); StorageService.saveAttendanceConfig(updated); };
    const handleUpdateHolidays = (updated: Holiday[]) => { setHolidays(updated); StorageService.saveHolidays(updated); };

    const handleAddTask = async (divId: DivisionType, title: string, priority: TaskPriority) => {
        const newTask: Task = { id: crypto.randomUUID(), title, isCompleted: false, priority, creatorId: user?.id || 'unknown', assigneeId: 'unassigned', originDivisionId: divId, targetDivisionId: divId, timestamp: Date.now() };
        setAllTasks(prev => [newTask, ...prev]);
        await UnifiedDataService.addTask(newTask);
        setNotification("Tugas ditambahkan");
    };

    const handleToggleTask = async (divId: DivisionType, taskId: string) => {
        const task = allTasks.find(t => t.id === taskId);
        if (task) {
            const newVal = !task.isCompleted;
            setAllTasks(prev => prev.map(t => t.id === taskId ? { ...t, isCompleted: newVal } : t));
            await UnifiedDataService.updateTask(taskId, { isCompleted: newVal });
        }
    };

    const handleDeleteTask = async (divId: DivisionType, taskId: string) => {
        if(confirm("Hapus tugas?")) {
             setAllTasks(prev => prev.filter(t => t.id !== taskId));
             await UnifiedDataService.deleteTask(taskId);
        }
    };

    const handleUpdateTask = async (divId: DivisionType, taskId: string, updates: Partial<Task>) => {
        setAllTasks(prev => prev.map(t => t.id === taskId ? { ...t, ...updates } : t));
        await UnifiedDataService.updateTask(taskId, updates);
    };

    const handleGlobalTaskSelect = (task: Task) => {
        const divId = task.targetDivisionId || task.originDivisionId;
        const div = DIVISIONS.find(d => d.id === divId);
        setGlobalSelectedTask({ ...task, divId: divId, divName: div?.name, divIcon: div?.icon });
    };

    const handleSendMessage = async (content: string, channelId: string = activeChatChannel) => { 
        if (!user) return; 
        const newMessage: ChatMessage = { id: crypto.randomUUID(), senderId: user.id, senderName: user.name, channelId: channelId, content, timestamp: Date.now() }; 
        setMessages(prev => [...prev, newMessage]);
        await UnifiedDataService.sendMessage(newMessage);
    };

    const handleCreateGroup = async (name: string, members: string[]) => {
        if (!user) return;
        const newGroup: ChatGroup = { id: `grp_${Date.now()}`, name, memberIds: members, createdAt: Date.now(), createdBy: user.id };
        setChatGroups(prev => [...prev, newGroup]);
        await UnifiedDataService.createChatGroup(newGroup);
        setNotification(`Grup "${name}" berhasil dibuat!`);
        setActiveChatChannel(newGroup.id);
    };

    const handleAddTool = (newToolData: any) => { const newTool = { ...newToolData, id: `t_${Date.now()}`, lastAccessed: 0 }; const updated = [...tools, newTool]; handleUpdateTools(updated); StorageService.logActivity('Created Tool', newTool.name); };
    const handleUpdateToolSingle = (updatedData: Partial<Tool>) => { if (!updatedData.id) return; const updatedTools = tools.map(t => t.id === updatedData.id ? { ...t, ...updatedData } : t); handleUpdateTools(updatedTools); setNotification('Tool updated'); StorageService.logActivity('Updated Tool', updatedData.name || 'Unknown Tool'); };

    const handleToolClick = (tool: Tool) => { 
        StorageService.recordAccess(tool.id); 
        setTools(StorageService.getTools()); 
        if (tool.url && tool.url !== '#') {
            window.open(tool.url, '_blank'); 
        } else {
            setNotification("Aplikasi ini masih dalam pengembangan (Draf)");
        }
    };

    const handleToggleSelection = (tool: Tool) => { const toolId = tool.id; const newSet = new Set(selectedToolIds); if (newSet.has(toolId)) newSet.delete(toolId); else newSet.add(toolId); setSelectedToolIds(newSet); setIsSelectionMode(newSet.size > 0); };

    const handleBulkAction = (action: string) => {
        if (selectedToolIds.size === 0) return;
        if (action === 'DELETE' && confirm(`Move ${selectedToolIds.size} items to trash?`)) { 
            const updated = tools.map(t => selectedToolIds.has(t.id) ? { ...t, deletedAt: Date.now() } : t); handleUpdateTools(updated); setNotification("Moved to trash"); setSelectedToolIds(new Set()); setIsSelectionMode(false); 
        } else if (action === 'ARCHIVE') {
            const updatedArch = tools.map(t => selectedToolIds.has(t.id) ? { ...t, isArchived: true } : t); handleUpdateTools(updatedArch); setNotification("Archived"); setSelectedToolIds(new Set()); setIsSelectionMode(false); 
        }
    };

    const handleContextMenu = (e: any, tool: Tool) => { e.preventDefault(); let x = e.touches ? e.touches[0].clientX : e.clientX; let y = e.touches ? e.touches[0].clientY : e.clientY; setContextMenu({ isOpen: true, x, y, toolId: tool.id }); };
    const executeAction = (action: string) => {
        const toolId = contextMenu.toolId; const tool = tools.find(t => t.id === toolId); setContextMenu({ ...contextMenu, isOpen: false }); if (!tool) return;
        if (tool.isLocked && ['EDIT', 'MOVE', 'MIRROR', 'ARCHIVE', 'DELETE'].includes(action)) { setNotification("Tool is locked"); return; }
        switch (action) { case 'OPEN': handleToolClick(tool); break; case 'EDIT': setEditModalOpen(true); break; case 'DELETE': if(confirm("Move to trash?")) { const updated = tools.map(t => t.id === toolId ? { ...t, deletedAt: Date.now() } : t); handleUpdateTools(updated); setNotification("Moved to trash"); } break; case 'MOVE': setActionModal({ isOpen: true, mode: 'move', toolId }); break; case 'MIRROR': setActionModal({ isOpen: true, mode: 'mirror', toolId }); break; case 'TOGGLE_LOCK': const updatedLock = tools.map(t => t.id === toolId ? { ...t, isLocked: !t.isLocked } : t); handleUpdateTools(updatedLock); break; }
    };

    if (!user) return <LoginView onLogin={handleLogin} />;

    return (
        <HashRouter>
            <AppLayout user={user} selectedCount={selectedToolIds.size} onBulkAction={handleBulkAction} onCancelSelection={() => { setSelectedToolIds(new Set()); setIsSelectionMode(false); }} lang={lang} onLogout={handleLogout}>
                {notification && <Toast message={notification} onClose={() => setNotification(null)} />}

                <Routes>
                    <Route path="/" element={
                        <>
                            <ChannelUpdater onUpdate={setActiveChatChannel} />
                            <Dashboard 
                                tools={tools} user={user} handleToolClick={handleToolClick} onContextMenu={handleContextMenu} onSelect={handleToggleSelection} 
                                onAddTool={handleAddTool} setNotification={setNotification} isSelectionMode={isSelectionMode} selectedIds={selectedToolIds} 
                                setSmartAddContext={setSmartAddContext}
                                onOpenAttendance={() => setAttendanceOpen(true)} onOpenProfile={() => setProfileOpen(true)} 
                                lang={lang} todayAttendance={StorageService.getTodayAttendance(user.id)} unreadAnnouncements={announcements.length} 
                                tasks={allTasks} 
                                announcements={announcements} messages={messages} onSendMessage={(msg) => handleSendMessage(msg)}
                                dashboardDivisions={dashboardDivisions}
                                onAddTask={handleAddTask} 
                                onToggleTask={handleToggleTask} 
                                onDeleteTask={handleDeleteTask}
                                onUpdateTask={handleUpdateTask}
                                activeChannel={activeChatChannel} onChangeChannel={setActiveChatChannel}
                                groups={chatGroups}
                                allUsers={users} 
                            />
                        </>
                    } />
                    <Route path="/division/:id" element={
                        <>
                            <ChannelUpdater onUpdate={setActiveChatChannel} />
                            <DivisionView 
                                tools={tools} user={user} handleToolClick={handleToolClick} onContextMenu={handleContextMenu} onSelect={handleToggleSelection} 
                                onAddTool={(divId) => setSmartAddContext(divId)} 
                                isSelectionMode={isSelectionMode} selectedIds={selectedToolIds} 
                                onOpenChat={(divId) => { setActiveChatChannel(divId); }} 
                                onOpenDivisionTasks={(divId) => {}}
                                lang={lang} 
                                tasks={allTasks}
                                onAddTask={handleAddTask} 
                                onToggleTask={handleToggleTask} 
                                onDeleteTask={handleDeleteTask}
                                onUpdateTask={handleUpdateTask}
                                messages={messages} 
                                onSendMessage={handleSendMessage} 
                            />
                        </>
                    } />
                    <Route path="/messages" element={
                        <Messages 
                            user={user}
                            messages={messages}
                            onSendMessage={handleSendMessage}
                            groups={chatGroups}
                            onCreateGroup={handleCreateGroup}
                        />
                    } />
                    <Route path="/documents" element={<DocumentsView user={user} />} />
                    <Route path="/inventory" element={<InventoryView user={user} />} />
                    <Route path="/finance" element={<FinanceView user={user} />} />
                    <Route path="/settings" element={
                        <SettingsView 
                            user={user} 
                            onUpdateUser={handleUpdateUser} 
                            tools={tools} 
                            onUpdateTools={handleUpdateTools} 
                            announcements={announcements} 
                            onUpdateAnnouncements={handleUpdateAnnouncements} 
                            attendanceConfig={attendanceConfig} 
                            onUpdateAttendanceConfig={handleUpdateAttendanceConfig} 
                            holidays={holidays} 
                            onUpdateHolidays={handleUpdateHolidays}
                            onTeamUpdate={handleTeamUpdate} 
                        />
                    } />
                </Routes>

                <QuickCommand 
                    isOpen={isQuickCommandOpen} 
                    onClose={() => setQuickCommandOpen(false)} 
                    tools={tools} 
                    users={users} 
                    divisions={DIVISIONS}
                    tasks={allTasks}
                    onTaskSelect={handleGlobalTaskSelect}
                />

                <AIAssistant 
                    tasks={allTasks} 
                    users={users} 
                    announcements={announcements} 
                />

                {globalSelectedTask && (
                    <TaskDetailView 
                        task={globalSelectedTask} 
                        isOpen={!!globalSelectedTask} 
                        onClose={() => setGlobalSelectedTask(null)} 
                        onToggle={() => handleToggleTask(globalSelectedTask.divId as DivisionType, globalSelectedTask.id)} 
                        onDelete={() => { handleDeleteTask(globalSelectedTask.divId as DivisionType, globalSelectedTask.id); setGlobalSelectedTask(null); }} 
                        onUpdate={(updates) => handleUpdateTask(globalSelectedTask.divId as DivisionType, globalSelectedTask.id, updates)} 
                    />
                )}

                {contextMenu.isOpen && (<ContextMenu x={contextMenu.x} y={contextMenu.y} isLocked={!!tools.find(t => t.id === contextMenu.toolId)?.isLocked} onClose={() => setContextMenu({ ...contextMenu, isOpen: false })} onOpen={() => executeAction('OPEN')} onEdit={() => executeAction('EDIT')} onMove={() => executeAction('MOVE')} onMirror={() => executeAction('MIRROR')} onArchive={() => executeAction('ARCHIVE')} onDelete={() => executeAction('DELETE')} onToggleLock={() => executeAction('TOGGLE_LOCK')} />)}
                <AddToolModal isOpen={isEditModalOpen} onClose={() => setEditModalOpen(false)} onSave={handleUpdateToolSingle} initialData={tools.find(t => t.id === contextMenu.toolId)} />
                <SmartAddModal isOpen={!!smartAddContext} onClose={() => setSmartAddContext(null)} onAdd={(tool) => handleAddTool(tool)} divisionName={smartAddContext || ''} />
                <ToolActionModal isOpen={actionModal.isOpen} mode={actionModal.mode} onClose={() => setActionModal({ ...actionModal, isOpen: false })} onConfirm={(div, cat) => { const updated = tools.map(t => t.id === actionModal.toolId ? { ...t, divisionId: div, category: cat } : t); if (actionModal.mode === 'mirror') { const original = tools.find(t => t.id === actionModal.toolId); if(original) updated.push({ ...original, id: `t_${Date.now()}`, divisionId: div, category: cat }); } handleUpdateTools(updated); setActionModal({ ...actionModal, isOpen: false }); setNotification("Action successful"); StorageService.logActivity(actionModal.mode === 'mirror' ? 'Mirror Tool' : 'Move Tool', tools.find(t => t.id === actionModal.toolId)?.name || 'Unknown'); }} />
                <AttendanceModal isOpen={isAttendanceOpen} onClose={() => setAttendanceOpen(false)} user={user} />
                <ProfileModal isOpen={isProfileOpen} onClose={() => setProfileOpen(false)} user={user} onUpdateUser={handleUpdateUser} announcements={announcements} onLogout={handleLogout} />
            </AppLayout>
        </HashRouter>
    );
};

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { DivisionData, ChatMessage, Announcement, User, TaskPriority, Task, UserPreferences, UserRole, ChatGroup } from '../types';
import { Icon } from './Icon';
import { GeminiService } from '../services/geminiService';
import { NotificationService } from '../services/notificationService';
import { StorageService } from '../services/storageService';
import { UnifiedDataService } from '../services/UnifiedDataService';
import { DIVISIONS } from '../constants';
import { TaskItem } from './TaskItem';
import { TaskDetailView } from './TaskDetailView';
import { BulkImportModal } from './BulkImportModal';

interface CollaborationPanelProps {
  isOpen: boolean;
  onClose: () => void;
  user: User;
  divisions: DivisionData[];
  onToggleTask: (divisionId: any, taskId: string) => void;
  onAddTask: (divisionId: any, text: string, priority: any, dueDate: string) => void;
  onDeleteTask: (divisionId: any, taskId: string) => void;
  announcements: Announcement[];
  messages: ChatMessage[];
  onSendMessage: (content: string, channelId: string) => void;
  activeChannel: string;
  onChangeChannel: (id: string) => void;
  initialTab?: 'tasks' | 'discussion';
  onUpdateTask?: (divisionId: any, taskId: string, updates: Partial<Task>) => void;
  groups?: ChatGroup[];
}

const ChatColumn: React.FC<{
    col: { id: string; name: string; icon: string; color: string };
    messages: ChatMessage[];
    user: User;
    inputValue: string;
    onInputChange: (val: string) => void;
    onSend: (e: React.FormEvent) => void;
    onFocus: () => void;
}> = ({ col, messages, user, inputValue, onInputChange, onSend, onFocus }) => {
    const lastMsgRef = useRef<HTMLDivElement>(null);
    useEffect(() => { lastMsgRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages.length]);
    return (
        <div className="flex flex-col w-80 min-w-[320px] h-full max-h-full glass-card rounded-2xl border border-white/5 bg-black/20 shrink-0">
            <div className={`p-3 border-b border-white/5 bg-white/5 flex items-center justify-between`}>
                <div className="flex items-center gap-2 font-bold text-gray-200 text-sm truncate">
                    <div className={`p-1.5 rounded-md ${col.color} text-white`}><Icon name={col.icon} size={14} /></div>
                    {col.name}
                </div>
                <span className="bg-black/30 px-2 py-0.5 rounded text-[10px] text-gray-400">{messages.length}</span>
            </div>
            <div className="flex-1 overflow-y-auto p-3 space-y-3 custom-scrollbar">
                {messages.length === 0 && <p className="text-center text-[10px] text-gray-600 italic mt-10">No messages yet.</p>}
                {messages.map(msg => {
                    const isMe = msg.senderId === user.id;
                    return (
                        <div key={msg.id} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'}`}>
                            <div className={`max-w-[90%] rounded-xl px-3 py-2 text-xs shadow-sm ${isMe ? 'bg-brand-600 text-white' : 'bg-[#1e293b] text-gray-200 border border-white/10'}`}>
                                {!isMe && <p className="text-[9px] font-bold text-brand-400 mb-0.5 truncate">{msg.senderName}</p>}
                                <p className="whitespace-pre-wrap leading-tight">{msg.content}</p>
                            </div>
                            <span className="text-[9px] text-gray-600 mt-1 px-1">{new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                        </div>
                    );
                })}
                <div ref={lastMsgRef} />
            </div>
            <div className="p-3 border-t border-white/5 bg-black/20">
                <form onSubmit={onSend} className="flex gap-2">
                    <input value={inputValue} onChange={(e) => onInputChange(e.target.value)} onFocus={onFocus} className="flex-1 bg-black/40 border border-white/10 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-brand-500 transition-colors" placeholder="Reply..." />
                    <button type="submit" disabled={!inputValue?.trim()} className="bg-brand-600 hover:bg-brand-500 text-white p-2 rounded-lg transition-colors disabled:opacity-50"><Icon name="Send" size={14} /></button>
                </form>
            </div>
        </div>
    );
};

const DivisionColumn: React.FC<{
    division: DivisionData; tasks: Task[]; onToggle: (taskId: string) => void; onSelect: (taskId: string) => void; onDelete: (taskId: string) => void; onDiscuss: (title: string) => void; onWhatsApp: (task: Task) => void; onReminder: (task: Task) => void; onQuickAdd: (text: string) => void;
}> = ({ division, tasks, onToggle, onSelect, onDelete, onDiscuss, onWhatsApp, onReminder, onQuickAdd }) => {
    const [isAdding, setIsAdding] = useState(false);
    const [quickInput, setQuickInput] = useState('');
    const handleSubmit = (e: React.FormEvent) => { e.preventDefault(); if(!quickInput.trim()) return; onQuickAdd(quickInput); setQuickInput(''); setIsAdding(false); }
    return (
        <div className="flex flex-col w-80 min-w-[320px] h-full max-h-full glass-card rounded-2xl border border-white/5 bg-black/20 shrink-0">
             <div className="p-4 border-b border-white/5 bg-white/5 flex justify-between items-center"><div className="flex items-center gap-2 font-bold text-gray-200"><Icon name={division.icon} size={16} className="text-brand-400" /><span className="text-sm truncate">{division.name}</span></div><span className="bg-black/30 px-2 py-0.5 rounded text-xs text-gray-400 font-mono">{tasks.filter(t => !t.isCompleted).length}</span></div>
            <div className="flex-1 overflow-y-auto p-3 space-y-3 custom-scrollbar">
                {tasks.length === 0 && <div className="text-center py-10 text-gray-600 text-xs italic border-2 border-dashed border-white/5 rounded-xl">No active tasks</div>}
                {tasks.map(task => (<div key={task.id}><TaskItem task={task} onToggle={() => onToggle(task.id)} onSelect={() => onSelect(task.id)} onDelete={() => onDelete(task.id)} onDiscuss={() => onDiscuss(task.title)} onWhatsApp={() => onWhatsApp(task)} onReminder={() => onReminder(task)} /></div>))}
            </div>
            <div className="p-3 border-t border-white/5 bg-black/20">{isAdding ? (<form onSubmit={handleSubmit} className="flex flex-col gap-2 animate-[fadeIn_0.2s]"><input autoFocus className="w-full bg-black/40 border border-white/10 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-brand-500" placeholder="Task title..." value={quickInput} onChange={e => setQuickInput(e.target.value)} onBlur={() => !quickInput && setIsAdding(false)} /><div className="flex gap-2"><button type="submit" className="flex-1 bg-brand-600 hover:bg-brand-500 text-white py-1.5 rounded-lg text-xs font-bold transition-colors">Add</button><button type="button" onClick={() => setIsAdding(false)} className="px-3 py-1.5 bg-white/5 hover:bg-white/10 text-gray-400 rounded-lg text-xs transition-colors">Cancel</button></div></form>) : (<button onClick={() => setIsAdding(true)} className="w-full py-2 flex items-center justify-center gap-2 text-xs font-bold text-gray-400 hover:text-white hover:bg-white/5 rounded-lg transition-all border border-transparent hover:border-white/10"><Icon name="Plus" size={14} /> Quick Add to {division.name}</button>)}</div>
        </div>
    )
}

export const CollaborationPanel: React.FC<CollaborationPanelProps> = ({
    isOpen, onClose, user, divisions, onToggleTask, onAddTask, onDeleteTask,
    announcements, messages, onSendMessage, activeChannel, onChangeChannel,
    initialTab = 'tasks', onUpdateTask, groups = []
}) => {
    // --- STATE MANAGEMENT ---
    const [activeMainTab, setActiveMainTab] = useState<'tasks' | 'discussion' | 'analytics'>('tasks');
    const [activeChatTab, setActiveChatTab] = useState<'announcements' | 'chat'>('announcements');
    const [isExpanded, setIsExpanded] = useState(false);
    const [taskViewMode, setTaskViewMode] = useState<'list' | 'board'>('board');
    const [tasksDisplayMode, setTasksDisplayMode] = useState<'folder' | 'list'>('folder');
    const [inputMode, setInputMode] = useState<'single' | 'bulk'>('single');
    const [newTaskText, setNewTaskText] = useState('');
    const [targetDivision, setTargetDivision] = useState<string>('AUTO');
    const [targetPriority, setTargetPriority] = useState<TaskPriority>('medium');
    const [isAIGenerating, setIsAIGenerating] = useState(false);
    const [isBulkModalOpen, setIsBulkModalOpen] = useState(false);
    const [expandedDivisions, setExpandedDivisions] = useState<Set<string>>(new Set());
    const [selectedTask, setSelectedTask] = useState<(Task & { divName?: string, divIcon?: string, description?: string, divId?: string }) | null>(null);
    const [msgInput, setMsgInput] = useState('');
    const [chatContext, setChatContext] = useState<string | null>(null);
    const chatEndRef = useRef<HTMLDivElement>(null);
    const [columnInputs, setColumnInputs] = useState<Record<string, string>>({});
    const [prefs, setPrefs] = useState<UserPreferences>(StorageService.getPreferences());

    // Voice & Reporting States
    const [isListening, setIsListening] = useState(false);
    const [isSendingReport, setIsSendingReport] = useState(false);

    const allUsers = StorageService.getUsers();

    useEffect(() => { if (isOpen) { setActiveMainTab(initialTab === 'discussion' ? 'discussion' : 'tasks'); setPrefs(StorageService.getPreferences()); } }, [isOpen, initialTab]);

    // --- FILTER LOGIC (Strict Access Control) ---
    const visibleDivisions = useMemo(() => {
        if (user.role === UserRole.ADMIN) return divisions;
        return divisions.filter(d => d.id === user.division);
    }, [user, divisions]);

    const myGroups = useMemo(() => groups.filter(g => g.memberIds.includes(user.id) || g.createdBy === user.id), [groups, user.id]);

    type FlatTask = Task & { divName: string; divId: string; divIcon: string };

    const allFlatTasks = useMemo<FlatTask[]>(() => {
        const flat: FlatTask[] = [];
        divisions.forEach(div => {
            div.tasks.forEach(t => {
                const isRelevant = user.role === UserRole.ADMIN || div.id === user.division || t.originDivisionId === user.division;
                if (isRelevant) {
                    flat.push({ ...t, divName: div.name, divId: div.id, divIcon: div.icon });
                }
            });
        });
        return flat.sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0));
    }, [divisions, user]);

    const activeChannelId = activeChannel;
    const filteredMessages = useMemo(() => messages.filter((m) => m.channelId === activeChannelId), [messages, activeChannelId]);
    useEffect(() => { if (isOpen && activeMainTab === 'discussion' && activeChatTab === 'chat' && !isExpanded) { chatEndRef.current?.scrollIntoView({ behavior: 'smooth' }); } }, [isOpen, activeMainTab, activeChatTab, filteredMessages.length, chatContext, isExpanded]);

    const getChannelName = (id: string) => {
        if (id === 'GENERAL') return '🌐 Umum / Semua Tim';
        const division = DIVISIONS.find(d => d.id === id);
        if (division) return `🔒 Divisi ${division.name}`;
        const group = groups.find(g => g.id === id);
        if (group) return `# ${group.name}`;
        if (id.includes('_') && !id.startsWith('grp_')) {
            const parts = id.split('_');
            const otherUserId = parts.find(p => p !== user.id);
            const otherUser = allUsers.find(u => u.id === otherUserId);
            return otherUser ? `👤 ${otherUser.name}` : 'Private Message';
        }
        return id;
    };

    const myDMs = useMemo(() => {
        const dmChannels = new Set<string>();
        messages.forEach(msg => {
            if (msg.channelId.includes('_') && !msg.channelId.startsWith('grp_')) {
                const parts = msg.channelId.split('_');
                if (parts.includes(user.id)) dmChannels.add(msg.channelId);
            }
        });
        return Array.from(dmChannels);
    }, [messages, user.id]);

    const handleSingleSubmit = async () => {
        if (!newTaskText.trim()) return;
        if (targetDivision === 'BROADCAST') { DIVISIONS.forEach(div => { onAddTask(div.id, newTaskText, targetPriority, ''); }); setNewTaskText(''); return; }
        let finalDiv = targetDivision; let finalTitle = newTaskText; let finalPriority = targetPriority;
        if (targetDivision === 'AUTO') {
            setIsAIGenerating(true);
            try {
                const result = await GeminiService.parseBulkTasks(newTaskText);
                if (result && result.length > 0) {
                    const aiResult = result[0];
                    if (aiResult.divisionId === 'BROADCAST') { DIVISIONS.forEach(div => onAddTask(div.id, aiResult.title || newTaskText, aiResult.priority as TaskPriority || 'medium', '')); setNewTaskText(''); setIsAIGenerating(false); return; }
                    finalDiv = aiResult.divisionId || user.division; finalTitle = aiResult.title || newTaskText; finalPriority = (aiResult.priority as TaskPriority) || 'medium';
                } else { finalDiv = user.division; }
            } catch (e) { finalDiv = user.division; } finally { setIsAIGenerating(false); }
        }
        onAddTask(finalDiv, finalTitle, finalPriority, '');
        setNewTaskText('');
    };

    const handleBulkConfirm = (tasks: any[]) => { 
        tasks.forEach(t => { 
            if (t.divisionId === 'BROADCAST') { 
                DIVISIONS.forEach(div => { onAddTask(div.id, t.title, t.priority || 'medium', t.dueDate || ''); }); 
            } else { 
                onAddTask(t.divisionId || 'Administrasi', t.title, t.priority || 'medium', t.dueDate || ''); 
            } 
        }); 
    };

    const handleVoiceInput = () => {
        if (!('webkitSpeechRecognition' in window) && !('SpeechRecognition' in window)) { alert("Browser tidak mendukung Input Suara."); return; }
        if (isListening) return;
        const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
        const recognition = new SpeechRecognition();
        recognition.lang = 'id-ID';
        recognition.onstart = () => { setIsListening(true); };
        recognition.onresult = (event: any) => { const transcript = event.results[0][0].transcript; setNewTaskText(prev => (prev + ' ' + transcript).trim()); };
        recognition.onend = () => { setIsListening(false); };
        recognition.start();
    };

    const handleDailyReport = async () => { setIsSendingReport(true); try { const result = await NotificationService.sendDailyReport(allFlatTasks, user, prefs); alert(result.success ? result.detail : "Gagal: " + result.detail); } catch (e) { alert("Error."); } finally { setIsSendingReport(false); } };
    const toggleDivision = (id: string) => { const newSet = new Set(expandedDivisions); if (newSet.has(id)) newSet.delete(id); else newSet.add(id); setExpandedDivisions(newSet); };
    const handleDiscussTask = (taskText: string, divisionId: string) => { setActiveMainTab('discussion'); setActiveChatTab('chat'); if (divisionId !== 'GENERAL' && DIVISIONS.some(d => d.id === divisionId)) onChangeChannel(divisionId); setChatContext(taskText); setMsgInput(""); if(isExpanded) setIsExpanded(false); };
    const handleSendChat = (e: React.FormEvent) => { e.preventDefault(); if (!msgInput.trim()) return; const finalMessage = chatContext ? `[Membahas: ${chatContext}]\n${msgInput}` : msgInput; onSendMessage(finalMessage, activeChannel); setMsgInput(''); setChatContext(null); };
    const handleMultiChatSend = (e: React.FormEvent, channelId: string) => { e.preventDefault(); const content = columnInputs[channelId]; if (!content?.trim()) return; onSendMessage(content, channelId); setColumnInputs(prev => ({ ...prev, [channelId]: '' })); onChangeChannel(channelId); };
    const handleWhatsApp = (task: Task) => NotificationService.sendToWhatsApp(task, prefs);
    const handleSetReminder = (divId: string, task: Task) => { const choice = prompt("Set Reminder (menit)?", "15"); if (choice && onUpdateTask) { const delay = parseInt(choice) * 60 * 1000; if (delay > 0) { onUpdateTask(divId, task.id, { reminderAt: Date.now() + delay, isReminded: false }); alert(`Pengingat diset.`); NotificationService.requestPermission(); }}};
    const handleSelectTask = (taskId: string) => { const found = allFlatTasks.find(t => t.id === taskId); if (found) setSelectedTask(found); };

    const renderAnalytics = () => {
        const total = allFlatTasks.length;
        const completed = allFlatTasks.filter(t => t.isCompleted).length;
        return (
            <div className="p-8 space-y-8 animate-[fadeIn_0.5s]">
                 <div className="bg-gradient-to-r from-indigo-900/40 to-purple-900/40 border border-indigo-500/30 p-6 rounded-2xl flex items-start gap-4 relative overflow-hidden"><div className="p-3 bg-indigo-500/20 rounded-xl text-indigo-300 shadow-inner shrink-0"><Icon name="Sparkles" size={24} /></div><div><h4 className="text-indigo-200 font-bold mb-1">AI Insight</h4><p className="text-indigo-100/70 text-sm">Team has {total} tasks, {completed} completed.</p></div></div>
                <div className="grid grid-cols-2 gap-4"><div className="glass-card p-5 rounded-2xl border-l-4 border-l-blue-500"><p className="text-xs text-gray-400 font-bold uppercase">Total</p><p className="text-3xl font-bold text-white">{total}</p></div><div className="glass-card p-5 rounded-2xl border-l-4 border-l-emerald-500"><p className="text-xs text-gray-400 font-bold uppercase">Done</p><p className="text-3xl font-bold text-emerald-400">{completed}</p></div></div>
            </div>
        )
    };

    const renderKanbanChat = () => {
        const columns = [ { id: 'GENERAL', name: '📢 GENERAL', icon: 'Megaphone', color: 'bg-indigo-500' }, ...visibleDivisions.map(d => ({ id: d.id, name: d.name, icon: d.icon, color: 'bg-gray-700' })), ...myGroups.map(g => ({ id: g.id, name: g.name, icon: 'Users', color: 'bg-emerald-600' })) ];
        return (<div className="flex gap-4 h-full p-6 overflow-x-auto items-start">{columns.map(col => (<ChatColumn key={col.id} col={col} messages={messages.filter(m => m.channelId === col.id)} user={user} inputValue={columnInputs[col.id] || ''} onInputChange={(val) => setColumnInputs(prev => ({ ...prev, [col.id]: val }))} onSend={(e) => handleMultiChatSend(e, col.id)} onFocus={() => onChangeChannel(col.id)} />))}</div>);
    };

    const renderDivisionBoard = () => {
        return (<div className="flex gap-4 h-full p-6 overflow-x-auto items-start">{visibleDivisions.map(div => (<DivisionColumn key={div.id} division={div} tasks={div.tasks.filter(t => !t.isCompleted)} onToggle={(tid) => onToggleTask(div.id, tid)} onSelect={(tid) => handleSelectTask(tid)} onDelete={(tid) => onDeleteTask(div.id, tid)} onDiscuss={(title) => handleDiscussTask(title, div.id)} onWhatsApp={handleWhatsApp} onReminder={(t) => handleSetReminder(div.id, t)} onQuickAdd={(text) => onAddTask(div.id, text, 'medium', '')} />))}</div>)
    };

    return (
        <div className={`fixed transition-all duration-500 ease-in-out bg-[#0f172a]/95 backdrop-blur-xl shadow-2xl z-[90] flex flex-col ${isExpanded ? 'inset-0 w-full' : `inset-y-0 right-0 w-full md:w-[420px] ${isOpen ? 'translate-x-0' : 'translate-x-full'}`} ${!isOpen && !isExpanded ? 'translate-x-full' : ''}`}>
            {/* HEADER TABS */}
            <div className="flex h-16 border-b border-white/10 shrink-0 bg-black/20 relative items-center px-2">
                <div className="flex-1 flex gap-1">
                    <button onClick={() => setActiveMainTab('tasks')} className={`flex-1 py-2 flex items-center justify-center gap-2 font-bold text-xs md:text-sm tracking-wide transition-all rounded-lg ${activeMainTab === 'tasks' ? 'bg-brand-600 text-white shadow-lg' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}><Icon name="Layout" size={16} /> TASKS</button>
                    <button onClick={() => setActiveMainTab('analytics')} className={`flex-1 py-2 flex items-center justify-center gap-2 font-bold text-xs md:text-sm tracking-wide transition-all rounded-lg ${activeMainTab === 'analytics' ? 'bg-brand-600 text-white shadow-lg' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}><Icon name="BarChart2" size={16} /> ANALYTICS</button>
                    <button onClick={() => setActiveMainTab('discussion')} className={`flex-1 py-2 flex items-center justify-center gap-2 font-bold text-xs md:text-sm tracking-wide transition-all rounded-lg ${activeMainTab === 'discussion' ? 'bg-brand-600 text-white shadow-lg' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}><Icon name="MessageSquare" size={16} /> DISCUSS</button>
                </div>
                <div className="flex items-center gap-1 ml-2 border-l border-white/10 pl-2">
                    {activeMainTab !== 'analytics' && (<button onClick={() => setIsExpanded(!isExpanded)} className={`p-2 hover:bg-white/10 rounded-lg text-gray-400 hover:text-brand-400 transition-colors ${isExpanded ? 'bg-white/10 text-white' : ''}`}><Icon name={isExpanded ? "Minimize2" : "Maximize2"} size={18} /></button>)}
                    <button onClick={onClose} className="p-2 bg-red-500/10 hover:bg-red-500 rounded-lg text-red-400 hover:text-white transition-colors ml-1"><Icon name="X" size={18} /></button>
                </div>
            </div>

            <div className="flex-1 overflow-hidden flex flex-col relative bg-gradient-to-br from-gray-900 to-[#0b1120]">
                {activeMainTab === 'analytics' && (<div className="flex-1 overflow-y-auto custom-scrollbar">{renderAnalytics()}</div>)}
                {activeMainTab === 'tasks' && (
                    <div className="flex-1 flex flex-col animate-[fadeIn_0.2s] overflow-hidden relative">
                        {/* INPUT HEADER */}
                        <div className="p-5 border-b border-white/10 bg-[#0f172a]/80 backdrop-blur-md shadow-xl z-30 shrink-0">

                            {/* AI / Manual Switch */}
                            <div className="flex bg-black/40 p-1 rounded-xl mb-4 border border-white/5">
                                <button className={`flex-1 py-2 rounded-lg text-xs font-bold flex items-center justify-center gap-2 transition-all bg-white/10 text-white shadow-sm`}><Icon name="PenTool" size={14} /> 🖊️ Task Input</button>
                                <button onClick={() => setIsBulkModalOpen(true)} className="flex-1 py-2 rounded-lg text-xs font-bold flex items-center justify-center gap-2 transition-all text-gray-500 hover:text-white"><Icon name="Sparkles" size={14} /> ✨ Bulk Import</button>
                            </div>

                            <div className="flex items-center justify-between mb-3 px-1">
                                <button onClick={handleDailyReport} disabled={isSendingReport} className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wider border transition-all ${isSendingReport ? 'bg-green-500/20 border-green-500/30 text-green-300' : 'bg-green-600 hover:bg-green-500 text-white border-transparent'}`}>{isSendingReport ? <Icon name="Loader2" size={12} className="animate-spin"/> : <Icon name="Megaphone" size={12}/>}{isSendingReport ? 'Mengirim...' : '📢 Lapor Harian'}</button>
                            </div>

                            <div className="space-y-3 animate-[fadeIn_0.2s]">
                                <div className="relative group">
                                    <input 
                                        className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 pr-12 text-sm text-white focus:ring-1 focus:ring-brand-500 outline-none transition-all placeholder-gray-500" 
                                        placeholder="Ketik tugas atau klik mic..." 
                                        value={newTaskText} 
                                        onChange={e => setNewTaskText(e.target.value)} 
                                        onKeyDown={e => { if(e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSingleSubmit(); }}} 
                                    />
                                    <div className="absolute right-2 top-1/2 -translate-y-1/2 flex items-center gap-1">
                                        {isAIGenerating && <Icon name="Loader2" size={16} className="text-purple-400 animate-spin mr-2" />}
                                        <button onClick={handleVoiceInput} className={`p-2 rounded-lg transition-colors ${isListening ? 'bg-red-500 text-white animate-pulse' : 'text-gray-400 hover:bg-white/10 hover:text-white'}`}><Icon name={isListening ? "MicOff" : "Mic"} size={18} /></button>
                                    </div>
                                </div>
                                <div className="flex gap-2">
                                    <div className="relative flex-1"><select value={targetDivision} onChange={e => setTargetDivision(e.target.value)} className="w-full bg-black/40 border border-white/10 rounded-xl pl-3 pr-8 py-2 text-xs text-white outline-none cursor-pointer hover:bg-white/5"><option value="AUTO">✨ Auto (AI)</option><option value="BROADCAST">📢 Broadcast All</option>{DIVISIONS.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select><Icon name="ChevronDown" size={12} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none"/></div>
                                    <div className="relative w-28"><select value={targetPriority} onChange={e => setTargetPriority(e.target.value as TaskPriority)} className="w-full bg-black/40 border border-white/10 rounded-xl pl-3 pr-8 py-2 text-xs text-white outline-none cursor-pointer hover:bg-white/5"><option value="low">Low</option><option value="medium">Normal</option><option value="high">Urgent</option></select><Icon name="ChevronDown" size={12} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none"/></div>
                                    <button onClick={handleSingleSubmit} disabled={isAIGenerating || !newTaskText.trim()} className="bg-brand-600 hover:bg-brand-500 text-white px-4 rounded-xl shadow-lg shadow-brand-500/20 transition-all active:scale-95 flex items-center justify-center gap-2 text-xs font-bold"><Icon name="Plus" size={16}/> ADD</button>
                                </div>
                            </div>

                            {!isExpanded && (<div className="mt-4 flex bg-black/40 p-1 rounded-xl border border-white/5"><button onClick={() => setTasksDisplayMode('folder')} className={`flex-1 py-1.5 rounded-lg text-[10px] font-bold uppercase transition-all flex items-center justify-center gap-2 ${tasksDisplayMode === 'folder' ? 'bg-white/10 text-white shadow-sm' : 'text-gray-500 hover:text-white'}`}><Icon name="Folder" size={12}/> Folders</button><button onClick={() => setTasksDisplayMode('list')} className={`flex-1 py-1.5 rounded-lg text-[10px] font-bold uppercase transition-all flex items-center justify-center gap-2 ${tasksDisplayMode === 'list' ? 'bg-white/10 text-white shadow-sm' : 'text-gray-500 hover:text-white'}`}><Icon name="List" size={12}/> All Tasks</button></div>)}
                        </div>
                        <div className="flex-1 overflow-y-auto custom-scrollbar p-5 space-y-4 bg-black/10">
                            {isExpanded && taskViewMode === 'board' ? renderDivisionBoard() : (
                                <>
                                    {tasksDisplayMode === 'folder' && visibleDivisions.map(div => (<div key={div.id} className="bg-white/5 border border-white/5 rounded-2xl overflow-hidden shadow-sm hover:shadow-md transition-all"><button onClick={() => toggleDivision(div.id)} className="w-full flex justify-between items-center p-4 hover:bg-white/5 transition-colors"><div className="flex items-center gap-3"><div className="p-1.5 bg-gray-800 rounded-lg text-gray-300"><Icon name={div.icon} size={16}/></div><span className="text-sm font-bold text-gray-200">{div.name}</span></div><div className="flex items-center gap-3">{div.tasks.filter(t => !t.isCompleted).length > 0 && <span className="bg-brand-500 text-white text-[10px] font-bold px-2 py-0.5 rounded-full">{div.tasks.filter(t => !t.isCompleted).length}</span>}<Icon name="ChevronDown" size={16} className={`text-gray-500 transition-transform duration-300 ${expandedDivisions.has(div.id) ? 'rotate-180' : ''}`} /></div></button>{expandedDivisions.has(div.id) && (<div className="p-4 pt-0 space-y-3 bg-black/10 border-t border-white/5 animate-[fadeIn_0.2s]"><div className="h-2"></div>{div.tasks.length === 0 && <p className="text-center text-xs text-gray-500 italic py-2">No tasks yet.</p>}{div.tasks.map(task => (<div key={task.id}><TaskItem task={task} onToggle={() => onToggleTask(div.id, task.id)} onSelect={() => handleSelectTask(task.id)} onDelete={() => onDeleteTask(div.id, task.id)} onDiscuss={() => handleDiscussTask(task.title, div.id)} onWhatsApp={() => handleWhatsApp(task)} onReminder={() => handleSetReminder(div.id, task)} /></div>))}</div>)}</div>))}
                                    {tasksDisplayMode === 'list' && (<div className="space-y-4">{allFlatTasks.length === 0 && (<div className="text-center py-10 text-gray-500 opacity-50"><Icon name="CheckSquare" size={48} className="mx-auto mb-2"/><p>No tasks found.</p></div>)}{allFlatTasks.map(task => (<div key={task.id}><TaskItem task={task} showDivisionBadge={true} divisionName={task.divName} divisionIcon={task.divIcon} onToggle={() => onToggleTask(task.divId, task.id)} onSelect={() => handleSelectTask(task.id)} onDelete={() => onDeleteTask(task.divId, task.id)} onDiscuss={() => handleDiscussTask(task.title, task.divId)} onWhatsApp={() => handleWhatsApp(task)} onReminder={() => handleSetReminder(task.divId, task)} /></div>))}</div>)}
                                </>
                            )}
                        </div>
                        {selectedTask && (
                            <TaskDetailView 
                                task={selectedTask} 
                                isOpen={!!selectedTask} 
                                onClose={() => setSelectedTask(null)} 
                                onToggle={() => onToggleTask(selectedTask.divId || selectedTask.originDivisionId, selectedTask.id)} 
                                onDelete={() => { onDeleteTask(selectedTask.divId || selectedTask.originDivisionId, selectedTask.id); setSelectedTask(null); }} 
                                onUpdate={(updates) => onUpdateTask && onUpdateTask(selectedTask.divId || selectedTask.originDivisionId, selectedTask.id, updates)} 
                            />
                        )}
                    </div>
                )}
                {activeMainTab === 'discussion' && (
                     <div className="flex flex-col h-full animate-[fadeIn_0.2s] overflow-hidden">
                        <div className="flex p-3 gap-2 shrink-0 bg-black/20 border-b border-white/5"><button onClick={() => setActiveChatTab('announcements')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition-colors ${activeChatTab === 'announcements' ? 'bg-white/10 text-white border border-white/10' : 'text-gray-500 hover:text-gray-300'}`}>Announcements</button><button onClick={() => setActiveChatTab('chat')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition-colors ${activeChatTab === 'chat' ? 'bg-white/10 text-white border border-white/10' : 'text-gray-500 hover:text-gray-300'}`}>Chat</button></div>
                         {activeChatTab === 'chat' && (
                            <div className="flex-1 flex flex-col min-h-0 overflow-hidden">
                                {isExpanded ? (
                                    <div className="flex-1 overflow-hidden relative">{renderKanbanChat()}</div>
                                ) : (
                                    <>
                                        <div className="p-3 border-b border-white/5 bg-white/5">
                                            <select className="w-full bg-black/40 border border-white/10 text-white text-xs rounded-lg px-3 py-2 outline-none" value={activeChannelId} onChange={(e) => onChangeChannel(e.target.value)}>
                                                <option value="GENERAL">🌐 Umum / Semua Tim</option>
                                                <optgroup label="Divisi Spesifik">{visibleDivisions.map((d) => (<option key={d.id} value={d.id}>🔒 {d.name}</option>))}</optgroup>
                                                {myGroups.length > 0 && <optgroup label="Grup Saya">{myGroups.map(g => (<option key={g.id} value={g.id}># {g.name}</option>))}</optgroup>}
                                                {myDMs.length > 0 && <optgroup label="Pesan Pribadi">{myDMs.map(id => (<option key={id} value={id}>{getChannelName(id)}</option>))}</optgroup>}
                                            </select>
                                        </div>
                                        <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                                            {filteredMessages.map((msg) => (
                                                <div key={msg.id} className={`flex flex-col ${msg.senderId === user.id ? 'items-end' : 'items-start'}`}>
                                                    <div className={`max-w-[85%] rounded-xl px-3 py-2 text-xs ${msg.senderId === user.id ? 'bg-brand-600 text-white' : 'bg-[#1e293b] text-gray-200 border border-white/10'}`}>
                                                        {msg.senderId !== user.id && <p className="text-[9px] font-bold text-brand-400 mb-0.5">{msg.senderName}</p>}
                                                        <p>{msg.content}</p>
                                                    </div>
                                                </div>
                                            ))}
                                            <div ref={chatEndRef} />
                                        </div>
                                        <div className="p-3 border-t border-white/5 bg-black/20">
                                            <form onSubmit={handleSendChat} className="flex gap-2">
                                                <input value={msgInput} onChange={(e) => setMsgInput(e.target.value)} className="flex-1 bg-black/40 border border-white/10 rounded-lg px-3 py-2 text-xs text-white outline-none" placeholder="Type message..." />
                                                <button type="submit" disabled={!msgInput.trim()} className="bg-brand-600 text-white p-2 rounded-lg"><Icon name="Send" size={16}/></button>
                                            </form>
                                        </div>
                                    </>
                                )}
                            </div>
                         )}
                         {activeChatTab === 'announcements' && (<div className="flex-1 overflow-y-auto p-4 space-y-4">{announcements.map(ann => (<div key={ann.id} className="bg-white/5 border border-white/5 p-4 rounded-xl border-l-4 border-l-brand-500"><h5 className="text-white text-sm font-bold">{ann.title}</h5><p className="text-xs text-gray-400 mt-1">{ann.content}</p></div>))}</div>)}
                     </div>
                )}
            </div>

            <BulkImportModal isOpen={isBulkModalOpen} onClose={() => setIsBulkModalOpen(false)} onImport={handleBulkConfirm} />
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, useParams } from 'react-router-dom';
import { Tool, User, Announcement, ChatMessage, AttendanceConfig, Holiday, UserPreferences, AttendanceRecord, Task, DivisionType, DivisionData, TaskPriority, ChatGroup } from './types';
import { StorageService } from './services/storageService';
import { UnifiedDataService } from './services/UnifiedDataService'; 
import { isSupabaseConfigured } from './services/supabaseClient';
import { AddToolModal } from './components/AddToolModal';
import { SmartAddModal } from './components/SmartAddModal';
import { ContextMenu } from './components/ContextMenu';
import { ToolActionModal } from './components/ToolActionModal';
import { ProfileModal } from './components/ProfileModal';
import { SettingsView } from './components/SettingsView';
import { AttendanceModal } from './components/AttendanceModal';
import { LoginView } from './components/LoginView';
import { Dashboard } from './components/Dashboard';
import { DivisionView } from './components/DivisionView';
import { Messages } from './components/Messages';
import { DocumentsView } from './components/DocumentsView';
import { InventoryView } from './components/InventoryView';
import { FinanceView } from './components/FinanceView';
import { AppLayout, Toast } from './components/Layout';
import { QuickCommand } from './components/QuickCommand';
import { AIAssistant } from './components/AIAssistant';
import { LanguageCode } from './translations';
import { DIVISIONS } from './constants';
import { NotificationService } from './services/notificationService';
import { TaskDetailView } from './components/TaskDetailView';

const ChannelUpdater: React.FC<{ onUpdate: (id: string) => void }> = ({ onUpdate }) => {
    const { id } = useParams<{ id: string }>();
    useEffect(() => {
        if (id) onUpdate(id);
        else onUpdate('GENERAL');
    }, [id, onUpdate]);
    return null;
};

const App: React.FC = () => {
    const [user, setUser] = useState<User | null>(StorageService.getUser());
    const [tools, setTools] = useState<Tool[]>(StorageService.getTools());
    const [users, setUsers] = useState<User[]>(StorageService.getUsers());
    const [allTasks, setAllTasks] = useState<Task[]>([]);
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [chatGroups, setChatGroups] = useState<ChatGroup[]>([]);
    const [notification, setNotification] = useState<string | null>(null);
    const [announcements, setAnnouncements] = useState<Announcement[]>(StorageService.getAnnouncements());
    const [attendanceConfig, setAttendanceConfig] = useState<AttendanceConfig>(StorageService.getAttendanceConfig());
    const [holidays, setHolidays] = useState<Holiday[]>(StorageService.getHolidays());
    const [preferences] = useState<UserPreferences>(StorageService.getPreferences());
    const lang = (preferences.language as LanguageCode) || 'en';

    const [contextMenu, setContextMenu] = useState<{ isOpen: boolean; x: number; y: number; toolId: string | null }>({ isOpen: false, x: 0, y: 0, toolId: null });
    const [isEditModalOpen, setEditModalOpen] = useState(false);
    const [actionModal, setActionModal] = useState<{ isOpen: boolean; mode: 'move' | 'mirror'; toolId: string | null }>({ isOpen: false, mode: 'move', toolId: null });
    const [isSelectionMode, setIsSelectionMode] = useState(false);
    const [selectedToolIds, setSelectedToolIds] = useState<Set<string>>(new Set());
    const [smartAddContext, setSmartAddContext] = useState<string | null>(null);
    const [activeChatChannel, setActiveChatChannel] = useState<string>('GENERAL');
    const [isAttendanceOpen, setAttendanceOpen] = useState(false);
    const [isProfileOpen, setProfileOpen] = useState(false);
    const [isQuickCommandOpen, setQuickCommandOpen] = useState(false);
    const [globalSelectedTask, setGlobalSelectedTask] = useState<(Task & { divName?: string, divIcon?: string, description?: string, divId?: string }) | null>(null);

    useEffect(() => {
        const loadData = async () => {
            const [t, m, g] = await Promise.all([
                UnifiedDataService.getTasks(),
                UnifiedDataService.getMessages(),
                UnifiedDataService.getChatGroups()
            ]);
            setAllTasks(t);
            setMessages(m);
            setChatGroups(g);
        };
        loadData();
    }, []);

    useEffect(() => {
        if (!user) return;
        if (isSupabaseConfigured()) {
            const subscription = UnifiedDataService.subscribeToUpdates(
                () => { UnifiedDataService.getTasks().then(setAllTasks); },
                (newMsg) => {
                    setMessages(prev => [...prev, newMsg]);
                    if (newMsg.senderId !== user.id) {
                        NotificationService.playSound();
                        if (newMsg.channelId.includes(user.id) && !newMsg.channelId.startsWith('grp_')) {
                            setNotification(`Pesan baru dari ${newMsg.senderName}`);
                        }
                    }
                },
                () => { UnifiedDataService.getChatGroups().then(setChatGroups); }
            );
            return () => { subscription?.unsubscribe(); };
        } else {
            const syncInterval = setInterval(() => {
                const storedMessages = StorageService.getMessages();
                if (storedMessages.length !== messages.length) {
                    const lastMsg = storedMessages[storedMessages.length - 1];
                    setMessages(storedMessages);
                    if (lastMsg && lastMsg.senderId !== user.id) { NotificationService.playSound(); }
                }
                const storedGroups = StorageService.getChatGroups();
                if (storedGroups.length !== chatGroups.length) setChatGroups(storedGroups);
                const storedTasks = StorageService.getTasks();
                if (storedTasks.length !== allTasks.length) setAllTasks(storedTasks);
                const storedUsers = StorageService.getUsers();
                if (storedUsers.length !== users.length) setUsers(storedUsers);
            }, 2000); 
            return () => clearInterval(syncInterval);
        }
    }, [user, messages.length, chatGroups.length, allTasks.length, users.length]);

    const dashboardDivisions = DIVISIONS.map(div => ({
        ...div,
        tasks: allTasks.filter(t => t.targetDivisionId === div.id || t.originDivisionId === div.id).sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0))
    }));

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
                e.preventDefault();
                setQuickCommandOpen(prev => !prev);
            }
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, []);

    useEffect(() => {
        if (!user) return;
        const interval = setInterval(() => {
            NotificationService.checkReminders(allTasks, (taskId) => {
                const updatedTasks = allTasks.map(t => t.id === taskId ? { ...t, isReminded: true } : t);
                setAllTasks(updatedTasks);
                UnifiedDataService.updateTask(taskId, { isReminded: true });
            });
        }, 60000);
        return () => clearInterval(interval);
    }, [user, allTasks]);

    useEffect(() => { 
        const root = window.document.documentElement; 
        if (preferences.theme === 'dark') root.classList.add('dark'); 
        else root.classList.remove('dark'); 
    }, [preferences.theme]);

    const handleLogin = (loggedInUser: User) => { StorageService.saveUser(loggedInUser); setUser(loggedInUser); };
    const handleLogout = () => { StorageService.logout(); setUser(null); };
    const handleUpdateUser = (updated: User) => { setUser(updated); StorageService.saveUser(updated); setNotification("Profile updated"); };
    const handleTeamUpdate = () => { setUsers(StorageService.getUsers()); };
    const handleUpdateAnnouncements = (updated: Announcement[]) => { setAnnouncements(updated); StorageService.saveAnnouncements(updated); setNotification("Announcements updated"); };
    const handleUpdateTools = (updated: Tool[]) => { setTools(updated); StorageService.saveTools(updated); setNotification("Tools updated"); };
    const handleUpdateAttendanceConfig = (updated: AttendanceConfig) => { setAttendanceConfig(updated); StorageService.saveAttendanceConfig(updated); };
    const handleUpdateHolidays = (updated: Holiday[]) => { setHolidays(updated); StorageService.saveHolidays(updated); };

    const handleAddTask = async (divId: DivisionType, title: string, priority: TaskPriority) => {
        const newTask: Task = { id: crypto.randomUUID(), title, isCompleted: false, priority, creatorId: user?.id || 'unknown', assigneeId: 'unassigned', originDivisionId: divId, targetDivisionId: divId, timestamp: Date.now() };
        setAllTasks(prev => [newTask, ...prev]);
        await UnifiedDataService.addTask(newTask);
        setNotification("Tugas ditambahkan");
    };

    const handleToggleTask = async (divId: DivisionType, taskId: string) => {
        const task = allTasks.find(t => t.id === taskId);
        if (task) {
            const newVal = !task.isCompleted;
            setAllTasks(prev => prev.map(t => t.id === taskId ? { ...t, isCompleted: newVal } : t));
            await UnifiedDataService.updateTask(taskId, { isCompleted: newVal });
        }
    };

    const handleDeleteTask = async (divId: DivisionType, taskId: string) => {
        if(confirm("Hapus tugas?")) {
             setAllTasks(prev => prev.filter(t => t.id !== taskId));
             await UnifiedDataService.deleteTask(taskId);
        }
    };

    const handleUpdateTask = async (divId: DivisionType, taskId: string, updates: Partial<Task>) => {
        setAllTasks(prev => prev.map(t => t.id === taskId ? { ...t, ...updates } : t));
        await UnifiedDataService.updateTask(taskId, updates);
    };

    const handleGlobalTaskSelect = (task: Task) => {
        const divId = task.targetDivisionId || task.originDivisionId;
        const div = DIVISIONS.find(d => d.id === divId);
        setGlobalSelectedTask({ ...task, divId: divId, divName: div?.name, divIcon: div?.icon });
    };

    const handleSendMessage = async (content: string, channelId: string = activeChatChannel) => { 
        if (!user) return; 
        const newMessage: ChatMessage = { id: crypto.randomUUID(), senderId: user.id, senderName: user.name, channelId: channelId, content, timestamp: Date.now() }; 
        setMessages(prev => [...prev, newMessage]);
        await UnifiedDataService.sendMessage(newMessage);
    };

    const handleCreateGroup = async (name: string, members: string[]) => {
        if (!user) return;
        const newGroup: ChatGroup = { id: `grp_${Date.now()}`, name, memberIds: members, createdAt: Date.now(), createdBy: user.id };
        setChatGroups(prev => [...prev, newGroup]);
        await UnifiedDataService.createChatGroup(newGroup);
        setNotification(`Grup "${name}" berhasil dibuat!`);
        setActiveChatChannel(newGroup.id);
    };

    const handleAddTool = (newToolData: any) => { const newTool = { ...newToolData, id: `t_${Date.now()}`, lastAccessed: 0 }; const updated = [...tools, newTool]; handleUpdateTools(updated); StorageService.logActivity('Created Tool', newTool.name); };
    const handleUpdateToolSingle = (updatedData: Partial<Tool>) => { if (!updatedData.id) return; const updatedTools = tools.map(t => t.id === updatedData.id ? { ...t, ...updatedData } : t); handleUpdateTools(updatedTools); setNotification('Tool updated'); StorageService.logActivity('Updated Tool', updatedData.name || 'Unknown Tool'); };

    const handleToolClick = (tool: Tool) => { 
        StorageService.recordAccess(tool.id); 
        setTools(StorageService.getTools()); 
        if (tool.url && tool.url !== '#') {
            window.open(tool.url, '_blank'); 
        } else {
            setNotification("Aplikasi ini masih dalam pengembangan (Draf)");
        }
    };

    const handleToggleSelection = (tool: Tool) => { const toolId = tool.id; const newSet = new Set(selectedToolIds); if (newSet.has(toolId)) newSet.delete(toolId); else newSet.add(toolId); setSelectedToolIds(newSet); setIsSelectionMode(newSet.size > 0); };

    const handleBulkAction = (action: string) => {
        if (selectedToolIds.size === 0) return;
        if (action === 'DELETE' && confirm(`Move ${selectedToolIds.size} items to trash?`)) { 
            const updated = tools.map(t => selectedToolIds.has(t.id) ? { ...t, deletedAt: Date.now() } : t); handleUpdateTools(updated); setNotification("Moved to trash"); setSelectedToolIds(new Set()); setIsSelectionMode(false); 
        } else if (action === 'ARCHIVE') {
            const updatedArch = tools.map(t => selectedToolIds.has(t.id) ? { ...t, isArchived: true } : t); handleUpdateTools(updatedArch); setNotification("Archived"); setSelectedToolIds(new Set()); setIsSelectionMode(false); 
        }
    };

    const handleContextMenu = (e: any, tool: Tool) => { e.preventDefault(); let x = e.touches ? e.touches[0].clientX : e.clientX; let y = e.touches ? e.touches[0].clientY : e.clientY; setContextMenu({ isOpen: true, x, y, toolId: tool.id }); };
    const executeAction = (action: string) => {
        const toolId = contextMenu.toolId; const tool = tools.find(t => t.id === toolId); setContextMenu({ ...contextMenu, isOpen: false }); if (!tool) return;
        if (tool.isLocked && ['EDIT', 'MOVE', 'MIRROR', 'ARCHIVE', 'DELETE'].includes(action)) { setNotification("Tool is locked"); return; }
        switch (action) { case 'OPEN': handleToolClick(tool); break; case 'EDIT': setEditModalOpen(true); break; case 'DELETE': if(confirm("Move to trash?")) { const updated = tools.map(t => t.id === toolId ? { ...t, deletedAt: Date.now() } : t); handleUpdateTools(updated); setNotification("Moved to trash"); } break; case 'MOVE': setActionModal({ isOpen: true, mode: 'move', toolId }); break; case 'MIRROR': setActionModal({ isOpen: true, mode: 'mirror', toolId }); break; case 'TOGGLE_LOCK': const updatedLock = tools.map(t => t.id === toolId ? { ...t, isLocked: !t.isLocked } : t); handleUpdateTools(updatedLock); break; }
    };

    if (!user) return <LoginView onLogin={handleLogin} />;

    return (
        <HashRouter>
            <AppLayout user={user} selectedCount={selectedToolIds.size} onBulkAction={handleBulkAction} onCancelSelection={() => { setSelectedToolIds(new Set()); setIsSelectionMode(false); }} lang={lang} onLogout={handleLogout}>
                {notification && <Toast message={notification} onClose={() => setNotification(null)} />}

                <Routes>
                    <Route path="/" element={
                        <>
                            <ChannelUpdater onUpdate={setActiveChatChannel} />
                            <Dashboard 
                                tools={tools} user={user} handleToolClick={handleToolClick} onContextMenu={handleContextMenu} onSelect={handleToggleSelection} 
                                onAddTool={handleAddTool} setNotification={setNotification} isSelectionMode={isSelectionMode} selectedIds={selectedToolIds} 
                                setSmartAddContext={setSmartAddContext}
                                onOpenAttendance={() => setAttendanceOpen(true)} onOpenProfile={() => setProfileOpen(true)} 
                                lang={lang} todayAttendance={StorageService.getTodayAttendance(user.id)} unreadAnnouncements={announcements.length} 
                                tasks={allTasks} 
                                announcements={announcements} messages={messages} onSendMessage={(msg) => handleSendMessage(msg)}
                                dashboardDivisions={dashboardDivisions}
                                onAddTask={handleAddTask} 
                                onToggleTask={handleToggleTask} 
                                onDeleteTask={handleDeleteTask}
                                onUpdateTask={handleUpdateTask}
                                activeChannel={activeChatChannel} onChangeChannel={setActiveChatChannel}
                                groups={chatGroups}
                                allUsers={users} 
                            />
                        </>
                    } />
                    <Route path="/division/:id" element={
                        <>
                            <ChannelUpdater onUpdate={setActiveChatChannel} />
                            <DivisionView 
                                tools={tools} user={user} handleToolClick={handleToolClick} onContextMenu={handleContextMenu} onSelect={handleToggleSelection} 
                                onAddTool={(divId) => setSmartAddContext(divId)} 
                                isSelectionMode={isSelectionMode} selectedIds={selectedToolIds} 
                                onOpenChat={(divId) => { setActiveChatChannel(divId); }} 
                                onOpenDivisionTasks={(divId) => {}}
                                lang={lang} 
                                tasks={allTasks}
                                onAddTask={handleAddTask} 
                                onToggleTask={handleToggleTask} 
                                onDeleteTask={handleDeleteTask}
                                onUpdateTask={handleUpdateTask}
                                messages={messages} 
                                onSendMessage={handleSendMessage} 
                            />
                        </>
                    } />
                    <Route path="/messages" element={
                        <Messages 
                            user={user}
                            messages={messages}
                            onSendMessage={handleSendMessage}
                            groups={chatGroups}
                            onCreateGroup={handleCreateGroup}
                        />
                    } />
                    <Route path="/documents" element={<DocumentsView user={user} />} />
                    <Route path="/inventory" element={<InventoryView user={user} />} />
                    <Route path="/finance" element={<FinanceView user={user} />} />
                    <Route path="/settings" element={
                        <SettingsView 
                            user={user} 
                            onUpdateUser={handleUpdateUser} 
                            tools={tools} 
                            onUpdateTools={handleUpdateTools} 
                            announcements={announcements} 
                            onUpdateAnnouncements={handleUpdateAnnouncements} 
                            attendanceConfig={attendanceConfig} 
                            onUpdateAttendanceConfig={handleUpdateAttendanceConfig} 
                            holidays={holidays} 
                            onUpdateHolidays={handleUpdateHolidays}
                            onTeamUpdate={handleTeamUpdate} 
                        />
                    } />
                </Routes>

                <QuickCommand 
                    isOpen={isQuickCommandOpen} 
                    onClose={() => setQuickCommandOpen(false)} 
                    tools={tools} 
                    users={users} 
                    divisions={DIVISIONS}
                    tasks={allTasks}
                    onTaskSelect={handleGlobalTaskSelect}
                />

                <AIAssistant 
                    tasks={allTasks} 
                    users={users} 
                    announcements={announcements} 
                />

                {globalSelectedTask && (
                    <TaskDetailView 
                        task={globalSelectedTask} 
                        isOpen={!!globalSelectedTask} 
                        onClose={() => setGlobalSelectedTask(null)} 
                        onToggle={() => handleToggleTask(globalSelectedTask.divId as DivisionType, globalSelectedTask.id)} 
                        onDelete={() => { handleDeleteTask(globalSelectedTask.divId as DivisionType, globalSelectedTask.id); setGlobalSelectedTask(null); }} 
                        onUpdate={(updates) => handleUpdateTask(globalSelectedTask.divId as DivisionType, globalSelectedTask.id, updates)} 
                    />
                )}

                {contextMenu.isOpen && (<ContextMenu x={contextMenu.x} y={contextMenu.y} isLocked={!!tools.find(t => t.id === contextMenu.toolId)?.isLocked} onClose={() => setContextMenu({ ...contextMenu, isOpen: false })} onOpen={() => executeAction('OPEN')} onEdit={() => executeAction('EDIT')} onMove={() => executeAction('MOVE')} onMirror={() => executeAction('MIRROR')} onArchive={() => executeAction('ARCHIVE')} onDelete={() => executeAction('DELETE')} onToggleLock={() => executeAction('TOGGLE_LOCK')} />)}
                <AddToolModal isOpen={isEditModalOpen} onClose={() => setEditModalOpen(false)} onSave={handleUpdateToolSingle} initialData={tools.find(t => t.id === contextMenu.toolId)} />
                <SmartAddModal isOpen={!!smartAddContext} onClose={() => setSmartAddContext(null)} onAdd={(tool) => handleAddTool(tool)} divisionName={smartAddContext || ''} />
                <ToolActionModal isOpen={actionModal.isOpen} mode={actionModal.mode} onClose={() => setActionModal({ ...actionModal, isOpen: false })} onConfirm={(div, cat) => { const updated = tools.map(t => t.id === actionModal.toolId ? { ...t, divisionId: div, category: cat } : t); if (actionModal.mode === 'mirror') { const original = tools.find(t => t.id === actionModal.toolId); if(original) updated.push({ ...original, id: `t_${Date.now()}`, divisionId: div, category: cat }); } handleUpdateTools(updated); setActionModal({ ...actionModal, isOpen: false }); setNotification("Action successful"); StorageService.logActivity(actionModal.mode === 'mirror' ? 'Mirror Tool' : 'Move Tool', tools.find(t => t.id === actionModal.toolId)?.name || 'Unknown'); }} />
                <AttendanceModal isOpen={isAttendanceOpen} onClose={() => setAttendanceOpen(false)} user={user} />
                <ProfileModal isOpen={isProfileOpen} onClose={() => setProfileOpen(false)} user={user} onUpdateUser={handleUpdateUser} announcements={announcements} onLogout={handleLogout} />
            </AppLayout>
        </HashRouter>
    );
};

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { DivisionData, ChatMessage, Announcement, User, TaskPriority, Task, UserPreferences, UserRole, ChatGroup } from '../types';
import { Icon } from './Icon';
import { GeminiService } from '../services/geminiService';
import { NotificationService } from '../services/notificationService';
import { StorageService } from '../services/storageService';
import { UnifiedDataService } from '../services/UnifiedDataService';
import { DIVISIONS } from '../constants';
import { TaskItem } from './TaskItem';
import { TaskDetailView } from './TaskDetailView';
import { BulkImportModal } from './BulkImportModal';

interface CollaborationPanelProps {
  isOpen: boolean;
  onClose: () => void;
  user: User;
  divisions: DivisionData[];
  onToggleTask: (divisionId: any, taskId: string) => void;
  onAddTask: (divisionId: any, text: string, priority: any, dueDate: string) => void;
  onDeleteTask: (divisionId: any, taskId: string) => void;
  announcements: Announcement[];
  messages: ChatMessage[];
  onSendMessage: (content: string, channelId: string) => void;
  activeChannel: string;
  onChangeChannel: (id: string) => void;
  initialTab?: 'tasks' | 'discussion';
  onUpdateTask?: (divisionId: any, taskId: string, updates: Partial<Task>) => void;
  groups?: ChatGroup[];
}

const ChatColumn: React.FC<{
    col: { id: string; name: string; icon: string; color: string };
    messages: ChatMessage[];
    user: User;
    inputValue: string;
    onInputChange: (val: string) => void;
    onSend: (e: React.FormEvent) => void;
    onFocus: () => void;
}> = ({ col, messages, user, inputValue, onInputChange, onSend, onFocus }) => {
    const lastMsgRef = useRef<HTMLDivElement>(null);
    useEffect(() => { lastMsgRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages.length]);
    return (
        <div className="flex flex-col w-80 min-w-[320px] h-full max-h-full glass-card rounded-2xl border border-white/5 bg-black/20 shrink-0">
            <div className={`p-3 border-b border-white/5 bg-white/5 flex items-center justify-between`}>
                <div className="flex items-center gap-2 font-bold text-gray-200 text-sm truncate">
                    <div className={`p-1.5 rounded-md ${col.color} text-white`}><Icon name={col.icon} size={14} /></div>
                    {col.name}
                </div>
                <span className="bg-black/30 px-2 py-0.5 rounded text-[10px] text-gray-400">{messages.length}</span>
            </div>
            <div className="flex-1 overflow-y-auto p-3 space-y-3 custom-scrollbar">
                {messages.length === 0 && <p className="text-center text-[10px] text-gray-600 italic mt-10">No messages yet.</p>}
                {messages.map(msg => {
                    const isMe = msg.senderId === user.id;
                    return (
                        <div key={msg.id} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'}`}>
                            <div className={`max-w-[90%] rounded-xl px-3 py-2 text-xs shadow-sm ${isMe ? 'bg-brand-600 text-white' : 'bg-[#1e293b] text-gray-200 border border-white/10'}`}>
                                {!isMe && <p className="text-[9px] font-bold text-brand-400 mb-0.5 truncate">{msg.senderName}</p>}
                                <p className="whitespace-pre-wrap leading-tight">{msg.content}</p>
                            </div>
                            <span className="text-[9px] text-gray-600 mt-1 px-1">{new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                        </div>
                    );
                })}
                <div ref={lastMsgRef} />
            </div>
            <div className="p-3 border-t border-white/5 bg-black/20">
                <form onSubmit={onSend} className="flex gap-2">
                    <input value={inputValue} onChange={(e) => onInputChange(e.target.value)} onFocus={onFocus} className="flex-1 bg-black/40 border border-white/10 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-brand-500 transition-colors" placeholder="Reply..." />
                    <button type="submit" disabled={!inputValue?.trim()} className="bg-brand-600 hover:bg-brand-500 text-white p-2 rounded-lg transition-colors disabled:opacity-50"><Icon name="Send" size={14} /></button>
                </form>
            </div>
        </div>
    );
};

const DivisionColumn: React.FC<{
    division: DivisionData; tasks: Task[]; onToggle: (taskId: string) => void; onSelect: (taskId: string) => void; onDelete: (taskId: string) => void; onDiscuss: (title: string) => void; onWhatsApp: (task: Task) => void; onReminder: (task: Task) => void; onQuickAdd: (text: string) => void;
}> = ({ division, tasks, onToggle, onSelect, onDelete, onDiscuss, onWhatsApp, onReminder, onQuickAdd }) => {
    const [isAdding, setIsAdding] = useState(false);
    const [quickInput, setQuickInput] = useState('');
    const handleSubmit = (e: React.FormEvent) => { e.preventDefault(); if(!quickInput.trim()) return; onQuickAdd(quickInput); setQuickInput(''); setIsAdding(false); }
    return (
        <div className="flex flex-col w-80 min-w-[320px] h-full max-h-full glass-card rounded-2xl border border-white/5 bg-black/20 shrink-0">
             <div className="p-4 border-b border-white/5 bg-white/5 flex justify-between items-center"><div className="flex items-center gap-2 font-bold text-gray-200"><Icon name={division.icon} size={16} className="text-brand-400" /><span className="text-sm truncate">{division.name}</span></div><span className="bg-black/30 px-2 py-0.5 rounded text-xs text-gray-400 font-mono">{tasks.filter(t => !t.isCompleted).length}</span></div>
            <div className="flex-1 overflow-y-auto p-3 space-y-3 custom-scrollbar">
                {tasks.length === 0 && <div className="text-center py-10 text-gray-600 text-xs italic border-2 border-dashed border-white/5 rounded-xl">No active tasks</div>}
                {tasks.map(task => (<div key={task.id}><TaskItem task={task} onToggle={() => onToggle(task.id)} onSelect={() => onSelect(task.id)} onDelete={() => onDelete(task.id)} onDiscuss={() => onDiscuss(task.title)} onWhatsApp={() => onWhatsApp(task)} onReminder={() => onReminder(task)} /></div>))}
            </div>
            <div className="p-3 border-t border-white/5 bg-black/20">{isAdding ? (<form onSubmit={handleSubmit} className="flex flex-col gap-2 animate-[fadeIn_0.2s]"><input autoFocus className="w-full bg-black/40 border border-white/10 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-brand-500" placeholder="Task title..." value={quickInput} onChange={e => setQuickInput(e.target.value)} onBlur={() => !quickInput && setIsAdding(false)} /><div className="flex gap-2"><button type="submit" className="flex-1 bg-brand-600 hover:bg-brand-500 text-white py-1.5 rounded-lg text-xs font-bold transition-colors">Add</button><button type="button" onClick={() => setIsAdding(false)} className="px-3 py-1.5 bg-white/5 hover:bg-white/10 text-gray-400 rounded-lg text-xs transition-colors">Cancel</button></div></form>) : (<button onClick={() => setIsAdding(true)} className="w-full py-2 flex items-center justify-center gap-2 text-xs font-bold text-gray-400 hover:text-white hover:bg-white/5 rounded-lg transition-all border border-transparent hover:border-white/10"><Icon name="Plus" size={14} /> Quick Add to {division.name}</button>)}</div>
        </div>
    )
}

export const CollaborationPanel: React.FC<CollaborationPanelProps> = ({
    isOpen, onClose, user, divisions, onToggleTask, onAddTask, onDeleteTask,
    announcements, messages, onSendMessage, activeChannel, onChangeChannel,
    initialTab = 'tasks', onUpdateTask, groups = []
}) => {
    // --- STATE MANAGEMENT ---
    const [activeMainTab, setActiveMainTab] = useState<'tasks' | 'discussion' | 'analytics'>('tasks');
    const [activeChatTab, setActiveChatTab] = useState<'announcements' | 'chat'>('announcements');
    const [isExpanded, setIsExpanded] = useState(false);
    const [taskViewMode, setTaskViewMode] = useState<'list' | 'board'>('board');
    const [tasksDisplayMode, setTasksDisplayMode] = useState<'folder' | 'list'>('folder');
    const [inputMode, setInputMode] = useState<'single' | 'bulk'>('single');
    const [newTaskText, setNewTaskText] = useState('');
    const [targetDivision, setTargetDivision] = useState<string>('AUTO');
    const [targetPriority, setTargetPriority] = useState<TaskPriority>('medium');
    const [isAIGenerating, setIsAIGenerating] = useState(false);
    const [isBulkModalOpen, setIsBulkModalOpen] = useState(false);
    const [expandedDivisions, setExpandedDivisions] = useState<Set<string>>(new Set());
    const [selectedTask, setSelectedTask] = useState<(Task & { divName?: string, divIcon?: string, description?: string, divId?: string }) | null>(null);
    const [msgInput, setMsgInput] = useState('');
    const [chatContext, setChatContext] = useState<string | null>(null);
    const chatEndRef = useRef<HTMLDivElement>(null);
    const [columnInputs, setColumnInputs] = useState<Record<string, string>>({});
    const [prefs, setPrefs] = useState<UserPreferences>(StorageService.getPreferences());

    // Voice & Reporting States
    const [isListening, setIsListening] = useState(false);
    const [isSendingReport, setIsSendingReport] = useState(false);

    const allUsers = StorageService.getUsers();

    useEffect(() => { if (isOpen) { setActiveMainTab(initialTab === 'discussion' ? 'discussion' : 'tasks'); setPrefs(StorageService.getPreferences()); } }, [isOpen, initialTab]);

    // --- FILTER LOGIC (Strict Access Control) ---
    const visibleDivisions = useMemo(() => {
        if (user.role === UserRole.ADMIN) return divisions;
        return divisions.filter(d => d.id === user.division);
    }, [user, divisions]);

    const myGroups = useMemo(() => groups.filter(g => g.memberIds.includes(user.id) || g.createdBy === user.id), [groups, user.id]);

    type FlatTask = Task & { divName: string; divId: string; divIcon: string };

    const allFlatTasks = useMemo<FlatTask[]>(() => {
        const flat: FlatTask[] = [];
        divisions.forEach(div => {
            div.tasks.forEach(t => {
                const isRelevant = user.role === UserRole.ADMIN || div.id === user.division || t.originDivisionId === user.division;
                if (isRelevant) {
                    flat.push({ ...t, divName: div.name, divId: div.id, divIcon: div.icon });
                }
            });
        });
        return flat.sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0));
    }, [divisions, user]);

    const activeChannelId = activeChannel;
    const filteredMessages = useMemo(() => messages.filter((m) => m.channelId === activeChannelId), [messages, activeChannelId]);
    useEffect(() => { if (isOpen && activeMainTab === 'discussion' && activeChatTab === 'chat' && !isExpanded) { chatEndRef.current?.scrollIntoView({ behavior: 'smooth' }); } }, [isOpen, activeMainTab, activeChatTab, filteredMessages.length, chatContext, isExpanded]);

    const getChannelName = (id: string) => {
        if (id === 'GENERAL') return '🌐 Umum / Semua Tim';
        const division = DIVISIONS.find(d => d.id === id);
        if (division) return `🔒 Divisi ${division.name}`;
        const group = groups.find(g => g.id === id);
        if (group) return `# ${group.name}`;
        if (id.includes('_') && !id.startsWith('grp_')) {
            const parts = id.split('_');
            const otherUserId = parts.find(p => p !== user.id);
            const otherUser = allUsers.find(u => u.id === otherUserId);
            return otherUser ? `👤 ${otherUser.name}` : 'Private Message';
        }
        return id;
    };

    const myDMs = useMemo(() => {
        const dmChannels = new Set<string>();
        messages.forEach(msg => {
            if (msg.channelId.includes('_') && !msg.channelId.startsWith('grp_')) {
                const parts = msg.channelId.split('_');
                if (parts.includes(user.id)) dmChannels.add(msg.channelId);
            }
        });
        return Array.from(dmChannels);
    }, [messages, user.id]);

    const handleSingleSubmit = async () => {
        if (!newTaskText.trim()) return;
        if (targetDivision === 'BROADCAST') { DIVISIONS.forEach(div => { onAddTask(div.id, newTaskText, targetPriority, ''); }); setNewTaskText(''); return; }
        let finalDiv = targetDivision; let finalTitle = newTaskText; let finalPriority = targetPriority;
        if (targetDivision === 'AUTO') {
            setIsAIGenerating(true);
            try {
                const result = await GeminiService.parseBulkTasks(newTaskText);
                if (result && result.length > 0) {
                    const aiResult = result[0];
                    if (aiResult.divisionId === 'BROADCAST') { DIVISIONS.forEach(div => onAddTask(div.id, aiResult.title || newTaskText, aiResult.priority as TaskPriority || 'medium', '')); setNewTaskText(''); setIsAIGenerating(false); return; }
                    finalDiv = aiResult.divisionId || user.division; finalTitle = aiResult.title || newTaskText; finalPriority = (aiResult.priority as TaskPriority) || 'medium';
                } else { finalDiv = user.division; }
            } catch (e) { finalDiv = user.division; } finally { setIsAIGenerating(false); }
        }
        onAddTask(finalDiv, finalTitle, finalPriority, '');
        setNewTaskText('');
    };

    const handleBulkConfirm = (tasks: any[]) => { 
        tasks.forEach(t => { 
            if (t.divisionId === 'BROADCAST') { 
                DIVISIONS.forEach(div => { onAddTask(div.id, t.title, t.priority || 'medium', t.dueDate || ''); }); 
            } else { 
                onAddTask(t.divisionId || 'Administrasi', t.title, t.priority || 'medium', t.dueDate || ''); 
            } 
        }); 
    };

    const handleVoiceInput = () => {
        if (!('webkitSpeechRecognition' in window) && !('SpeechRecognition' in window)) { alert("Browser tidak mendukung Input Suara."); return; }
        if (isListening) return;
        const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
        const recognition = new SpeechRecognition();
        recognition.lang = 'id-ID';
        recognition.onstart = () => { setIsListening(true); };
        recognition.onresult = (event: any) => { const transcript = event.results[0][0].transcript; setNewTaskText(prev => (prev + ' ' + transcript).trim()); };
        recognition.onend = () => { setIsListening(false); };
        recognition.start();
    };

    const handleDailyReport = async () => { setIsSendingReport(true); try { const result = await NotificationService.sendDailyReport(allFlatTasks, user, prefs); alert(result.success ? result.detail : "Gagal: " + result.detail); } catch (e) { alert("Error."); } finally { setIsSendingReport(false); } };
    const toggleDivision = (id: string) => { const newSet = new Set(expandedDivisions); if (newSet.has(id)) newSet.delete(id); else newSet.add(id); setExpandedDivisions(newSet); };
    const handleDiscussTask = (taskText: string, divisionId: string) => { setActiveMainTab('discussion'); setActiveChatTab('chat'); if (divisionId !== 'GENERAL' && DIVISIONS.some(d => d.id === divisionId)) onChangeChannel(divisionId); setChatContext(taskText); setMsgInput(""); if(isExpanded) setIsExpanded(false); };
    const handleSendChat = (e: React.FormEvent) => { e.preventDefault(); if (!msgInput.trim()) return; const finalMessage = chatContext ? `[Membahas: ${chatContext}]\n${msgInput}` : msgInput; onSendMessage(finalMessage, activeChannel); setMsgInput(''); setChatContext(null); };
    const handleMultiChatSend = (e: React.FormEvent, channelId: string) => { e.preventDefault(); const content = columnInputs[channelId]; if (!content?.trim()) return; onSendMessage(content, channelId); setColumnInputs(prev => ({ ...prev, [channelId]: '' })); onChangeChannel(channelId); };
    const handleWhatsApp = (task: Task) => NotificationService.sendToWhatsApp(task, prefs);
    const handleSetReminder = (divId: string, task: Task) => { const choice = prompt("Set Reminder (menit)?", "15"); if (choice && onUpdateTask) { const delay = parseInt(choice) * 60 * 1000; if (delay > 0) { onUpdateTask(divId, task.id, { reminderAt: Date.now() + delay, isReminded: false }); alert(`Pengingat diset.`); NotificationService.requestPermission(); }}};
    const handleSelectTask = (taskId: string) => { const found = allFlatTasks.find(t => t.id === taskId); if (found) setSelectedTask(found); };

    const renderAnalytics = () => {
        const total = allFlatTasks.length;
        const completed = allFlatTasks.filter(t => t.isCompleted).length;
        return (
            <div className="p-8 space-y-8 animate-[fadeIn_0.5s]">
                 <div className="bg-gradient-to-r from-indigo-900/40 to-purple-900/40 border border-indigo-500/30 p-6 rounded-2xl flex items-start gap-4 relative overflow-hidden"><div className="p-3 bg-indigo-500/20 rounded-xl text-indigo-300 shadow-inner shrink-0"><Icon name="Sparkles" size={24} /></div><div><h4 className="text-indigo-200 font-bold mb-1">AI Insight</h4><p className="text-indigo-100/70 text-sm">Team has {total} tasks, {completed} completed.</p></div></div>
                <div className="grid grid-cols-2 gap-4"><div className="glass-card p-5 rounded-2xl border-l-4 border-l-blue-500"><p className="text-xs text-gray-400 font-bold uppercase">Total</p><p className="text-3xl font-bold text-white">{total}</p></div><div className="glass-card p-5 rounded-2xl border-l-4 border-l-emerald-500"><p className="text-xs text-gray-400 font-bold uppercase">Done</p><p className="text-3xl font-bold text-emerald-400">{completed}</p></div></div>
            </div>
        )
    };

    const renderKanbanChat = () => {
        const columns = [ { id: 'GENERAL', name: '📢 GENERAL', icon: 'Megaphone', color: 'bg-indigo-500' }, ...visibleDivisions.map(d => ({ id: d.id, name: d.name, icon: d.icon, color: 'bg-gray-700' })), ...myGroups.map(g => ({ id: g.id, name: g.name, icon: 'Users', color: 'bg-emerald-600' })) ];
        return (<div className="flex gap-4 h-full p-6 overflow-x-auto items-start">{columns.map(col => (<ChatColumn key={col.id} col={col} messages={messages.filter(m => m.channelId === col.id)} user={user} inputValue={columnInputs[col.id] || ''} onInputChange={(val) => setColumnInputs(prev => ({ ...prev, [col.id]: val }))} onSend={(e) => handleMultiChatSend(e, col.id)} onFocus={() => onChangeChannel(col.id)} />))}</div>);
    };

    const renderDivisionBoard = () => {
        return (<div className="flex gap-4 h-full p-6 overflow-x-auto items-start">{visibleDivisions.map(div => (<DivisionColumn key={div.id} division={div} tasks={div.tasks.filter(t => !t.isCompleted)} onToggle={(tid) => onToggleTask(div.id, tid)} onSelect={(tid) => handleSelectTask(tid)} onDelete={(tid) => onDeleteTask(div.id, tid)} onDiscuss={(title) => handleDiscussTask(title, div.id)} onWhatsApp={handleWhatsApp} onReminder={(t) => handleSetReminder(div.id, t)} onQuickAdd={(text) => onAddTask(div.id, text, 'medium', '')} />))}</div>)
    };

    return (
        <div className={`fixed transition-all duration-500 ease-in-out bg-[#0f172a]/95 backdrop-blur-xl shadow-2xl z-[90] flex flex-col ${isExpanded ? 'inset-0 w-full' : `inset-y-0 right-0 w-full md:w-[420px] ${isOpen ? 'translate-x-0' : 'translate-x-full'}`} ${!isOpen && !isExpanded ? 'translate-x-full' : ''}`}>
            {/* HEADER TABS */}
            <div className="flex h-16 border-b border-white/10 shrink-0 bg-black/20 relative items-center px-2">
                <div className="flex-1 flex gap-1">
                    <button onClick={() => setActiveMainTab('tasks')} className={`flex-1 py-2 flex items-center justify-center gap-2 font-bold text-xs md:text-sm tracking-wide transition-all rounded-lg ${activeMainTab === 'tasks' ? 'bg-brand-600 text-white shadow-lg' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}><Icon name="Layout" size={16} /> TASKS</button>
                    <button onClick={() => setActiveMainTab('analytics')} className={`flex-1 py-2 flex items-center justify-center gap-2 font-bold text-xs md:text-sm tracking-wide transition-all rounded-lg ${activeMainTab === 'analytics' ? 'bg-brand-600 text-white shadow-lg' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}><Icon name="BarChart2" size={16} /> ANALYTICS</button>
                    <button onClick={() => setActiveMainTab('discussion')} className={`flex-1 py-2 flex items-center justify-center gap-2 font-bold text-xs md:text-sm tracking-wide transition-all rounded-lg ${activeMainTab === 'discussion' ? 'bg-brand-600 text-white shadow-lg' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}><Icon name="MessageSquare" size={16} /> DISCUSS</button>
                </div>
                <div className="flex items-center gap-1 ml-2 border-l border-white/10 pl-2">
                    {activeMainTab !== 'analytics' && (<button onClick={() => setIsExpanded(!isExpanded)} className={`p-2 hover:bg-white/10 rounded-lg text-gray-400 hover:text-brand-400 transition-colors ${isExpanded ? 'bg-white/10 text-white' : ''}`}><Icon name={isExpanded ? "Minimize2" : "Maximize2"} size={18} /></button>)}
                    <button onClick={onClose} className="p-2 bg-red-500/10 hover:bg-red-500 rounded-lg text-red-400 hover:text-white transition-colors ml-1"><Icon name="X" size={18} /></button>
                </div>
            </div>

            <div className="flex-1 overflow-hidden flex flex-col relative bg-gradient-to-br from-gray-900 to-[#0b1120]">
                {activeMainTab === 'analytics' && (<div className="flex-1 overflow-y-auto custom-scrollbar">{renderAnalytics()}</div>)}
                {activeMainTab === 'tasks' && (
                    <div className="flex-1 flex flex-col animate-[fadeIn_0.2s] overflow-hidden relative">
                        {/* INPUT HEADER */}
                        <div className="p-5 border-b border-white/10 bg-[#0f172a]/80 backdrop-blur-md shadow-xl z-30 shrink-0">

                            {/* AI / Manual Switch */}
                            <div className="flex bg-black/40 p-1 rounded-xl mb-4 border border-white/5">
                                <button className={`flex-1 py-2 rounded-lg text-xs font-bold flex items-center justify-center gap-2 transition-all bg-white/10 text-white shadow-sm`}><Icon name="PenTool" size={14} /> 🖊️ Task Input</button>
                                <button onClick={() => setIsBulkModalOpen(true)} className="flex-1 py-2 rounded-lg text-xs font-bold flex items-center justify-center gap-2 transition-all text-gray-500 hover:text-white"><Icon name="Sparkles" size={14} /> ✨ Bulk Import</button>
                            </div>

                            <div className="flex items-center justify-between mb-3 px-1">
                                <button onClick={handleDailyReport} disabled={isSendingReport} className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wider border transition-all ${isSendingReport ? 'bg-green-500/20 border-green-500/30 text-green-300' : 'bg-green-600 hover:bg-green-500 text-white border-transparent'}`}>{isSendingReport ? <Icon name="Loader2" size={12} className="animate-spin"/> : <Icon name="Megaphone" size={12}/>}{isSendingReport ? 'Mengirim...' : '📢 Lapor Harian'}</button>
                            </div>

                            <div className="space-y-3 animate-[fadeIn_0.2s]">
                                <div className="relative group">
                                    <input 
                                        className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 pr-12 text-sm text-white focus:ring-1 focus:ring-brand-500 outline-none transition-all placeholder-gray-500" 
                                        placeholder="Ketik tugas atau klik mic..." 
                                        value={newTaskText} 
                                        onChange={e => setNewTaskText(e.target.value)} 
                                        onKeyDown={e => { if(e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSingleSubmit(); }}} 
                                    />
                                    <div className="absolute right-2 top-1/2 -translate-y-1/2 flex items-center gap-1">
                                        {isAIGenerating && <Icon name="Loader2" size={16} className="text-purple-400 animate-spin mr-2" />}
                                        <button onClick={handleVoiceInput} className={`p-2 rounded-lg transition-colors ${isListening ? 'bg-red-500 text-white animate-pulse' : 'text-gray-400 hover:bg-white/10 hover:text-white'}`}><Icon name={isListening ? "MicOff" : "Mic"} size={18} /></button>
                                    </div>
                                </div>
                                <div className="flex gap-2">
                                    <div className="relative flex-1"><select value={targetDivision} onChange={e => setTargetDivision(e.target.value)} className="w-full bg-black/40 border border-white/10 rounded-xl pl-3 pr-8 py-2 text-xs text-white outline-none cursor-pointer hover:bg-white/5"><option value="AUTO">✨ Auto (AI)</option><option value="BROADCAST">📢 Broadcast All</option>{DIVISIONS.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select><Icon name="ChevronDown" size={12} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none"/></div>
                                    <div className="relative w-28"><select value={targetPriority} onChange={e => setTargetPriority(e.target.value as TaskPriority)} className="w-full bg-black/40 border border-white/10 rounded-xl pl-3 pr-8 py-2 text-xs text-white outline-none cursor-pointer hover:bg-white/5"><option value="low">Low</option><option value="medium">Normal</option><option value="high">Urgent</option></select><Icon name="ChevronDown" size={12} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none"/></div>
                                    <button onClick={handleSingleSubmit} disabled={isAIGenerating || !newTaskText.trim()} className="bg-brand-600 hover:bg-brand-500 text-white px-4 rounded-xl shadow-lg shadow-brand-500/20 transition-all active:scale-95 flex items-center justify-center gap-2 text-xs font-bold"><Icon name="Plus" size={16}/> ADD</button>
                                </div>
                            </div>

                            {!isExpanded && (<div className="mt-4 flex bg-black/40 p-1 rounded-xl border border-white/5"><button onClick={() => setTasksDisplayMode('folder')} className={`flex-1 py-1.5 rounded-lg text-[10px] font-bold uppercase transition-all flex items-center justify-center gap-2 ${tasksDisplayMode === 'folder' ? 'bg-white/10 text-white shadow-sm' : 'text-gray-500 hover:text-white'}`}><Icon name="Folder" size={12}/> Folders</button><button onClick={() => setTasksDisplayMode('list')} className={`flex-1 py-1.5 rounded-lg text-[10px] font-bold uppercase transition-all flex items-center justify-center gap-2 ${tasksDisplayMode === 'list' ? 'bg-white/10 text-white shadow-sm' : 'text-gray-500 hover:text-white'}`}><Icon name="List" size={12}/> All Tasks</button></div>)}
                        </div>
                        <div className="flex-1 overflow-y-auto custom-scrollbar p-5 space-y-4 bg-black/10">
                            {isExpanded && taskViewMode === 'board' ? renderDivisionBoard() : (
                                <>
                                    {tasksDisplayMode === 'folder' && visibleDivisions.map(div => (<div key={div.id} className="bg-white/5 border border-white/5 rounded-2xl overflow-hidden shadow-sm hover:shadow-md transition-all"><button onClick={() => toggleDivision(div.id)} className="w-full flex justify-between items-center p-4 hover:bg-white/5 transition-colors"><div className="flex items-center gap-3"><div className="p-1.5 bg-gray-800 rounded-lg text-gray-300"><Icon name={div.icon} size={16}/></div><span className="text-sm font-bold text-gray-200">{div.name}</span></div><div className="flex items-center gap-3">{div.tasks.filter(t => !t.isCompleted).length > 0 && <span className="bg-brand-500 text-white text-[10px] font-bold px-2 py-0.5 rounded-full">{div.tasks.filter(t => !t.isCompleted).length}</span>}<Icon name="ChevronDown" size={16} className={`text-gray-500 transition-transform duration-300 ${expandedDivisions.has(div.id) ? 'rotate-180' : ''}`} /></div></button>{expandedDivisions.has(div.id) && (<div className="p-4 pt-0 space-y-3 bg-black/10 border-t border-white/5 animate-[fadeIn_0.2s]"><div className="h-2"></div>{div.tasks.length === 0 && <p className="text-center text-xs text-gray-500 italic py-2">No tasks yet.</p>}{div.tasks.map(task => (<div key={task.id}><TaskItem task={task} onToggle={() => onToggleTask(div.id, task.id)} onSelect={() => handleSelectTask(task.id)} onDelete={() => onDeleteTask(div.id, task.id)} onDiscuss={() => handleDiscussTask(task.title, div.id)} onWhatsApp={() => handleWhatsApp(task)} onReminder={() => handleSetReminder(div.id, task)} /></div>))}</div>)}</div>))}
                                    {tasksDisplayMode === 'list' && (<div className="space-y-4">{allFlatTasks.length === 0 && (<div className="text-center py-10 text-gray-500 opacity-50"><Icon name="CheckSquare" size={48} className="mx-auto mb-2"/><p>No tasks found.</p></div>)}{allFlatTasks.map(task => (<div key={task.id}><TaskItem task={task} showDivisionBadge={true} divisionName={task.divName} divisionIcon={task.divIcon} onToggle={() => onToggleTask(task.divId, task.id)} onSelect={() => handleSelectTask(task.id)} onDelete={() => onDeleteTask(task.divId, task.id)} onDiscuss={() => handleDiscussTask(task.title, task.divId)} onWhatsApp={() => handleWhatsApp(task)} onReminder={() => handleSetReminder(task.divId, task)} /></div>))}</div>)}
                                </>
                            )}
                        </div>
                        {selectedTask && (
                            <TaskDetailView 
                                task={selectedTask} 
                                isOpen={!!selectedTask} 
                                onClose={() => setSelectedTask(null)} 
                                onToggle={() => onToggleTask(selectedTask.divId || selectedTask.originDivisionId, selectedTask.id)} 
                                onDelete={() => { onDeleteTask(selectedTask.divId || selectedTask.originDivisionId, selectedTask.id); setSelectedTask(null); }} 
                                onUpdate={(updates) => onUpdateTask && onUpdateTask(selectedTask.divId || selectedTask.originDivisionId, selectedTask.id, updates)} 
                            />
                        )}
                    </div>
                )}
                {activeMainTab === 'discussion' && (
                     <div className="flex flex-col h-full animate-[fadeIn_0.2s] overflow-hidden">
                        <div className="flex p-3 gap-2 shrink-0 bg-black/20 border-b border-white/5"><button onClick={() => setActiveChatTab('announcements')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition-colors ${activeChatTab === 'announcements' ? 'bg-white/10 text-white border border-white/10' : 'text-gray-500 hover:text-gray-300'}`}>Announcements</button><button onClick={() => setActiveChatTab('chat')} className={`flex-1 py-2 text-xs font-bold rounded-lg transition-colors ${activeChatTab === 'chat' ? 'bg-white/10 text-white border border-white/10' : 'text-gray-500 hover:text-gray-300'}`}>Chat</button></div>
                         {activeChatTab === 'chat' && (
                            <div className="flex-1 flex flex-col min-h-0 overflow-hidden">
                                {isExpanded ? (
                                    <div className="flex-1 overflow-hidden relative">{renderKanbanChat()}</div>
                                ) : (
                                    <>
                                        <div className="p-3 border-b border-white/5 bg-white/5">
                                            <select className="w-full bg-black/40 border border-white/10 text-white text-xs rounded-lg px-3 py-2 outline-none" value={activeChannelId} onChange={(e) => onChangeChannel(e.target.value)}>
                                                <option value="GENERAL">🌐 Umum / Semua Tim</option>
                                                <optgroup label="Divisi Spesifik">{visibleDivisions.map((d) => (<option key={d.id} value={d.id}>🔒 {d.name}</option>))}</optgroup>
                                                {myGroups.length > 0 && <optgroup label="Grup Saya">{myGroups.map(g => (<option key={g.id} value={g.id}># {g.name}</option>))}</optgroup>}
                                                {myDMs.length > 0 && <optgroup label="Pesan Pribadi">{myDMs.map(id => (<option key={id} value={id}>{getChannelName(id)}</option>))}</optgroup>}
                                            </select>
                                        </div>
                                        <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                                            {filteredMessages.map((msg) => (
                                                <div key={msg.id} className={`flex flex-col ${msg.senderId === user.id ? 'items-end' : 'items-start'}`}>
                                                    <div className={`max-w-[85%] rounded-xl px-3 py-2 text-xs ${msg.senderId === user.id ? 'bg-brand-600 text-white' : 'bg-[#1e293b] text-gray-200 border border-white/10'}`}>
                                                        {msg.senderId !== user.id && <p className="text-[9px] font-bold text-brand-400 mb-0.5">{msg.senderName}</p>}
                                                        <p>{msg.content}</p>
                                                    </div>
                                                </div>
                                            ))}
                                            <div ref={chatEndRef} />
                                        </div>
                                        <div className="p-3 border-t border-white/5 bg-black/20">
                                            <form onSubmit={handleSendChat} className="flex gap-2">
                                                <input value={msgInput} onChange={(e) => setMsgInput(e.target.value)} className="flex-1 bg-black/40 border border-white/10 rounded-lg px-3 py-2 text-xs text-white outline-none" placeholder="Type message..." />
                                                <button type="submit" disabled={!msgInput.trim()} className="bg-brand-600 text-white p-2 rounded-lg"><Icon name="Send" size={16}/></button>
                                            </form>
                                        </div>
                                    </>
                                )}
                            </div>
                         )}
                         {activeChatTab === 'announcements' && (<div className="flex-1 overflow-y-auto p-4 space-y-4">{announcements.map(ann => (<div key={ann.id} className="bg-white/5 border border-white/5 p-4 rounded-xl border-l-4 border-l-brand-500"><h5 className="text-white text-sm font-bold">{ann.title}</h5><p className="text-xs text-gray-400 mt-1">{ann.content}</p></div>))}</div>)}
                     </div>
                )}
            </div>

            <BulkImportModal isOpen={isBulkModalOpen} onClose={() => setIsBulkModalOpen(false)} onImport={handleBulkConfirm} />
        </div>
    );
};

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Tool, User, DivisionType, Task, ToolCategory, UserRole, ChatMessage, TaskPriority } from '../types';
import { DIVISIONS } from '../constants';
import { Icon } from './Icon';
import { ToolCard } from './ToolCard';
import { WorkflowMap } from './WorkflowMap';
import { TaskBoard } from './TaskBoard';
import { translations, LanguageCode } from '../translations';
import { NotificationService } from '../services/notificationService';
import { StorageService } from '../services/storageService';
import { TaskDetailView } from './TaskDetailView'; 

interface DivisionViewProps {
  tools: Tool[];
  user: User;
  handleToolClick: (tool: Tool) => void;
  onContextMenu: (e: any, tool: Tool) => void;
  onSelect: (tool: Tool) => void;
  onAddTool: (divisionId: string) => void;
  isSelectionMode: boolean;
  selectedIds: Set<string>;
  onOpenChat: (divisionId: string) => void;
  onOpenDivisionTasks: (divisionId: DivisionType) => void;
  lang: LanguageCode;
  tasks: Task[];
  onAddTask: (divId: DivisionType, title: string, priority: TaskPriority) => void;
  onToggleTask: (divId: DivisionType, taskId: string) => void;
  onDeleteTask: (divId: DivisionType, taskId: string) => void;
  onUpdateTask: (divId: DivisionType, taskId: string, updates: Partial<Task>) => void;
  messages: ChatMessage[];
  onSendMessage: (content: string, channelId: string) => void;
}

export const DivisionView: React.FC<DivisionViewProps> = ({ 
    tools, user, handleToolClick, onContextMenu, onSelect, onAddTool, isSelectionMode, selectedIds, 
    lang, tasks, onAddTask, onToggleTask, onDeleteTask, onUpdateTask, messages, onSendMessage 
}) => {
    const { id } = useParams<{ id: string }>(); 
    const navigate = useNavigate(); 

    const [searchTerm, setSearchTerm] = useState(''); 
    const [showMobileSidebar, setShowMobileSidebar] = useState(false); // Mobile state

    // Persistent Side Panel State
    const [activeSideTab, setActiveSideTab] = useState<'tasks' | 'chat'>('tasks');
    const [chatInput, setChatInput] = useState('');
    const chatEndRef = useRef<HTMLDivElement>(null);
    const [selectedTask, setSelectedTask] = useState<(Task & { divName?: string, divIcon?: string, description?: string, divId?: string }) | null>(null);

    const prefs = StorageService.getPreferences();
    const t = translations[lang] || translations.en;

    // --- 1. ACCESS CONTROL LOGIC ---
    if (user.role !== UserRole.ADMIN && user.division !== id) {
        return (
            <div className="flex flex-col items-center justify-center h-full text-center p-10 bg-[radial-gradient(ellipse_at_top_right,_var(--tw-gradient-stops))] from-[#020617] via-[#0f172a] to-[#172554]">
                <div className="bg-red-500/10 p-8 rounded-2xl border border-red-500/20 backdrop-blur-xl shadow-2xl max-w-md animate-[scaleIn_0.3s_ease-out]">
                    <div className="w-20 h-20 bg-red-500/20 rounded-full flex items-center justify-center mx-auto mb-6">
                        <Icon name="ShieldAlert" size={40} className="text-red-500" />
                    </div>
                    <h2 className="text-2xl font-bold text-white mb-2">Akses Ditolak</h2>
                    <p className="text-gray-400 mb-8 leading-relaxed">
                        Maaf, Anda tidak memiliki izin untuk mengakses area <strong>{DIVISIONS.find(d => d.id === id)?.name || id}</strong>.
                    </p>
                    <button 
                        onClick={() => navigate('/')} 
                        className="px-8 py-3 bg-white/10 hover:bg-white/20 rounded-xl text-white font-bold transition-all border border-white/5 shadow-lg flex items-center justify-center gap-2 w-full"
                    >
                        <Icon name="ArrowLeft" size={18} /> Kembali ke Dashboard
                    </button>
                </div>
            </div>
        );
    }

    const division = DIVISIONS.find(d => d.id === id); 
    if (!division) return <div className="p-10 text-white text-center pt-20">{t.division.notFound}</div>;

    const canAddTool = user.role === UserRole.ADMIN || (user.role === UserRole.MANAGER && user.division === id);

    // Scroll chat to bottom
    useEffect(() => {
        if (activeSideTab === 'chat') {
            chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
        }
    }, [messages, activeSideTab, showMobileSidebar]);

    // --- 2. FILTER TOOLS ---
    const filteredTools = tools.filter((t: Tool) => 
        t.divisionId === id && 
        (t.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
         (t.description && t.description.toLowerCase().includes(searchTerm.toLowerCase())))
    );

    const groupedTools = useMemo(() => { 
        return { 
            [ToolCategory.DAILY]: filteredTools.filter((t: Tool) => t.category === ToolCategory.DAILY), 
            [ToolCategory.SHARED]: filteredTools.filter((t: Tool) => t.category === ToolCategory.SHARED), 
            [ToolCategory.PROJECT]: filteredTools.filter((t: Tool) => t.category === ToolCategory.PROJECT), 
        }; 
    }, [filteredTools]);

    const divisionTasks = tasks.filter(t => t.targetDivisionId === division.id || (!t.targetDivisionId && t.originDivisionId === division.id));
    const divisionMessages = messages.filter(m => m.channelId === division.id);

    const handleChatSend = (e: React.FormEvent) => {
        e.preventDefault();
        if(!chatInput.trim()) return;
        onSendMessage(chatInput, division.id);
        setChatInput('');
    };

    const ToolColumn: React.FC<{ title: string; categoryTools: Tool[]; color: string }> = ({ title, categoryTools, color }) => (
        <div className="flex-1 min-w-[280px] flex flex-col glass-card rounded-2xl border border-white/5 h-full overflow-hidden">
            <div className={`p-4 border-b border-white/5 bg-white/5 flex justify-between items-center`}>
                <div className="flex items-center gap-2">
                    <div className={`w-2 h-2 rounded-full ${color}`}></div>
                    <h3 className="font-bold text-sm text-gray-200 uppercase tracking-wide">{title}</h3>
                </div>
                <span className="text-xs text-gray-500 bg-black/20 px-2 py-0.5 rounded-full">{categoryTools.length}</span>
            </div>
            <div className="flex-1 p-3 overflow-y-auto custom-scrollbar space-y-2 bg-black/10">
                {categoryTools.map(tool => (
                    <div key={tool.id} draggable={!tool.isLocked}>
                        <ToolCard tool={tool} onClick={() => handleToolClick(tool)} onContextMenu={onContextMenu} onSelect={() => onSelect(tool)} variant="list" isSelectionMode={isSelectionMode} isSelected={selectedIds.has(tool.id)} />
                    </div>
                ))}
                {categoryTools.length === 0 && <div className="h-20 flex items-center justify-center text-xs text-gray-500 italic">No tools</div>}
            </div>
        </div>
    );

    const handleAddTaskBoard = (task: Task) => {
        onAddTask(division.id, task.title, task.priority);
    };

    const handleTaskClick = (task: Task) => {
        setSelectedTask({ ...task, divId: division.id });
    };

    const handleWhatsApp = (task: Task) => NotificationService.sendToWhatsApp(task, prefs);

    return (
        <div className="flex h-full overflow-hidden bg-[radial-gradient(ellipse_at_top_right,_var(--tw-gradient-stops))] from-[#020617] via-[#0f172a] to-[#172554] relative">

            {/* MAIN CONTENT (TOOLS) */}
            <div className="flex-1 flex flex-col h-full overflow-hidden">

                {/* Header */}
                <div className="flex items-center justify-between px-4 md:px-6 py-4 md:py-6 border-b border-white/5 bg-white/5 shrink-0 gap-3">
                    <div className="flex items-center gap-3 md:gap-4 overflow-hidden">
                        <button onClick={() => navigate('/')} className="p-2 hover:bg-white/10 rounded-full text-gray-400 hover:text-white transition-colors shrink-0"><Icon name="ArrowLeft" size={20} /></button>
                        <div className="min-w-0">
                            <h1 className="text-lg md:text-2xl font-bold text-white tracking-tight flex items-center gap-2 truncate">
                                <Icon name={division.icon} className="text-brand-400 shrink-0" />
                                <span className="truncate">{division.name}</span>
                            </h1>
                            <p className="text-xs text-gray-500 mt-1 truncate hidden md:block">{division.description}</p>
                        </div>
                    </div>

                    <div className="flex items-center gap-2 shrink-0">
                        {/* Search Bar (Hidden on small mobile if needed, or collapsed) */}
                        <div className="relative group w-32 md:w-64 hidden sm:block">
                            <Icon name="Search" className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={14} />
                            <input 
                                type="text" 
                                placeholder="Search tools..." 
                                value={searchTerm} 
                                onChange={(e) => setSearchTerm(e.target.value)} 
                                className="w-full pl-9 pr-3 py-2 bg-black/20 border border-white/10 rounded-lg text-xs text-white placeholder-gray-500 outline-none focus:border-brand-500 transition-all" 
                            />
                        </div>

                        {canAddTool && (<button onClick={() => onAddTool(division.id)} className="flex items-center justify-center w-8 h-8 md:w-auto md:px-4 md:py-2 bg-brand-600 hover:bg-brand-500 text-white text-sm font-semibold rounded-lg shadow-lg"><Icon name="Plus" size={16} /> <span className="hidden md:inline ml-2">{t.division.addTool}</span></button>)}

                        {/* Mobile Sidebar Toggle */}
                        <button 
                            onClick={() => setShowMobileSidebar(true)}
                            className="md:hidden p-2 bg-indigo-600/20 text-indigo-400 border border-indigo-500/30 rounded-lg relative"
                        >
                            <Icon name="Layout" size={20} />
                            {divisionTasks.filter(t => !t.isCompleted).length > 0 && (
                                <div className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full animate-pulse border border-black"></div>
                            )}
                        </button>
                    </div>
                </div>

                {/* Tools Grid */}
                <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-6">
                    <div className="max-w-7xl mx-auto h-full space-y-6 md:space-y-8 animate-[fadeIn_0.3s]">
                        {division.workflow.length > 0 && (
                            <div className="glass-card rounded-2xl p-4 md:p-6 border border-white/5 overflow-x-auto">
                                <div className="flex items-center gap-2 mb-4">
                                    <Icon name="GitMerge" className="text-brand-400" size={18} />
                                    <h3 className="font-bold text-sm text-gray-200 uppercase tracking-wide">{t.division.workflow}</h3>
                                </div>
                                <WorkflowMap steps={division.workflow} onStepClick={() => {}} />
                            </div>
                        )}
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6 pb-20 md:pb-0">
                            <ToolColumn title={t.division.daily} categoryTools={groupedTools[ToolCategory.DAILY]} color="bg-blue-500" />
                            <ToolColumn title={t.division.shared} categoryTools={groupedTools[ToolCategory.SHARED]} color="bg-purple-500" />
                            <ToolColumn title={t.division.projects} categoryTools={groupedTools[ToolCategory.PROJECT]} color="bg-emerald-500" />
                        </div>
                    </div>
                </div>
            </div>

            {/* RESPONSIVE RIGHT SIDEBAR (TASKS & CHAT) */}
            <div className={`
                fixed inset-y-0 right-0 z-50 bg-[#0b1120]/95 backdrop-blur-xl border-l border-white/5 shadow-2xl transition-transform duration-300
                w-full md:w-[400px] md:relative md:transform-none md:flex flex-col
                ${showMobileSidebar ? 'translate-x-0' : 'translate-x-full md:translate-x-0'}
            `}>

                <div className="md:hidden flex items-center justify-between p-4 border-b border-white/10 bg-black/20">
                    <h3 className="font-bold text-white flex items-center gap-2">
                        <Icon name="Layout" className="text-indigo-400" /> Division Activity
                    </h3>
                    <button onClick={() => setShowMobileSidebar(false)} className="p-2 text-gray-400 hover:text-white bg-white/5 rounded-full">
                        <Icon name="X" size={20} />
                    </button>
                </div>

                <div className="flex p-3 gap-2 border-b border-white/5 bg-white/5 shrink-0">
                    <button 
                        onClick={() => setActiveSideTab('tasks')} 
                        className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg text-xs font-bold transition-all ${activeSideTab === 'tasks' ? 'bg-brand-600 text-white shadow-lg' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}
                    >
                        <Icon name="Layout" size={14} /> Workload
                        <span className="bg-black/20 px-1.5 py-0.5 rounded-full text-[10px]">{divisionTasks.filter(t => !t.isCompleted).length}</span>
                    </button>
                    <button 
                        onClick={() => setActiveSideTab('chat')} 
                        className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg text-xs font-bold transition-all ${activeSideTab === 'chat' ? 'bg-indigo-600 text-white shadow-lg' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}
                    >
                        <Icon name="MessageSquare" size={14} /> Team Chat
                    </button>
                </div>

                <div className="flex-1 overflow-hidden relative flex flex-col">
                    {activeSideTab === 'tasks' && (
                        <div className="flex-1 overflow-y-auto custom-scrollbar animate-[fadeIn_0.2s]">
                            <TaskBoard 
                                user={user} 
                                tasks={tasks} 
                                onAdd={handleAddTaskBoard} 
                                onToggle={(tid) => onToggleTask(division.id, tid)} 
                                onDelete={(tid) => onDeleteTask(division.id, tid)} 
                                onTaskClick={handleTaskClick} 
                                onWhatsApp={handleWhatsApp}
                                divisionContext={division.id} 
                                isEmbedded={true} 
                            />
                        </div>
                    )}

                    {activeSideTab === 'chat' && (
                        <div className="flex-1 flex flex-col animate-[fadeIn_0.2s] overflow-hidden">
                            <div className="p-3 border-b border-white/5 bg-black/20 flex items-center justify-between shrink-0">
                                <div className="flex items-center gap-2 text-xs text-gray-400">
                                    <span className="w-2 h-2 rounded-full bg-green-500"></span>
                                    {division.name} Channel
                                </div>
                                <Icon name="Users" size={14} className="text-gray-500" />
                            </div>

                            <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar bg-black/10">
                                {divisionMessages.length === 0 && (
                                    <div className="text-center py-10 text-gray-500 opacity-50">
                                        <Icon name="MessageCircle" size={32} className="mx-auto mb-2" />
                                        <p className="text-xs">No messages yet. Start the conversation!</p>
                                    </div>
                                )}
                                {divisionMessages.map((msg) => (
                                    <div key={msg.id} className={`flex flex-col ${msg.senderId === user.id ? 'items-end' : 'items-start'}`}>
                                        <div className={`max-w-[90%] rounded-xl px-3 py-2 text-xs shadow-sm ${msg.senderId === user.id ? 'bg-indigo-600 text-white' : 'bg-[#1e293b] text-gray-200 border border-white/10'}`}>
                                            {msg.senderId !== user.id && <p className="text-[9px] font-bold text-indigo-300 mb-0.5">{msg.senderName}</p>}
                                            <p className="whitespace-pre-wrap">{msg.content}</p>
                                        </div>
                                        <span className="text-[9px] text-gray-600 mt-1 px-1">{new Date(msg.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                                    </div>
                                ))}
                                <div ref={chatEndRef} />
                            </div>

                            <div className="p-3 border-t border-white/5 bg-white/5 shrink-0 safe-area-pb">
                                <form onSubmit={handleChatSend} className="flex gap-2">
                                    <input 
                                        className="flex-1 bg-black/40 border border-white/10 rounded-xl px-3 py-2 text-xs text-white focus:ring-1 focus:ring-indigo-500 outline-none placeholder-gray-500 transition-all"
                                        placeholder={`Message...`}
                                        value={chatInput}
                                        onChange={(e) => setChatInput(e.target.value)}
                                    />
                                    <button 
                                        type="submit" 
                                        disabled={!chatInput.trim()}
                                        className="p-2 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-xl shadow-lg transition-all"
                                    >
                                        <Icon name="Send" size={16} />
                                    </button>
                                </form>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {showMobileSidebar && (
                <div className="fixed inset-0 bg-black/50 z-40 md:hidden backdrop-blur-sm" onClick={() => setShowMobileSidebar(false)}></div>
            )}

            {selectedTask && (
                <TaskDetailView 
                    task={selectedTask} 
                    isOpen={!!selectedTask} 
                    onClose={() => setSelectedTask(null)} 
                    onToggle={() => onToggleTask(division.id, selectedTask.id)} 
                    onDelete={() => { onDeleteTask(division.id, selectedTask.id); setSelectedTask(null); }} 
                    onUpdate={(updates) => onUpdateTask && onUpdateTask(division.id, selectedTask.id, updates)} 
                />
            )}
        </div>
    );
};

import React, { useState, useEffect, useRef } from 'react';
import { User, Tool, Announcement, UserRole, AttendanceConfig, Holiday, UserPreferences, SystemBackup, DivisionType, AttendanceRecord } from '../types';
import { Icon } from './Icon';
import { StorageService } from '../services/storageService';
import { translations, LanguageCode } from '../translations';
import { NotificationService } from '../services/notificationService';
import { UnifiedDataService } from '../services/UnifiedDataService';
import { isSupabaseConfigured } from '../services/supabaseClient';
import { EmployeeModal } from './EmployeeModal';
import { OrgChart } from './OrgChart';
import { EMPLOYEE_DATA } from '../constants';

interface SettingsViewProps {
  user: User;
  onUpdateUser: (user: User) => void;
  tools: Tool[];
  onUpdateTools: (tools: Tool[]) => void;
  announcements: Announcement[];
  onUpdateAnnouncements: (announcements: Announcement[]) => void;
  attendanceConfig: AttendanceConfig;
  onUpdateAttendanceConfig: (config: AttendanceConfig) => void;
  holidays: Holiday[];
  onUpdateHolidays: (holidays: Holiday[]) => void;
  onTeamUpdate: () => void; 
}

export const SettingsView: React.FC<SettingsViewProps> = ({ 
  user, onUpdateUser, tools, onUpdateTools, announcements, onUpdateAnnouncements,
  attendanceConfig, onUpdateAttendanceConfig, holidays, onUpdateHolidays, onTeamUpdate
}) => {
  const isSystemAdmin = user.role === UserRole.ADMIN || user.division === DivisionType.GA_SECURITY || user.division === DivisionType.IT_SUPPORT;
  const canManageTeam = isSystemAdmin || user.division === DivisionType.HR;

  const [activeTab, setActiveTab] = useState<'team' | 'profile' | 'system' | 'notifications'>(
      canManageTeam ? 'team' : 'profile'
  );

  const [teamViewMode, setTeamViewMode] = useState<'list' | 'chart'>('list');
  const [searchTerm, setSearchTerm] = useState('');
  const [isSyncing, setIsSyncing] = useState(false);
  const [allEmployees, setAllEmployees] = useState<User[]>([]);
  const [isEmployeeModalOpen, setIsEmployeeModalOpen] = useState(false);
  const [editingEmployee, setEditingEmployee] = useState<User | undefined>(undefined);
  const [isCheckingFonnteStatus, setIsCheckingFonnteStatus] = useState(false);
  const [fonnteDeviceStatus, setFonnteDeviceStatus] = useState<any>(null);
  const [preferences, setPreferences] = useState<UserPreferences>(StorageService.getPreferences());
  const t = translations[preferences.language as LanguageCode] || translations.en;

  const [editName, setEditName] = useState(user.name);
  const [editNote, setEditNote] = useState(user.stickyNote);
  const [editRole, setEditRole] = useState(user.role);
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [systemSubTab, setSystemSubTab] = useState<'announcements' | 'attendance' | 'backup'>('announcements');
  const [newAnnTitle, setNewAnnTitle] = useState('');
  const [newAnnContent, setNewAnnContent] = useState('');
  const [newAnnPriority, setNewAnnPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editWorkStart, setEditWorkStart] = useState(attendanceConfig.workStartTime);
  const [editWorkEnd, setEditWorkEnd] = useState(attendanceConfig.workEndTime);
  const [waNumber, setWaNumber] = useState(preferences.whatsappNumber || '');
  const [webhookUrl, setWebhookUrl] = useState(preferences.webhookUrl || '');
  const [fonnteToken, setFonnteToken] = useState(preferences.fonnteToken || '');

  const [attendanceHistory, setAttendanceHistory] = useState<AttendanceRecord[]>([]);

  useEffect(() => {
      setAllEmployees(StorageService.getUsers());
      if (canManageTeam) {
          setAttendanceHistory(StorageService.getAttendanceHistory());
      }
  }, [canManageTeam]);

  const handleAddEmployee = () => { setEditingEmployee(undefined); setIsEmployeeModalOpen(true); };
  const handleEditEmployee = (emp: User) => { setEditingEmployee(emp); setIsEmployeeModalOpen(true); };

  const handleDeleteEmployee = (id: string) => { 
      if (id === user.id) return alert("Anda tidak dapat menghapus akun sendiri."); 
      if (window.confirm("Hapus user ini secara permanen?")) { 
          StorageService.deleteUser(id); 
          setAllEmployees(StorageService.getUsers()); 
          if(onTeamUpdate) onTeamUpdate();
      } 
  };

  const handleSaveEmployee = (empData: User) => { 
      if (editingEmployee) StorageService.updateUser(empData); 
      else StorageService.addUser(empData); 
      setAllEmployees(StorageService.getUsers()); 
      setIsEmployeeModalOpen(false); 
      if(onTeamUpdate) onTeamUpdate();
  };

  const handleSaveProfile = () => { onUpdateUser({ ...user, name: editName, stickyNote: editNote, role: editRole }); alert(t.common.save); };
  const handleChangePassword = (e: React.FormEvent) => { e.preventDefault(); if (!newPassword || newPassword !== confirmPassword) return alert("Mismatch"); onUpdateUser({ ...user, password: newPassword }); setNewPassword(''); setConfirmPassword(''); alert("Updated"); };
  const handleAddAnnouncement = (e: React.FormEvent) => { e.preventDefault(); onUpdateAnnouncements([{ id: `ann_${Date.now()}`, title: newAnnTitle, content: newAnnContent, priority: newAnnPriority, date: new Date().toISOString().split('T')[0] }, ...announcements]); setNewAnnTitle(''); setNewAnnContent(''); };
  const handleDeleteAnnouncement = (id: string) => { onUpdateAnnouncements(announcements.filter(a => a.id !== id)); };
  const handleSaveAttendanceConfig = () => { onUpdateAttendanceConfig({ ...attendanceConfig, workStartTime: editWorkStart, workEndTime: editWorkEnd }); alert("Saved"); };
  const handleExportConfig = () => { const blob = new Blob([JSON.stringify(StorageService.createBackup(), null, 2)], { type: 'application/json' }); const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = 'config.json'; a.click(); };
  const handleImportConfig = (e: React.ChangeEvent<HTMLInputElement>) => { const file = e.target.files?.[0]; if (!file) return; const reader = new FileReader(); reader.onload = (ev) => { try { StorageService.restoreBackup(JSON.parse(ev.target?.result as string)); } catch (e) { alert("Invalid"); } }; reader.readAsText(file); };
  const handleCloudSync = async () => { if (!window.confirm("Sync to cloud?")) return; setIsSyncing(true); await UnifiedDataService.syncLocalToCloud(StorageService.getTasks(), StorageService.getMessages(), StorageService.getChatGroups()); setIsSyncing(false); alert("Done"); };
  const handleSaveNotifications = () => { const upd = { ...preferences, whatsappNumber: waNumber, webhookUrl, fonnteToken }; setPreferences(upd); StorageService.savePreferences(upd); alert("Saved"); };
  const handleCheckFonnteStatus = async () => { setIsCheckingFonnteStatus(true); setFonnteDeviceStatus(await NotificationService.validateFonnteToken(fonnteToken)); setIsCheckingFonnteStatus(false); };

  const getBadgeColor = (division: string) => { 
      switch(division) { 
          case 'Direksi': return 'bg-purple-500/20 text-purple-300 border-purple-500/30'; 
          case 'Marketing': return 'bg-blue-500/20 text-blue-300 border-blue-500/30'; 
          case 'Administrasi': return 'bg-orange-500/20 text-orange-300 border-orange-500/30'; 
          case 'Keuangan': return 'bg-emerald-500/20 text-emerald-300 border-emerald-500/30'; 
          case 'IT Support': return 'bg-indigo-500/20 text-indigo-300 border-indigo-500/30';
          case 'SDM & Personalia': return 'bg-pink-500/20 text-pink-300 border-pink-500/30';
          default: return 'bg-gray-500/20 text-gray-300 border-gray-500/30'; 
      } 
  };

  const filteredEmployees = allEmployees.filter(emp => emp.name.toLowerCase().includes(searchTerm.toLowerCase()) || emp.division.toLowerCase().includes(searchTerm.toLowerCase()));

  const getUserName = (id: string) => {
      const u = allEmployees.find(emp => emp.id === id);
      return u ? u.name : id;
  };

  return (
    <div className="flex h-full bg-[#0b0f1a] overflow-hidden">
      <div className="hidden md:flex w-64 bg-black/20 border-r border-white/5 p-6 flex-col gap-2 shrink-0 backdrop-blur-md">
        <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2"><Icon name="Settings" className="text-brand-400" /> Pengaturan</h2>
        {canManageTeam && (<button onClick={() => setActiveTab('team')} className={`text-left px-4 py-3 rounded-xl flex items-center gap-3 transition-all ${activeTab === 'team' ? 'bg-brand-600 text-white' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}><Icon name="Users" size={18} /> Data Tim</button>)}
        <button onClick={() => setActiveTab('profile')} className={`text-left px-4 py-3 rounded-xl flex items-center gap-3 transition-all ${activeTab === 'profile' ? 'bg-brand-600 text-white' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}><Icon name="User" size={18} /> Profil</button>
        {isSystemAdmin && (<button onClick={() => setActiveTab('notifications')} className={`text-left px-4 py-3 rounded-xl flex items-center gap-3 transition-all ${activeTab === 'notifications' ? 'bg-brand-600 text-white' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}><Icon name="Bell" size={18} /> Notifikasi</button>)}
        {isSystemAdmin && (<button onClick={() => setActiveTab('system')} className={`text-left px-4 py-3 rounded-xl flex items-center gap-3 transition-all ${activeTab === 'system' ? 'bg-brand-600 text-white' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}><Icon name="Server" size={18} /> Sistem</button>)}
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8">
        <div className="md:hidden flex overflow-x-auto gap-2 mb-6 pb-2 scrollbar-hide">
             {canManageTeam && <button onClick={() => setActiveTab('team')} className={`whitespace-nowrap px-4 py-2 rounded-full text-xs font-bold border transition-colors ${activeTab === 'team' ? 'bg-brand-600 border-brand-500 text-white' : 'bg-white/5 border-white/10 text-gray-400'}`}>Tim</button>}
             <button onClick={() => setActiveTab('profile')} className={`whitespace-nowrap px-4 py-2 rounded-full text-xs font-bold border transition-colors ${activeTab === 'profile' ? 'bg-brand-600 border-brand-500 text-white' : 'bg-white/5 border-white/10 text-gray-400'}`}>Profil</button>
             {isSystemAdmin && <button onClick={() => setActiveTab('notifications')} className={`whitespace-nowrap px-4 py-2 rounded-full text-xs font-bold border transition-colors ${activeTab === 'notifications' ? 'bg-brand-600 border-brand-500 text-white' : 'bg-white/5 border-white/10 text-gray-400'}`}>Pesan</button>}
             {isSystemAdmin && <button onClick={() => setActiveTab('system')} className={`whitespace-nowrap px-4 py-2 rounded-full text-xs font-bold border transition-colors ${activeTab === 'system' ? 'bg-brand-600 border-brand-500 text-white' : 'bg-white/5 border-white/10 text-gray-400'}`}>Sistem</button>}
        </div>

        {activeTab === 'team' && canManageTeam && (
            <div className="max-w-6xl mx-auto space-y-6 animate-[fadeIn_0.3s]">
                <div className="flex flex-col md:flex-row md:justify-between md:items-center gap-4 mb-2">
                    <h2 className="text-xl md:text-2xl font-bold text-white mb-1">Data Tim</h2>
                    <div className="flex flex-wrap gap-3">
                        <button onClick={() => setTeamViewMode('list')} className={`px-3 py-1.5 rounded-lg text-xs font-bold flex items-center gap-2 ${teamViewMode === 'list' ? 'bg-white/10 text-white' : 'text-gray-500'}`}><Icon name="List" size={14} /> List</button>
                        <button onClick={() => setTeamViewMode('chart')} className={`px-3 py-1.5 rounded-lg text-xs font-bold flex items-center gap-2 ${teamViewMode === 'chart' ? 'bg-white/10 text-white' : 'text-gray-500'}`}><Icon name="GitFork" size={14} /> Bagan</button>
                        <button onClick={handleAddEmployee} className="bg-brand-600 hover:bg-brand-500 text-white px-4 py-2 rounded-xl text-sm font-bold flex items-center gap-2 shadow-lg transition-all"><Icon name="UserPlus" size={16} /> Tambah</button>
                    </div>
                </div>

                {teamViewMode === 'list' ? (
                    <div className="bg-white/5 border border-white/5 rounded-2xl overflow-hidden shadow-2xl">
                        <table className="w-full text-left border-collapse">
                            <thead className="bg-black/20 text-gray-400 text-xs uppercase tracking-wider font-semibold">
                                <tr><th className="p-4 w-16 text-center">No</th><th className="p-4">Nama</th><th className="p-4">Divisi</th><th className="p-4 text-center">Aksi</th></tr>
                            </thead>
                            <tbody className="divide-y divide-white/5 text-sm">
                                {filteredEmployees.map((emp, idx) => (
                                    <tr key={emp.id} className="hover:bg-white/5 transition-colors group">
                                        <td className="p-4 text-center text-gray-500">{idx + 1}</td>
                                        <td className="p-4 font-medium text-white flex items-center gap-3"><div className="w-8 h-8 rounded-full bg-gray-700 flex items-center justify-center text-xs">{emp.name.charAt(0)}</div>{emp.name}</td>
                                        <td className="p-4"><span className={`text-[10px] px-2 py-0.5 rounded border uppercase font-bold ${getBadgeColor(emp.division)}`}>{emp.division}</span></td>
                                        <td className="p-4 text-center"><div className="flex justify-center gap-2"><button onClick={() => handleEditEmployee(emp)} className="p-1.5 bg-blue-500/10 text-blue-400 rounded"><Icon name="Pencil" size={14} /></button><button onClick={() => handleDeleteEmployee(emp.id)} className="p-1.5 bg-red-500/10 text-red-400 rounded"><Icon name="Trash2" size={14} /></button></div></td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                ) : (
                    <OrgChart users={allEmployees} />
                )}
            </div>
        )}

        {activeTab === 'profile' && (
            <div className="max-w-2xl mx-auto space-y-8 animate-[fadeIn_0.3s]">
                <div className="bg-gradient-to-r from-brand-900/50 to-indigo-900/50 border border-brand-500/30 rounded-2xl p-6 flex items-center gap-6 shadow-2xl">
                    <div className="w-24 h-24 rounded-2xl bg-brand-500 flex items-center justify-center text-white text-4xl font-bold">{user.name.charAt(0)}</div>
                    <div><h2 className="text-2xl font-bold text-white">{user.name}</h2><p className="text-gray-400 text-sm">{user.role} • {user.division}</p></div>
                </div>
                <div className="bg-white/5 border border-white/5 rounded-2xl p-6 space-y-6">
                    <h3 className="text-lg font-bold text-white">Edit Profil</h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="space-y-2"><label className="text-xs font-bold text-gray-400">Nama</label><input className="w-full bg-black/30 border border-white/10 rounded-lg px-3 py-2 text-white text-sm outline-none" value={editName} onChange={e => setEditName(e.target.value)} /></div>
                        <div className="space-y-2"><label className="text-xs font-bold text-gray-400">Sticky Note</label><input className="w-full bg-black/30 border border-white/10 rounded-lg px-3 py-2 text-white text-sm outline-none" value={editNote} onChange={e => setEditNote(e.target.value)} /></div>
                    </div>
                    <button onClick={handleSaveProfile} className="px-4 py-2 bg-white/10 hover:bg-white/20 text-white rounded-lg text-sm font-bold">Simpan</button>
                </div>
            </div>
        )}

        {activeTab === 'notifications' && isSystemAdmin && (
            <div className="max-w-2xl mx-auto space-y-8 animate-[fadeIn_0.3s]">
                <div className="bg-white/5 border border-white/5 rounded-2xl p-6 space-y-4">
                    <h3 className="text-lg font-bold text-white">Nomor Admin (WhatsApp)</h3>
                    <input className="w-full bg-black/30 border border-white/10 rounded-lg px-3 py-2 text-white text-sm outline-none" value={waNumber} onChange={e => setWaNumber(e.target.value)} placeholder="628..." />
                </div>
                <div className="bg-white/5 border border-white/5 rounded-2xl p-6 space-y-4">
                    <h3 className="text-lg font-bold text-white">Integrasi Fonnte</h3>
                    <div className="flex gap-2"><input className="flex-1 bg-black/30 border border-white/10 rounded-lg px-3 py-2 text-white text-sm outline-none" type="password" value={fonnteToken} onChange={e => setFonnteToken(e.target.value)} placeholder="Token..." /><button onClick={handleCheckFonnteStatus} className="px-4 py-2 bg-indigo-600 text-white rounded-lg text-xs font-bold">{isCheckingFonnteStatus ? '...' : 'Cek'}</button></div>
                    {fonnteDeviceStatus && (<div className={`p-3 rounded border text-xs ${fonnteDeviceStatus.status ? 'bg-green-500/20 border-green-500/50 text-green-300' : 'bg-red-500/20 border-red-500/50 text-red-300'}`}>{fonnteDeviceStatus.status ? `Connected: ${fonnteDeviceStatus.name}` : `Error: ${fonnteDeviceStatus.reason}`}</div>)}
                </div>
                <button onClick={handleSaveNotifications} className="w-full py-3 bg-brand-600 text-white font-bold rounded-xl shadow-lg">Simpan Konfigurasi</button>
            </div>
        )}

        {activeTab === 'system' && isSystemAdmin && (
            <div className="max-w-4xl mx-auto animate-[fadeIn_0.3s]">
                <div className="flex gap-2 mb-8 bg-black/30 p-1 rounded-xl w-fit overflow-x-auto max-w-full">
                    <button onClick={() => setSystemSubTab('announcements')} className={`px-4 py-2 rounded-lg text-xs font-bold whitespace-nowrap ${systemSubTab === 'announcements' ? 'bg-brand-600 text-white' : 'text-gray-400'}`}>Pengumuman</button>
                    <button onClick={() => setSystemSubTab('backup')} className={`px-4 py-2 rounded-lg text-xs font-bold whitespace-nowrap ${systemSubTab === 'backup' ? 'bg-brand-600 text-white' : 'text-gray-400'}`}>Backup</button>
                </div>
                {systemSubTab === 'backup' && (<div className="space-y-6"><div className="bg-indigo-900/20 border border-indigo-500/30 rounded-2xl p-6"><h3 className="font-bold text-white">Cloud Sync</h3><button onClick={handleCloudSync} disabled={isSyncing} className="mt-4 px-6 py-2 bg-indigo-600 text-white rounded font-bold">{isSyncing ? 'Syncing...' : 'Sync to Cloud'}</button></div><div className="bg-white/5 border border-white/5 rounded-2xl p-6"><h3 className="font-bold text-white">Local Backup</h3><div className="flex flex-col md:flex-row gap-4 mt-4"><button onClick={handleExportConfig} className="flex-1 bg-black/30 border border-white/10 p-4 rounded text-white font-bold">Export JSON</button><label className="flex-1 bg-black/30 border border-white/10 p-4 rounded text-white font-bold cursor-pointer text-center"><input type="file" className="hidden" onChange={handleImportConfig} />Import JSON</label></div></div></div>)}
            </div>
        )}
      </div>
      <EmployeeModal isOpen={isEmployeeModalOpen} onClose={() => setIsEmployeeModalOpen(false)} onSave={handleSaveEmployee} initialData={editingEmployee} />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, useParams } from 'react-router-dom';
import { Tool, User, Announcement, ChatMessage, AttendanceConfig, Holiday, UserPreferences, AttendanceRecord, Task, DivisionType, DivisionData, TaskPriority, ChatGroup } from './types';
import { StorageService } from './services/storageService';
import { UnifiedDataService } from './services/UnifiedDataService'; 
import { isSupabaseConfigured } from './services/supabaseClient';
import { AddToolModal } from './components/AddToolModal';
import { SmartAddModal } from './components/SmartAddModal';
import { ContextMenu } from './components/ContextMenu';
import { ToolActionModal } from './components/ToolActionModal';
import { ProfileModal } from './components/ProfileModal';
import { SettingsView } from './components/SettingsView';
import { AttendanceModal } from './components/AttendanceModal';
import { LoginView } from './components/LoginView';
import { Dashboard } from './components/Dashboard';
import { DivisionView } from './components/DivisionView';
import { Messages } from './components/Messages';
import { DocumentsView } from './components/DocumentsView';
import { InventoryView } from './components/InventoryView';
import { FinanceView } from './components/FinanceView';
import { AppLayout, Toast } from './components/Layout';
import { QuickCommand } from './components/QuickCommand';
import { AIAssistant } from './components/AIAssistant';
import { LanguageCode } from './translations';
import { DIVISIONS } from './constants';
import { NotificationService } from './services/notificationService';
import { TaskDetailView } from './components/TaskDetailView';

const ChannelUpdater: React.FC<{ onUpdate: (id: string) => void }> = ({ onUpdate }) => {
    const { id } = useParams<{ id: string }>();
    useEffect(() => {
        if (id) onUpdate(id);
        else onUpdate('GENERAL');
    }, [id, onUpdate]);
    return null;
};

const App: React.FC = () => {
    const [user, setUser] = useState<User | null>(StorageService.getUser());
    const [tools, setTools] = useState<Tool[]>(StorageService.getTools());
    const [users, setUsers] = useState<User[]>(StorageService.getUsers());
    const [allTasks, setAllTasks] = useState<Task[]>([]);
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [chatGroups, setChatGroups] = useState<ChatGroup[]>([]);
    const [notification, setNotification] = useState<string | null>(null);
    const [announcements, setAnnouncements] = useState<Announcement[]>(StorageService.getAnnouncements());
    const [attendanceConfig, setAttendanceConfig] = useState<AttendanceConfig>(StorageService.getAttendanceConfig());
    const [holidays, setHolidays] = useState<Holiday[]>(StorageService.getHolidays());
    const [preferences] = useState<UserPreferences>(StorageService.getPreferences());
    const lang = (preferences.language as LanguageCode) || 'en';

    const [contextMenu, setContextMenu] = useState<{ isOpen: boolean; x: number; y: number; toolId: string | null }>({ isOpen: false, x: 0, y: 0, toolId: null });
    const [isEditModalOpen, setEditModalOpen] = useState(false);
    const [actionModal, setActionModal] = useState<{ isOpen: boolean; mode: 'move' | 'mirror'; toolId: string | null }>({ isOpen: false, mode: 'move', toolId: null });
    const [isSelectionMode, setIsSelectionMode] = useState(false);
    const [selectedToolIds, setSelectedToolIds] = useState<Set<string>>(new Set());
    const [smartAddContext, setSmartAddContext] = useState<string | null>(null);
    const [activeChatChannel, setActiveChatChannel] = useState<string>('GENERAL');
    const [isAttendanceOpen, setAttendanceOpen] = useState(false);
    const [isProfileOpen, setProfileOpen] = useState(false);
    const [isQuickCommandOpen, setQuickCommandOpen] = useState(false);
    const [globalSelectedTask, setGlobalSelectedTask] = useState<(Task & { divName?: string, divIcon?: string, description?: string, divId?: string }) | null>(null);

    useEffect(() => {
        const loadData = async () => {
            const [t, m, g] = await Promise.all([
                UnifiedDataService.getTasks(),
                UnifiedDataService.getMessages(),
                UnifiedDataService.getChatGroups()
            ]);
            setAllTasks(t);
            setMessages(m);
            setChatGroups(g);
        };
        loadData();
    }, []);

    useEffect(() => {
        if (!user) return;
        if (isSupabaseConfigured()) {
            const subscription = UnifiedDataService.subscribeToUpdates(
                () => { UnifiedDataService.getTasks().then(setAllTasks); },
                (newMsg) => {
                    setMessages(prev => [...prev, newMsg]);
                    if (newMsg.senderId !== user.id) {
                        NotificationService.playSound();
                        if (newMsg.channelId.includes(user.id) && !newMsg.channelId.startsWith('grp_')) {
                            setNotification(`Pesan baru dari ${newMsg.senderName}`);
                        }
                    }
                },
                () => { UnifiedDataService.getChatGroups().then(setChatGroups); }
            );
            return () => { subscription?.unsubscribe(); };
        } else {
            const syncInterval = setInterval(() => {
                const storedMessages = StorageService.getMessages();
                if (storedMessages.length !== messages.length) {
                    const lastMsg = storedMessages[storedMessages.length - 1];
                    setMessages(storedMessages);
                    if (lastMsg && lastMsg.senderId !== user.id) { NotificationService.playSound(); }
                }
                const storedGroups = StorageService.getChatGroups();
                if (storedGroups.length !== chatGroups.length) setChatGroups(storedGroups);
                const storedTasks = StorageService.getTasks();
                if (storedTasks.length !== allTasks.length) setAllTasks(storedTasks);
                const storedUsers = StorageService.getUsers();
                if (storedUsers.length !== users.length) setUsers(storedUsers);
            }, 2000); 
            return () => clearInterval(syncInterval);
        }
    }, [user, messages.length, chatGroups.length, allTasks.length, users.length]);

    const dashboardDivisions = DIVISIONS.map(div => ({
        ...div,
        tasks: allTasks.filter(t => t.targetDivisionId === div.id || t.originDivisionId === div.id).sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0))
    }));

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
                e.preventDefault();
                setQuickCommandOpen(prev => !prev);
            }
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, []);

    useEffect(() => {
        if (!user) return;
        const interval = setInterval(() => {
            NotificationService.checkReminders(allTasks, (taskId) => {
                const updatedTasks = allTasks.map(t => t.id === taskId ? { ...t, isReminded: true } : t);
                setAllTasks(updatedTasks);
                UnifiedDataService.updateTask(taskId, { isReminded: true });
            });
        }, 60000);
        return () => clearInterval(interval);
    }, [user, allTasks]);

    useEffect(() => { 
        const root = window.document.documentElement; 
        if (preferences.theme === 'dark') root.classList.add('dark'); 
        else root.classList.remove('dark'); 
    }, [preferences.theme]);

    const handleLogin = (loggedInUser: User) => { StorageService.saveUser(loggedInUser); setUser(loggedInUser); };
    const handleLogout = () => { StorageService.logout(); setUser(null); };
    const handleUpdateUser = (updated: User) => { setUser(updated); StorageService.saveUser(updated); setNotification("Profile updated"); };
    const handleTeamUpdate = () => { setUsers(StorageService.getUsers()); };
    const handleUpdateAnnouncements = (updated: Announcement[]) => { setAnnouncements(updated); StorageService.saveAnnouncements(updated); setNotification("Announcements updated"); };
    const handleUpdateTools = (updated: Tool[]) => { setTools(updated); StorageService.saveTools(updated); setNotification("Tools updated"); };
    const handleUpdateAttendanceConfig = (updated: AttendanceConfig) => { setAttendanceConfig(updated); StorageService.saveAttendanceConfig(updated); };
    const handleUpdateHolidays = (updated: Holiday[]) => { setHolidays(updated); StorageService.saveHolidays(updated); };

    const handleAddTask = async (divId: DivisionType, title: string, priority: TaskPriority) => {
        const newTask: Task = { id: crypto.randomUUID(), title, isCompleted: false, priority, creatorId: user?.id || 'unknown', assigneeId: 'unassigned', originDivisionId: divId, targetDivisionId: divId, timestamp: Date.now() };
        setAllTasks(prev => [newTask, ...prev]);
        await UnifiedDataService.addTask(newTask);
        setNotification("Tugas ditambahkan");
    };

    const handleToggleTask = async (divId: DivisionType, taskId: string) => {
        const task = allTasks.find(t => t.id === taskId);
        if (task) {
            const newVal = !task.isCompleted;
            setAllTasks(prev => prev.map(t => t.id === taskId ? { ...t, isCompleted: newVal } : t));
            await UnifiedDataService.updateTask(taskId, { isCompleted: newVal });
        }
    };

    const handleDeleteTask = async (divId: DivisionType, taskId: string) => {
        if(confirm("Hapus tugas?")) {
             setAllTasks(prev => prev.filter(t => t.id !== taskId));
             await UnifiedDataService.deleteTask(taskId);
        }
    };

    const handleUpdateTask = async (divId: DivisionType, taskId: string, updates: Partial<Task>) => {
        setAllTasks(prev => prev.map(t => t.id === taskId ? { ...t, ...updates } : t));
        await UnifiedDataService.updateTask(taskId, updates);
    };

    const handleGlobalTaskSelect = (task: Task) => {
        const divId = task.targetDivisionId || task.originDivisionId;
        const div = DIVISIONS.find(d => d.id === divId);
        setGlobalSelectedTask({ ...task, divId: divId, divName: div?.name, divIcon: div?.icon });
    };

    const handleSendMessage = async (content: string, channelId: string = activeChatChannel) => { 
        if (!user) return; 
        const newMessage: ChatMessage = { id: crypto.randomUUID(), senderId: user.id, senderName: user.name, channelId: channelId, content, timestamp: Date.now() }; 
        setMessages(prev => [...prev, newMessage]);
        await UnifiedDataService.sendMessage(newMessage);
    };

    const handleCreateGroup = async (name: string, members: string[]) => {
        if (!user) return;
        const newGroup: ChatGroup = { id: `grp_${Date.now()}`, name, memberIds: members, createdAt: Date.now(), createdBy: user.id };
        setChatGroups(prev => [...prev, newGroup]);
        await UnifiedDataService.createChatGroup(newGroup);
        setNotification(`Grup "${name}" berhasil dibuat!`);
        setActiveChatChannel(newGroup.id);
    };

    const handleAddTool = (newToolData: any) => { const newTool = { ...newToolData, id: `t_${Date.now()}`, lastAccessed: 0 }; const updated = [...tools, newTool]; handleUpdateTools(updated); StorageService.logActivity('Created Tool', newTool.name); };
    const handleUpdateToolSingle = (updatedData: Partial<Tool>) => { if (!updatedData.id) return; const updatedTools = tools.map(t => t.id === updatedData.id ? { ...t, ...updatedData } : t); handleUpdateTools(updatedTools); setNotification('Tool updated'); StorageService.logActivity('Updated Tool', updatedData.name || 'Unknown Tool'); };

    const handleToolClick = (tool: Tool) => { 
        StorageService.recordAccess(tool.id); 
        setTools(StorageService.getTools()); 
        if (tool.url && tool.url !== '#') {
            window.open(tool.url, '_blank'); 
        } else {
            setNotification("Aplikasi ini masih dalam pengembangan (Draf)");
        }
    };

    const handleToggleSelection = (tool: Tool) => { const toolId = tool.id; const newSet = new Set(selectedToolIds); if (newSet.has(toolId)) newSet.delete(toolId); else newSet.add(toolId); setSelectedToolIds(newSet); setIsSelectionMode(newSet.size > 0); };

    const handleBulkAction = (action: string) => {
        if (selectedToolIds.size === 0) return;
        if (action === 'DELETE' && confirm(`Move ${selectedToolIds.size} items to trash?`)) { 
            const updated = tools.map(t => selectedToolIds.has(t.id) ? { ...t, deletedAt: Date.now() } : t); handleUpdateTools(updated); setNotification("Moved to trash"); setSelectedToolIds(new Set()); setIsSelectionMode(false); 
        } else if (action === 'ARCHIVE') {
            const updatedArch = tools.map(t => selectedToolIds.has(t.id) ? { ...t, isArchived: true } : t); handleUpdateTools(updatedArch); setNotification("Archived"); setSelectedToolIds(new Set()); setIsSelectionMode(false); 
        }
    };

    const handleContextMenu = (e: any, tool: Tool) => { e.preventDefault(); let x = e.touches ? e.touches[0].clientX : e.clientX; let y = e.touches ? e.touches[0].clientY : e.clientY; setContextMenu({ isOpen: true, x, y, toolId: tool.id }); };
    const executeAction = (action: string) => {
        const toolId = contextMenu.toolId; const tool = tools.find(t => t.id === toolId); setContextMenu({ ...contextMenu, isOpen: false }); if (!tool) return;
        if (tool.isLocked && ['EDIT', 'MOVE', 'MIRROR', 'ARCHIVE', 'DELETE'].includes(action)) { setNotification("Tool is locked"); return; }
        switch (action) { case 'OPEN': handleToolClick(tool); break; case 'EDIT': setEditModalOpen(true); break; case 'DELETE': if(confirm("Move to trash?")) { const updated = tools.map(t => t.id === toolId ? { ...t, deletedAt: Date.now() } : t); handleUpdateTools(updated); setNotification("Moved to trash"); } break; case 'MOVE': setActionModal({ isOpen: true, mode: 'move', toolId }); break; case 'MIRROR': setActionModal({ isOpen: true, mode: 'mirror', toolId }); break; case 'TOGGLE_LOCK': const updatedLock = tools.map(t => t.id === toolId ? { ...t, isLocked: !t.isLocked } : t); handleUpdateTools(updatedLock); break; }
    };

    if (!user) return <LoginView onLogin={handleLogin} />;

    return (
        <HashRouter>
            <AppLayout user={user} selectedCount={selectedToolIds.size} onBulkAction={handleBulkAction} onCancelSelection={() => { setSelectedToolIds(new Set()); setIsSelectionMode(false); }} lang={lang} onLogout={handleLogout}>
                {notification && <Toast message={notification} onClose={() => setNotification(null)} />}

                <Routes>
                    <Route path="/" element={
                        <>
                            <ChannelUpdater onUpdate={setActiveChatChannel} />
                            <Dashboard 
                                tools={tools} user={user} handleToolClick={handleToolClick} onContextMenu={handleContextMenu} onSelect={handleToggleSelection} 
                                onAddTool={handleAddTool} setNotification={setNotification} isSelectionMode={isSelectionMode} selectedIds={selectedToolIds} 
                                setSmartAddContext={setSmartAddContext}
                                onOpenAttendance={() => setAttendanceOpen(true)} onOpenProfile={() => setProfileOpen(true)} 
                                lang={lang} todayAttendance={StorageService.getTodayAttendance(user.id)} unreadAnnouncements={announcements.length} 
                                tasks={allTasks} 
                                announcements={announcements} messages={messages} onSendMessage={(msg) => handleSendMessage(msg)}
                                dashboardDivisions={dashboardDivisions}
                                onAddTask={handleAddTask} 
                                onToggleTask={handleToggleTask} 
                                onDeleteTask={handleDeleteTask}
                                onUpdateTask={handleUpdateTask}
                                activeChannel={activeChatChannel} onChangeChannel={setActiveChatChannel}
                                groups={chatGroups}
                                allUsers={users} 
                            />
                        </>
                    } />
                    <Route path="/division/:id" element={
                        <>
                            <ChannelUpdater onUpdate={setActiveChatChannel} />
                            <DivisionView 
                                tools={tools} user={user} handleToolClick={handleToolClick} onContextMenu={handleContextMenu} onSelect={handleToggleSelection} 
                                onAddTool={(divId) => setSmartAddContext(divId)} 
                                isSelectionMode={isSelectionMode} selectedIds={selectedToolIds} 
                                onOpenChat={(divId) => { setActiveChatChannel(divId); }} 
                                onOpenDivisionTasks={(divId) => {}}
                                lang={lang} 
                                tasks={allTasks}
                                onAddTask={handleAddTask} 
                                onToggleTask={handleToggleTask} 
                                onDeleteTask={handleDeleteTask}
                                onUpdateTask={handleUpdateTask}
                                messages={messages} 
                                onSendMessage={handleSendMessage} 
                            />
                        </>
                    } />
                    <Route path="/messages" element={
                        <Messages 
                            user={user}
                            messages={messages}
                            onSendMessage={handleSendMessage}
                            groups={chatGroups}
                            onCreateGroup={handleCreateGroup}
                        />
                    } />
                    <Route path="/documents" element={<DocumentsView user={user} />} />
                    <Route path="/inventory" element={<InventoryView user={user} />} />
                    <Route path="/finance" element={<FinanceView user={user} />} />
                    <Route path="/settings" element={
                        <SettingsView 
                            user={user} 
                            onUpdateUser={handleUpdateUser} 
                            tools={tools} 
                            onUpdateTools={handleUpdateTools} 
                            announcements={announcements} 
                            onUpdateAnnouncements={handleUpdateAnnouncements} 
                            attendanceConfig={attendanceConfig} 
                            onUpdateAttendanceConfig={handleUpdateAttendanceConfig} 
                            holidays={holidays} 
                            onUpdateHolidays={handleUpdateHolidays}
                            onTeamUpdate={handleTeamUpdate} 
                        />
                    } />
                </Routes>

                <QuickCommand 
                    isOpen={isQuickCommandOpen} 
                    onClose={() => setQuickCommandOpen(false)} 
                    tools={tools} 
                    users={users} 
                    divisions={DIVISIONS}
                    tasks={allTasks}
                    onTaskSelect={handleGlobalTaskSelect}
                />

                <AIAssistant 
                    tasks={allTasks} 
                    users={users} 
                    announcements={announcements} 
                />

                {globalSelectedTask && (
                    <TaskDetailView 
                        task={globalSelectedTask} 
                        isOpen={!!globalSelectedTask} 
                        onClose={() => setGlobalSelectedTask(null)} 
                        onToggle={() => handleToggleTask(globalSelectedTask.divId as DivisionType, globalSelectedTask.id)} 
                        onDelete={() => { handleDeleteTask(globalSelectedTask.divId as DivisionType, globalSelectedTask.id); setGlobalSelectedTask(null); }} 
                        onUpdate={(updates) => handleUpdateTask(globalSelectedTask.divId as DivisionType, globalSelectedTask.id, updates)} 
                    />
                )}

                {contextMenu.isOpen && (<ContextMenu x={contextMenu.x} y={contextMenu.y} isLocked={!!tools.find(t => t.id === contextMenu.toolId)?.isLocked} onClose={() => setContextMenu({ ...contextMenu, isOpen: false })} onOpen={() => executeAction('OPEN')} onEdit={() => executeAction('EDIT')} onMove={() => executeAction('MOVE')} onMirror={() => executeAction('MIRROR')} onArchive={() => executeAction('ARCHIVE')} onDelete={() => executeAction('DELETE')} onToggleLock={() => executeAction('TOGGLE_LOCK')} />)}
                <AddToolModal isOpen={isEditModalOpen} onClose={() => setEditModalOpen(false)} onSave={handleUpdateToolSingle} initialData={tools.find(t => t.id === contextMenu.toolId)} />
                <SmartAddModal isOpen={!!smartAddContext} onClose={() => setSmartAddContext(null)} onAdd={(tool) => handleAddTool(tool)} divisionName={smartAddContext || ''} />
                <ToolActionModal isOpen={actionModal.isOpen} mode={actionModal.mode} onClose={() => setActionModal({ ...actionModal, isOpen: false })} onConfirm={(div, cat) => { const updated = tools.map(t => t.id === actionModal.toolId ? { ...t, divisionId: div, category: cat } : t); if (actionModal.mode === 'mirror') { const original = tools.find(t => t.id === actionModal.toolId); if(original) updated.push({ ...original, id: `t_${Date.now()}`, divisionId: div, category: cat }); } handleUpdateTools(updated); setActionModal({ ...actionModal, isOpen: false }); setNotification("Action successful"); StorageService.logActivity(actionModal.mode === 'mirror' ? 'Mirror Tool' : 'Move Tool', tools.find(t => t.id === actionModal.toolId)?.name || 'Unknown'); }} />
                <AttendanceModal isOpen={isAttendanceOpen} onClose={() => setAttendanceOpen(false)} user={user} />
                <ProfileModal isOpen={isProfileOpen} onClose={() => setProfileOpen(false)} user={user} onUpdateUser={handleUpdateUser} announcements={announcements} onLogout={handleLogout} />
            </AppLayout>
        </HashRouter>
    );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { User, Tool, Announcement, UserRole, AttendanceConfig, Holiday, UserPreferences, SystemBackup, DivisionType, AttendanceRecord } from '../types';
import { Icon } from './Icon';
import { StorageService } from '../services/storageService';
import { translations, LanguageCode } from '../translations';
import { NotificationService } from '../services/notificationService';
import { UnifiedDataService } from '../services/UnifiedDataService';
import { isSupabaseConfigured } from '../services/supabaseClient';
import { EmployeeModal } from './EmployeeModal';
import { OrgChart } from './OrgChart';
import { EMPLOYEE_DATA } from '../constants';

interface SettingsViewProps {
  user: User;
  onUpdateUser: (user: User) => void;
  tools: Tool[];
  onUpdateTools: (tools: Tool[]) => void;
  announcements: Announcement[];
  onUpdateAnnouncements: (announcements: Announcement[]) => void;
  attendanceConfig: AttendanceConfig;
  onUpdateAttendanceConfig: (config: AttendanceConfig) => void;
  holidays: Holiday[];
  onUpdateHolidays: (holidays: Holiday[]) => void;
  onTeamUpdate: () => void; 
}

export const SettingsView: React.FC<SettingsViewProps> = ({ 
  user, onUpdateUser, tools, onUpdateTools, announcements, onUpdateAnnouncements,
  attendanceConfig, onUpdateAttendanceConfig, holidays, onUpdateHolidays, onTeamUpdate
}) => {
  const isSystemAdmin = user.role === UserRole.ADMIN || user.division === DivisionType.IT_SUPPORT;
  const canManageTeam = isSystemAdmin || user.division === DivisionType.HR;

  const [activeTab, setActiveTab] = useState<'team' | 'profile' | 'system' | 'notifications'>(
      canManageTeam ? 'team' : 'profile'
  );

  const [teamViewMode, setTeamViewMode] = useState<'list' | 'chart'>('list');
  const [searchTerm, setSearchTerm] = useState('');
  const [isSyncing, setIsSyncing] = useState(false);
  const [allEmployees, setAllEmployees] = useState<User[]>([]);
  const [isEmployeeModalOpen, setIsEmployeeModalOpen] = useState(false);
  const [editingEmployee, setEditingEmployee] = useState<User | undefined>(undefined);
  const [isCheckingFonnteStatus, setIsCheckingFonnteStatus] = useState(false);
  const [fonnteDeviceStatus, setFonnteDeviceStatus] = useState<any>(null);
  const [connectionStatus, setConnectionStatus] = useState<'checking' | 'connected' | 'disconnected'>('checking');
  const [preferences, setPreferences] = useState<UserPreferences>(StorageService.getPreferences());
  const t = translations[preferences.language as LanguageCode] || translations.en;

  const [editName, setEditName] = useState(user.name);
  const [editNote, setEditNote] = useState(user.stickyNote);
  const [editRole, setEditRole] = useState(user.role);
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [systemSubTab, setSystemSubTab] = useState<'announcements' | 'attendance' | 'backup'>('announcements');
  const [newAnnTitle, setNewAnnTitle] = useState('');
  const [newAnnContent, setNewAnnContent] = useState('');
  const [newAnnPriority, setNewAnnPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editWorkStart, setEditWorkStart] = useState(attendanceConfig.workStartTime);
  const [editWorkEnd, setEditWorkEnd] = useState(attendanceConfig.workEndTime);
  const [editGrace, setEditGrace] = useState(attendanceConfig.gracePeriodMinutes);
  const [editQuota, setEditQuota] = useState(attendanceConfig.annualLeaveQuota);
  const [waNumber, setWaNumber] = useState(preferences.whatsappNumber || '');
  const [webhookUrl, setWebhookUrl] = useState(preferences.webhookUrl || '');
  const [fonnteToken, setFonnteToken] = useState(preferences.fonnteToken || '');

  const [attendanceHistory, setAttendanceHistory] = useState<AttendanceRecord[]>([]);

  useEffect(() => {
      setAllEmployees(StorageService.getUsers());
      setConnectionStatus(isSupabaseConfigured() ? 'connected' : 'disconnected');
      if (canManageTeam) {
          setAttendanceHistory(StorageService.getAttendanceHistory());
      }
  }, [canManageTeam]);

  const handleAddEmployee = () => { setEditingEmployee(undefined); setIsEmployeeModalOpen(true); };
  const handleEditEmployee = (emp: User) => { setEditingEmployee(emp); setIsEmployeeModalOpen(true); };

  const handleDeleteEmployee = (id: string) => { 
      if (id === user.id) return alert("Anda tidak dapat menghapus akun sendiri."); 
      if (window.confirm("Hapus user ini secara permanen?")) { 
          StorageService.deleteUser(id); 
          setAllEmployees(StorageService.getUsers()); 
          if(onTeamUpdate) onTeamUpdate();
      } 
  };

  const handleSaveEmployee = (empData: User) => { 
      if (editingEmployee) StorageService.updateUser(empData); 
      else StorageService.addUser(empData); 
      setAllEmployees(StorageService.getUsers()); 
      setIsEmployeeModalOpen(false); 
      if(onTeamUpdate) onTeamUpdate();
  };

  const handleSaveProfile = () => { onUpdateUser({ ...user, name: editName, stickyNote: editNote, role: editRole }); alert(t.common.save); };
  const handleChangePassword = (e: React.FormEvent) => { e.preventDefault(); if (!newPassword || newPassword !== confirmPassword) return alert("Mismatch"); onUpdateUser({ ...user, password: newPassword }); setNewPassword(''); setConfirmPassword(''); alert("Updated"); };
  const handleAddAnnouncement = (e: React.FormEvent) => { e.preventDefault(); onUpdateAnnouncements([{ id: `ann_${Date.now()}`, title: newAnnTitle, content: newAnnContent, priority: newAnnPriority, date: new Date().toISOString().split('T')[0] }, ...announcements]); setNewAnnTitle(''); setNewAnnContent(''); };
  const handleDeleteAnnouncement = (id: string) => { onUpdateAnnouncements(announcements.filter(a => a.id !== id)); };
  const handleSaveAttendanceConfig = () => { onUpdateAttendanceConfig({ ...attendanceConfig, workStartTime: editWorkStart, workEndTime: editWorkEnd, gracePeriodMinutes: editGrace, annualLeaveQuota: editQuota }); alert("Saved"); };
  const handleExportConfig = () => { const blob = new Blob([JSON.stringify(StorageService.createBackup(), null, 2)], { type: 'application/json' }); const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = 'config.json'; a.click(); };
  const handleImportConfig = (e: React.ChangeEvent<HTMLInputElement>) => { const file = e.target.files?.[0]; if (!file) return; const reader = new FileReader(); reader.onload = (ev) => { try { StorageService.restoreBackup(JSON.parse(ev.target?.result as string)); } catch (e) { alert("Invalid"); } }; reader.readAsText(file); };
  const handleCloudSync = async () => { if (!window.confirm("Sync to cloud?")) return; setIsSyncing(true); await UnifiedDataService.syncLocalToCloud(StorageService.getTasks(), StorageService.getMessages(), StorageService.getChatGroups()); setIsSyncing(false); alert("Done"); };
  const handleSaveNotifications = () => { const upd = { ...preferences, whatsappNumber: waNumber, webhookUrl, fonnteToken }; setPreferences(upd); StorageService.savePreferences(upd); alert("Saved"); };
  const handleTestWebhook = () => { NotificationService.triggerWebhook({ id: 'test', title: 'Test', priority: 'medium', isCompleted: false, creatorId: 'me' } as any, 'created', webhookUrl); alert("Triggered"); };
  const handleCheckFonnteStatus = async () => { setIsCheckingFonnteStatus(true); setFonnteDeviceStatus(await NotificationService.validateFonnteToken(fonnteToken)); setIsCheckingFonnteStatus(false); };
  const handleTestFonnte = async () => { setIsTestingFonnte(true); await NotificationService.sendViaFonnte("Test Message", fonnteToken, waNumber); setIsTestingFonnte(false); alert("Sent request"); };

  const getBadgeColor = (division: string) => { 
      switch(division) { 
          case 'Direksi': return 'bg-purple-500/20 text-purple-300 border-purple-500/30'; 
          case 'Marketing': return 'bg-blue-500/20 text-blue-300 border-blue-500/30'; 
          case 'Administrasi': return 'bg-orange-500/20 text-orange-300 border-orange-500/30'; 
          case 'Keuangan': return 'bg-emerald-500/20 text-emerald-300 border-emerald-500/30'; 
          case 'IT Support': return 'bg-indigo-500/20 text-indigo-300 border-indigo-500/30';
          case 'SDM & Personalia': return 'bg-pink-500/20 text-pink-300 border-pink-500/30';
          default: return 'bg-gray-500/20 text-gray-300 border-gray-500/30'; 
      } 
  };

  const filteredEmployees = allEmployees.filter(emp => emp.name.toLowerCase().includes(searchTerm.toLowerCase()) || emp.division.toLowerCase().includes(searchTerm.toLowerCase()));

  const getUserName = (id: string) => {
      const u = allEmployees.find(emp => emp.id === id);
      return u ? u.name : id;
  };

  return (
    <div className="flex h-full bg-[#0b0f1a] overflow-hidden">
      <div className="hidden md:flex w-64 bg-black/20 border-r border-white/5 p-6 flex-col gap-2 shrink-0 backdrop-blur-md">
        <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2"><Icon name="Settings" className="text-brand-400" /> Pengaturan</h2>
        {canManageTeam && (<button onClick={() => setActiveTab('team')} className={`text-left px-4 py-3 rounded-xl flex items-center gap-3 transition-all ${activeTab === 'team' ? 'bg-brand-600 text-white' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}><Icon name="Users" size={18} /> Data Tim</button>)}
        <button onClick={() => setActiveTab('profile')} className={`text-left px-4 py-3 rounded-xl flex items-center gap-3 transition-all ${activeTab === 'profile' ? 'bg-brand-600 text-white' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}><Icon name="User" size={18} /> Profil</button>
        {isSystemAdmin && (<button onClick={() => setActiveTab('notifications')} className={`text-left px-4 py-3 rounded-xl flex items-center gap-3 transition-all ${activeTab === 'notifications' ? 'bg-brand-600 text-white' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}><Icon name="Bell" size={18} /> Notifikasi</button>)}
        {isSystemAdmin && (<button onClick={() => setActiveTab('system')} className={`text-left px-4 py-3 rounded-xl flex items-center gap-3 transition-all ${activeTab === 'system' ? 'bg-brand-600 text-white' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}><Icon name="Server" size={18} /> Sistem</button>)}
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8">
        <div className="md:hidden flex overflow-x-auto gap-2 mb-6 pb-2 scrollbar-hide">
             {canManageTeam && <button onClick={() => setActiveTab('team')} className={`whitespace-nowrap px-4 py-2 rounded-full text-xs font-bold border transition-colors ${activeTab === 'team' ? 'bg-brand-600 border-brand-500 text-white' : 'bg-white/5 border-white/10 text-gray-400'}`}>Data Tim</button>}
             <button onClick={() => setActiveTab('profile')} className={`whitespace-nowrap px-4 py-2 rounded-full text-xs font-bold border transition-colors ${activeTab === 'profile' ? 'bg-brand-600 border-brand-500 text-white' : 'bg-white/5 border-white/10 text-gray-400'}`}>Profil</button>
             {isSystemAdmin && <button onClick={() => setActiveTab('notifications')} className={`whitespace-nowrap px-4 py-2 rounded-full text-xs font-bold border transition-colors ${activeTab === 'notifications' ? 'bg-brand-600 border-brand-500 text-white' : 'bg-white/5 border-white/10 text-gray-400'}`}>Notifikasi</button>}
             {isSystemAdmin && <button onClick={() => setActiveTab('system')} className={`whitespace-nowrap px-4 py-2 rounded-full text-xs font-bold border transition-colors ${activeTab === 'system' ? 'bg-brand-600 border-brand-500 text-white' : 'bg-white/5 border-white/10 text-gray-400'}`}>Sistem</button>}
        </div>

        {activeTab === 'team' && canManageTeam && (
            <div className="max-w-6xl mx-auto space-y-6 animate-[fadeIn_0.3s]">
                <div className="flex flex-col md:flex-row md:justify-between md:items-center gap-4 mb-2">
                    <div>
                        <h2 className="text-xl md:text-2xl font-bold text-white mb-1">Data & Struktur Tim</h2>
                        <p className="text-gray-400 text-xs md:text-sm">Kelola akses dan hierarki perusahaan.</p>
                    </div>
                    <div className="flex flex-wrap gap-3">
                        <div className="hidden md:flex bg-black/30 p-1 rounded-xl border border-white/10">
                            <button onClick={() => setTeamViewMode('list')} className={`px-3 py-1.5 rounded-lg text-xs font-bold flex items-center gap-2 ${teamViewMode === 'list' ? 'bg-white/10 text-white' : 'text-gray-500'}`}><Icon name="List" size={14} /> List</button>
                            <button onClick={() => setTeamViewMode('chart')} className={`px-3 py-1.5 rounded-lg text-xs font-bold flex items-center gap-2 ${teamViewMode === 'chart' ? 'bg-white/10 text-white' : 'text-gray-500'}`}><Icon name="GitFork" size={14} /> Bagan</button>
                        </div>
                        <button onClick={handleAddEmployee} className="bg-brand-600 hover:bg-brand-500 text-white px-4 py-2 rounded-xl text-sm font-bold flex items-center gap-2 shadow-lg transition-all"><Icon name="UserPlus" size={16} /> <span className="hidden md:inline">Tambah</span></button>
                    </div>
                </div>

                {teamViewMode === 'list' ? (
                    <div className="bg-white/5 border border-white/5 rounded-2xl overflow-hidden shadow-2xl">
                        <table className="w-full text-left border-collapse">
                            <thead className="bg-black/20 text-gray-400 text-xs uppercase tracking-wider font-semibold">
                                <tr><th className="p-4 w-16 text-center">No</th><th className="p-4">Nama</th><th className="p-4">Divisi</th><th className="p-4">Kontak</th><th className="p-4 text-center">Aksi</th></tr>
                            </thead>
                            <tbody className="divide-y divide-white/5 text-sm">
                                {filteredEmployees.map((emp, idx) => (
                                    <tr key={emp.id} className="hover:bg-white/5 transition-colors group">
                                        <td className="p-4 text-center text-gray-500">{idx + 1}</td>
                                        <td className="p-4 font-medium text-white flex items-center gap-3"><div className="w-8 h-8 rounded-full bg-gray-700 flex items-center justify-center text-xs">{emp.name.charAt(0)}</div>{emp.name}</td>
                                        <td className="p-4"><span className={`text-[10px] px-2 py-0.5 rounded border uppercase font-bold ${getBadgeColor(emp.division)}`}>{emp.division}</span> <span className="text-gray-400 text-xs ml-2">{emp.role}</span></td>
                                        <td className="p-4 text-gray-400 font-mono text-xs"><div>{emp.email}</div><div>{emp.phoneNumber}</div></td>
                                        <td className="p-4 text-center"><div className="flex justify-center gap-2"><button onClick={() => handleEditEmployee(emp)} className="p-1.5 bg-blue-500/10 text-blue-400 rounded"><Icon name="Pencil" size={14} /></button><button onClick={() => handleDeleteEmployee(emp.id)} className="p-1.5 bg-red-500/10 text-red-400 rounded"><Icon name="Trash2" size={14} /></button></div></td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                ) : (
                    <OrgChart users={allEmployees} />
                )}
            </div>
        )}

        {activeTab === 'profile' && (
            <div className="max-w-2xl mx-auto space-y-8 animate-[fadeIn_0.3s]">
                <div className="bg-gradient-to-r from-brand-900/50 to-indigo-900/50 border border-brand-500/30 rounded-2xl p-6 flex items-center gap-6 shadow-2xl">
                    <div className="w-24 h-24 rounded-2xl bg-brand-500 flex items-center justify-center text-white text-4xl font-bold">{user.name.charAt(0)}</div>
                    <div><h2 className="text-2xl font-bold text-white">{user.name}</h2><p className="text-gray-400 text-sm">{user.role} • {user.division}</p></div>
                </div>
                <div className="bg-white/5 border border-white/5 rounded-2xl p-6 space-y-6">
                    <h3 className="text-lg font-bold text-white">Edit Profil</h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="space-y-2"><label className="text-xs font-bold text-gray-400">Nama</label><input className="w-full bg-black/30 border border-white/10 rounded-lg px-3 py-2 text-white text-sm outline-none" value={editName} onChange={e => setEditName(e.target.value)} /></div>
                        <div className="space-y-2"><label className="text-xs font-bold text-gray-400">Sticky Note</label><input className="w-full bg-black/30 border border-white/10 rounded-lg px-3 py-2 text-white text-sm outline-none" value={editNote} onChange={e => setEditNote(e.target.value)} /></div>
                    </div>
                    <button onClick={handleSaveProfile} className="px-4 py-2 bg-white/10 hover:bg-white/20 text-white rounded-lg text-sm font-bold">Simpan</button>
                </div>
            </div>
        )}

        {activeTab === 'notifications' && isSystemAdmin && (
            <div className="max-w-2xl mx-auto space-y-8 animate-[fadeIn_0.3s]">
                <div className="bg-white/5 border border-white/5 rounded-2xl p-6 space-y-4">
